const ORGS = [{"name": "900.care", "slug": "900-care", "country": "Not publicly available", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★★ High", "summary": "900.care is a French personal-care company co-founded by Aymeric Grange and Thomas Arnaudo, offering waterless, refillable hygiene products — biteable toothpaste tablets, dissolvable shower-gel and shampoo sticks, and refillable deodorant — designed to eliminate single-use plastic bottles and reduce water content in transported product. The company was founded in July 2019, ran a crowdfunding campaign and launched its subscription e-commerce model in December 2020, and entered French supermarket retail (Monoprix) in 2021. It has raised"}, {"name": "A Bit Less Bulk Store", "slug": "a-bit-less-bulk-store", "country": "Malaysia — Kepong Baru, Kuala Lumpur", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "A Bit Less Bulk Store is a small, independently run zero-waste retail shop in Kuala Lumpur, Malaysia, operating since 2018. Its mission is to eliminate single-use plastic packaging by letting customers refill organic food staples and household/personal-care products using their own containers. It is a physical, single-location bricks-and-mortar store rather than a chain, franchise, or online-first business, and its public presence is primarily via Facebook rather than a dedicated company website."}, {"name": "A New Earth Store", "slug": "a-new-earth-store", "country": "Lebanon — Achrafieh, Beirut (65 Zahret El Ihsan Street)", "categories": "consumer-education, waste-reduction", "priority": "★★ Low", "summary": "A New Earth is an organic and eco-living retail store in Achrafieh, Beirut, co-founded in 2009 by Layane Makarem and Sabine Kassouf. It is widely reported as Lebanon's first certified organic store. The shop sells organic food, health and wellbeing products, personal care and beauty items, pet care products, and a \"Green Lifestyle\" category of eco-friendly household goods, delivered across Lebanon. Since around 2019 it has expanded to include products from small producers and family"}, {"name": "A Public (PUBLIC: Sustainable Goods and Refills)", "slug": "a-public", "country": "United States — West Seattle, Washington (3836 California Ave SW, Seattle, WA 98116)", "categories": "consumer-education, refill, reusable-packaging, take-back", "priority": "★★★ Medium", "summary": "PUBLIC (marketed as \"A Public\" / apublicshop.com) is an independent brick-and-mortar and online refill shop based in West Seattle, Washington, founded by Kyleigh Turk-Polifko. The store has operated a refill service for home and personal-care products since 2018, alongside sales of curated reusable and refillable household goods. It has received regional media coverage (Sunset Magazine, Seattle Magazine, The Seattle Times, KING 5 News) as a Seattle-area zero-waste retail destination."}, {"name": "ABC Swappa Crate (Glass Packaging Forum initiative)", "slug": "abc-swappa-crate-glass-packaging-forum-initiative", "country": "New Zealand (nationwide)", "categories": "deposit-return, industrial-reuse, refill, reusable-packaging, reverse-logistics, waste-reduction", "priority": "★★★★ High", "summary": "The \"Swappa Crate\" is New Zealand's original and longest-running refill scheme, built around standardised, reusable glass beer bottles that originated with the Auckland Bottling Company (ABC) in 1920. At its 1975 peak, ABC-standard bottles made up roughly 92% of New Zealand's packaged beer market (about 336 million bottles annually). The scheme is now owned by brewers Lion and DB, operated logistically by Associated Bottlers Co., and promoted as an industry case study by the Glass"}, {"name": "Acala", "slug": "acala", "country": "United Kingdom — Kingston upon Thames, England (registered office: 43 St. Georges Road, Kingston Upon Thames, KT2 6DL)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Acala is a UK-based online retailer of zero-waste, plastic-free beauty and personal-care products, founded by Hanna Pumfrey in 2018 after she identified a lack of convenient, affordable package-free personal-care options in the UK market. Widely described in press coverage as one of the UK's first dedicated zero-waste cosmetics retailers, Acala sells both third-party sustainable beauty brands and its own-brand DIY beauty ingredients (oils, butters, waxes, clays, dried herbs and flowers) that let customers formulate products"}, {"name": "Adrish", "slug": "adrish", "country": "India — Pune, Maharashtra (founding location); now multi-city", "categories": "consumer-education, refill, rental, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Adrish is described in Indian press coverage as the country's first organised zero-waste organic lifestyle store chain, co-founded by chartered accountant Akshay Agarwal and Gajendra Choudhary, who opened their first store in Pune (Koregaon Park) in September 2018 after growing concerned about plastic pollution. Building on the founders' earlier organic-food venture, Satvyk, Adrish sells organic groceries, home decor, cleaning products, personal care, and zero-waste essentials, sourcing directly from a large network of organic farmers and"}, {"name": "Aer", "slug": "aer", "country": "Not publicly available", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Aer is an Austrian consumer-goods company selling home-cleaning and body-care products as concentrated, water-soluble powders packed in paper sachets, intended to be mixed with water in a reusable bottle rather than shipped as pre-filled liquid. The company, registered as aer GmbH, was founded in 2019 by Michael Bartenstein and Fabienne Hierzer (per company materials) and manufactures its products in Austria. Aer positions the model as eliminating single-use plastic bottles and the water weight normally shipped"}, {"name": "Aesop", "slug": "aesop", "country": "Not publicly available", "categories": "consumer-education, refill, take-back", "priority": "★★★ Medium", "summary": "Aesop is a premium skincare, haircare and body-care brand founded in 1987 by Dennis Paphitis in Melbourne, Australia, originally as an offshoot of his hairdressing salon \"Emeis.\" The brand grew into a global retailer of roughly 395 stores across some 27 countries, known for design-led signature stores and plant/lab-derived formulations. Aesop was majority- and then wholly-acquired by Brazilian cosmetics group Natura & Co between 2012 and 2016, then sold to L'Oréal in August 2023. Aesop"}, {"name": "AG Care", "slug": "ag-care", "country": "Not publicly available", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "AG Care (formerly branded AG Hair) is a Canadian professional haircare manufacturer founded in 1989 by Lotte Davis and John Davis in North Vancouver, initially selling directly to hair salons from 1990. The company describes itself as the largest independent manufacturer of professional hair-care products in Canada, formulating and bottling products at its own facility in Vancouver, British Columbia. In 2022 the brand relaunched in the US market under the \"AG Care\" name and introduced"}, {"name": "Again Again", "slug": "again-again", "country": "Not publicly available", "categories": "deposit-return, digital-tracking, packaging-as-a-service, rental, reusable-packaging, sharing", "priority": "★★★★ High", "summary": "Again Again is a New Zealand company founded by Nada Piatek and Melissa Firth that operates a technology platform enabling cafes and other foodservice businesses to offer customers reusable, returnable containers instead of single-use cups and packaging. Customers pay a small deposit (historically NZ$3) for a reusable stainless-steel cup or container, which can be returned to any participating venue for a refund; venues access the system via a mobile app and dashboard. The company launched"}, {"name": "Again", "slug": "again", "country": "Not publicly available", "categories": "digital-tracking, industrial-reuse, reusable-packaging, reverse-logistics, take-back", "priority": "★★★ Medium", "summary": "Again (legal entity Acet Circular Solutions Ltd) is a UK B2B reusable-packaging infrastructure company founded in 2021 by CEO Matt Kennedy. It built a decentralised network of automated \"CleanCell\" facilities — compact, shipping-container-sized units — that collect, sort, de-label, clean, inspect and palletise returned glass, PET and PP packaging so FMCG and drinks brands can reuse containers at a cost comparable to single-use packaging. The company positioned itself as infrastructure-layer plumbing for the reuse economy"}, {"name": "Air Closet", "slug": "air-closet", "country": "Not publicly available", "categories": "consumer-education, rental, reverse-logistics, sharing", "priority": "★★★★ High", "summary": "airCloset, Inc. is a Japanese fashion-technology company founded in 2014 and headquartered in Tokyo, operating an online clothing rental subscription service in which professional stylists select apparel for individual subscribers based on stated preferences and usage data. The company has since expanded into adjacent services including airCloset Fitting (styling advice for purchases), airCloset ABLE (in-person styling storefronts), airCloset Mall (rental/trial of household and lifestyle products), airCloset Dress (occasion wear) and airCloset Salon. airCloset listed on"}, {"name": "Akomeya (AKOMEYA TOKYO)", "slug": "akomeya", "country": "Not publicly available", "categories": "consumer-education, waste-reduction", "priority": "★★ Low", "summary": "AKOMEYA TOKYO is a Japanese specialty retailer built around rice: brown rice is milled to the customer's preferred degree on-site and sold by weight in paper bags rather than pre-packaged. The brand, operated by AKOMEYA TOKYO, Inc. (a subsidiary/joint venture of The SAZABY LEAGUE, Ltd.), opened its first Ginza store in 2013 and has since expanded to multiple locations in Tokyo (Shinjuku, Shibuya, Kagurazaka, Nihonbashi) offering rice, dashi, seasonings, baked goods, kitchenware and curated gifts"}, {"name": "Albo Drinks", "slug": "albo-drinks", "country": "Belgium — Wilrijk (Antwerp) and Aartselaar", "categories": "consumer-education, deposit-return, digital-tracking, industrial-reuse, material-recovery, packaging-as-a-service, refill, rental, repair, reusable-packaging, reverse-logistics, sharing, take-back, waste-reduction", "priority": "★ Low relevance", "summary": "Albo Drinks is a family-owned Belgian beverage retailer and wholesaler founded in 1963 by Kathleen \"Bomma\" and \"Bompa\" Van Looveren, originally delivering drinks from a garage in Mortsel. It has grown into a multi-thousand-product beverage specialist (beer, wine, spirits, soft drinks) serving both private consumers and hospitality businesses (cafés, restaurants, hotels) from retail locations in Wilrijk and Aartselaar. It is now run by the second and third generations of the founding family. No independently verifiable"}, {"name": "Alchemy", "slug": "alchemy", "country": "Ireland — Kildare (Monasterevin), with a technology centre in Newcastle-under-Lyme, UK, and facilities in 11 countries across 4 continents", "categories": "digital-tracking, industrial-reuse, repair, reverse-logistics, take-back, waste-reduction", "priority": "★★★★ High", "summary": "Alchemy is a Dublin, Ireland-headquartered company operating in the circular electronics market, managing the full device lifecycle from trade-in and reverse logistics through grading, data-wiping, repair, refurbishment, and remarketing of smartphones and other consumer electronics. Founded in 2017 by Gary Noone, James Murdock, and Walter Vicente, it has grown into what it describes as the fastest-growing company in the global circular tech market, operating facilities in 11 countries and selling refurbished devices in more than"}, {"name": "Aleph (Aleph Beauty)", "slug": "aleph", "country": "New Zealand", "categories": "consumer-education, material-recovery, refill, take-back", "priority": "★★ Low", "summary": "Aleph Beauty is a New Zealand-made clean, vegan, cruelty-free cosmetics and skincare brand founded in 2018 by makeup artist Emma Peters. It sells a curated range of multi-functional makeup and skincare products directly to consumers and through wholesale/stockist partners. The company is B Corp certified and operates \"Re Aleph,\" a packaging take-back initiative that collects empty product containers via mail-in and stockist drop-off points for industrial cleaning/reprocessing, with damaged or non-reusable glass diverted to recycling."}, {"name": "Algramo", "slug": "algramo", "country": "Not publicly available", "categories": "consumer-education, digital-tracking, refill, reusable-packaging, waste-reduction", "priority": "★★★★★ Essential", "summary": "Algramo is a Chilean social enterprise founded by José Manuel Moller that developed a \"Packaging-as-a-Wallet\" refill model: RFID-tagged reusable containers linked to a mobile app let customers buy household staples such as detergent, rice and pet food \"by the gram\" at neighbourhood stores or via home delivery, avoiding the higher per-unit cost typically paid by lower-income households buying small single-use packets. Algramo began as a bulk-dispenser concept aimed at Santiago's poorer neighbourhoods and has since"}, {"name": "Alima Pure", "slug": "alima-pure", "country": "Not publicly available", "categories": "consumer-education, refill", "priority": "★★ Low", "summary": "Alima Pure was a natural/mineral cosmetics company founded in Portland, Oregon in 2004 by Kate O'Brien. It manufactured mineral-based makeup — foundation, concealer, eyeshadow and related products — sold in refillable compact cases with swappable magnetic product pans, alongside standalone product refills, positioning refill as a core part of its packaging strategy. The company held Certified B Corporation and Leaping Bunny (cruelty-free) certifications. As of this research pass, the company's website displays a permanent closure"}, {"name": "Allas", "slug": "allas", "country": "Not publicly available", "categories": "consumer-education, digital-tracking, reusable-packaging, reverse-logistics, take-back, waste-reduction", "priority": "★★★ Medium", "summary": "Allas is described by its parent program as \"the first returnable packaging service for out-of-home food and drinks in Indonesia.\" It provides reusable silicone food containers and stainless-steel drink containers to restaurants and cafés in Jakarta for dine-in and delivery orders, then collects, washes, sanitises and redistributes the containers in a closed loop. Allas was developed and is administered through Zero Waste Living Lab, a venture-building program run by Enviu (an international entrepreneurial NGO focused"}, {"name": "Almang Market", "slug": "almang-market", "country": "Not publicly available", "categories": "consumer-education, material-recovery, refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Almang Market (알맹상점) is South Korea's first dedicated refill station, operating a Seoul retail store where customers bring their own containers to purchase cosmetics, household detergents, food ingredients (teas, coffee, spices, oils) and other goods by weight, without single-use packaging. It grew out of a 2018 grassroots community campaign in Seoul's Mangwon neighbourhood formed in response to a national waste-collection crisis, and opened as a permanent store in June 2020. The organisation also runs a"}, {"name": "AlmaWin", "slug": "almawin", "country": "Germany — Winterbach, near Stuttgart (Baden-Württemberg)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "AlmaWin is a German manufacturer of biodegradable laundry detergents, cleaning agents, and dishwashing liquids, founded in 1993 by Rudolf Bund in Winterbach, near Stuttgart. The company is family-owned and now in its second generation of leadership. Its products are formulated as concentrates from plant- and mineral-based ingredients, several certified organic, and are sold through conventional retail as well as through Germany's \"unverpackt\" (zero-waste/package-free) shop network, where empty bottles can be refilled rather than discarded. The"}, {"name": "Alner (formerly Koinpack)", "slug": "alner", "country": "Indonesia — Jakarta (Greater Jakarta metro area)", "categories": "consumer-education, deposit-return, digital-tracking, packaging-as-a-service, reusable-packaging, reverse-logistics, waste-reduction", "priority": "★★★★★ Essential", "summary": "Alner (known as Koinpack from its March 2020 founding until its rebrand on 1 August 2023) is an Indonesian returnable-packaging venture founded by CEO Bintang Ekananda and co-founder Trian Effransa, incubated through Enviu's Zero Waste Living Lab programme. It supplies FMCG brands (household, personal care, and food products) with reusable containers, sells the filled containers through points of sale in Greater Jakarta, and operates app-based reverse logistics — including cleaning, refilling, and cashback incentives —"}, {"name": "Alterpacks", "slug": "alterpacks", "country": "Not publicly available", "categories": "material-recovery, refill, waste-reduction", "priority": "★★ Low", "summary": "Alterpacks is a Singapore-based start-up, founded in 2019 by Karen Cheah (Founder and CEO) alongside co-founders Steven Tan and Herbin Chia, that converts spent grains and other agricultural/food-manufacturing by-products (e.g. wheat husks) into home-compostable food packaging. Incubated at Singapore Management University's Institute of Innovation & Entrepreneurship (Business Innovation Generator) and an NUS LLP alumnus, the company raised US$1 million in pre-seed funding in late 2022/January 2023. It operates a B2B model supplying food-container alternatives to"}, {"name": "Alya Packaging", "slug": "alya-packaging", "country": "Not publicly available", "categories": "reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "Alya Packaging is a privately held Istanbul manufacturer of custom-printed packaging — luxury paper bags, presentation and gift boxes, folding cartons and postal/e-commerce boxes — operating from an 8,000m² production facility and exporting to more than 40 countries. Alongside its core paper-packaging business, the company offers a line of reusable \"eco-bags\" made from cotton, non-woven polypropylene (PP) and woven PP, marketed as recyclable and reusable alternatives to single-use plastic carrier bags. It serves independent brands,"}, {"name": "Ambev", "slug": "ambev", "country": "Not publicly available", "categories": "consumer-education, deposit-return, material-recovery, refill, reusable-packaging, reverse-logistics", "priority": "★★★★★ Essential", "summary": "Ambev S.A. is a Brazilian brewing and beverage company formed in 1999 through the merger of Brahma and Antarctica, two breweries with 19th-century origins, and is today majority-owned by global brewer AB InBev while remaining separately listed on the NYSE and B3. With over 39,600 employees as of its most recent annual report and operations across 18 countries in the Americas, Ambev is one of the largest publicly documented operators of returnable glass bottle systems"}, {"name": "Amorepacific (Amore Store Gwanggyo Refill Station)", "slug": "amore-pacific-gwanggyo-store", "country": "Not publicly available", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "The Amore Store Gwanggyo Refill Station is a cosmetics refill concept launched by Amorepacific Corporation, South Korea's largest cosmetics company, in October 2020 — described in company and trade press as the first refill station in Korea's cosmetics industry. Located within the experiential \"Amore Store Gwanggyo\" retail concept store, it allows customers to dispense shampoo and body wash from any of 15 product lines into refillable containers made partly from coconut-shell material, paying by weight"}, {"name": "Anew", "slug": "anew", "country": "New Zealand — Waiheke Island (founder-based); products distributed in NZ, Australia, USA", "categories": "consumer-education, material-recovery, reusable-packaging", "priority": "★★ Low", "summary": "Anew is a New Zealand-founded consumer brand producing reusable, plant-based water bottles as an alternative to single-use and conventional reusable packaging (plastic, aluminium, glass). Founded by Waiheke Island-based Jayden Klinac in 2015, the company positions its bottles as a \"circular mindset\" product: made from renewable plant-based material rather than petroleum-based plastic, mono-material (no separate plastic lining, unlike aluminium bottles/cans), and designed to be either household-recycled or returned to company collection points to be remade into"}, {"name": "AnniePooh", "slug": "anniepooh", "country": "Ireland (Greystones, Co. Wicklow)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "AnniePooh is a small, independently owned zero-waste shop and refillery based in Greystones, County Wicklow, Ireland, with an accompanying online store. Founded in 2012 by Ann Teehan after she struggled to find chemical- and plastic-free products for her children, the business began with pop-up markets before opening a permanent shop. It sells reusable and refillable personal care, household, and lifestyle products, both own-curated and from third-party eco brands, aimed at helping customers reduce single-use plastic"}, {"name": "Araliya (Araliya Packaging Lanka)", "slug": "araliya", "country": "Sri Lanka (Lakshauyana, Polonnaruwa, North Central Province)", "categories": "material-recovery, reusable-packaging", "priority": "★★★ Medium", "summary": "Araliya Packaging Lanka is a Sri Lankan manufacturer of non-woven polypropylene (PP) bags, established in 2021 as a packaging subsidiary of the diversified Araliya Group (founded 1994). It was originally created to supply durable packaging for the group's flagship Araliya Rice product line and has since expanded to serve external retail and industrial customers across Sri Lanka and export markets. The company positions its non-woven bags as eco-friendly, long-lasting alternatives to single-use plastic packaging for"}, {"name": "AriaPack", "slug": "ariapack", "country": "Turkey (Ümraniye, Istanbul)", "categories": "Not publicly available", "priority": "★ Low relevance", "summary": "AriaPack is a Turkish B2B packaging manufacturer based in Ümraniye, Istanbul, supplying food-service packaging — kraft and non-woven bags, paper cups, cardboard/Kraft-Bristol salad bowls with PET/PP lids, and plastic film and sheet — to cafes, restaurants, and food businesses. The company markets its products with an \"eco-friendly\" tagline (\"Clean Environment, Healthy Future\") and offers custom flexo/offset printing. Its product range is dominated by single-use, disposable food-service items rather than reusable consumer goods."}, {"name": "Aromatica Zero Station", "slug": "aromatica-zero-station", "country": "South Korea (62 Dosan-daero 1-gil, Gangnam-gu, Seoul — Sinsa-dong)", "categories": "consumer-education, refill, reverse-logistics, waste-reduction", "priority": "★★★ Medium", "summary": "AROMATICA Zero Station is a flagship retail concept store operated by Korean beauty brand AROMATICA, opened in June 2021 in the Sinsa-dong area of Gangnam-gu, Seoul, on the site of the brand's earlier \"House of AROMATICA\" refill store (2020). Described by AROMATICA and trade press as one of the first spaces of its kind in Korea, it combines a bulk product refill station, a recycling/upcycling education area, an aromatherapy experience zone, and a tea house"}, {"name": "Aromatica", "slug": "aromatica", "country": "South Korea (Seoul, with manufacturing at an Osan, Gyeonggi-do \"Smart Factory\")", "categories": "consumer-education, refill, reverse-logistics, take-back, waste-reduction", "priority": "★★★★ High", "summary": "AROMATICA is a South Korean clean-beauty and aromatherapy company founded in 2004 by Jerry Kim, who set out to replace synthetic fragrance with natural essential oils in cosmetics. Beyond product formulation, AROMATICA has built a multi-year sustainable-packaging programme spanning refill pouches (since 2016), an in-store bottle refill network beginning with \"House of AROMATICA\" (2020), a subscription refill-and-return service (2022), and — as of 2024 — the first Science Based Targets initiative (SBTi)-validated greenhouse gas reduction"}, {"name": "Aroundrs", "slug": "aroundrs", "country": "Italy (Florence — Via G. Matteotti, 50121)", "categories": "digital-tracking, packaging-as-a-service, reusable-packaging, reverse-logistics, waste-reduction", "priority": "★★★ Medium", "summary": "Aroundrs is an Italian startup, headquartered in Florence, that provides a reusable-packaging system for food takeaway and delivery. Conceived in 2020 during COVID-19 lockdowns when co-founder Giulia Zanatta and colleagues observed a surge in single-use takeout waste, the company was formally established in 2021 as a Società Benefit (an Italian benefit-corporation legal form combining commercial and social/environmental purpose). Aroundrs supplies durable, reusable containers — tracked through a mobile app — to restaurants, supermarkets, corporate cafeterias,"}, {"name": "Artani Eco Bulk Store", "slug": "artani-eco-bulk-store", "country": "Indonesia (Jl. Botolempangan No. 57, Makassar, South Sulawesi)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "Artani is a small, independently owned zero-waste bulk store based in Makassar, South Sulawesi, Indonesia — described in local press as the city's first store of its kind. Founded in May 2021 by Ria Lestari Baso, an agriculture graduate, the business was inspired by her own difficulty sourcing package-free baby food. Operating under the tagline \"Beli secukupnya, pakai semuanya\" (\"Buy only what you need, use it all\"), Artani sells agricultural, household and personal-care products by"}, {"name": "Artsan Ambalaj", "slug": "artsan-ambalaj", "country": "Turkey (Çerkezköy OSB, İsmetpaşa, Kapaklı, Tekirdağ; sales office in Istanbul)", "categories": "material-recovery, reusable-packaging", "priority": "★★ Low", "summary": "Artsan Ambalaj is a Turkish flexible-packaging manufacturer established in May 2020 and operational since 2022, part of the diversified Sanat Group (industrial operations since 1973; flexible-packaging investment since 2016). Operating from an integrated production campus in Tekirdağ with a stated annual capacity of 60,000 tons, Artsan produces films, pouches, wicket bags and laminated structures — including mono-material, recyclable, and post-consumer-recycled (PCR) content options — for food and beverage, personal care, home care, and industrial B2B"}, {"name": "ASA Beauty", "slug": "asa-beauty", "country": "India (Mumbai — Bandra Kurla Complex)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "asa Beauty is a Mumbai-headquartered, direct-to-consumer clean beauty brand launched in 2020 by Asha Jindal Khaitan (co-founder of nutraceutical brand Pure Nutrition) and her daughter-in-law Sukriti Jindal Khaitan. The brand positions itself at the intersection of luxury and sustainability, offering natural, vegan, and cruelty-free makeup — lipsticks, lip & cheek tints, highlighters, SPF face sticks, and lip balms — built around a refillable packaging system intended to reduce single-use plastic waste while maintaining a premium"}, {"name": "ASD (Ambalaj Sanayicileri Derneği / Packaging Manufacturers' Association)", "slug": "asd", "country": "Turkey (Istanbul)", "categories": "consumer-education, waste-reduction", "priority": "★★★ Medium", "summary": "ASD (Ambalaj Sanayicileri Derneği), known in English as the Packaging Manufacturers' Association, is Turkey's principal packaging industry trade association, founded in 1992 by 39 founding members and now representing over 200 member companies. Based in Istanbul, ASD represents manufacturers across paper/cardboard, glass, metal, flexible packaging, plastic bottles and containers, labels, wooden packaging, and packaging machinery sub-sectors. As confirmed during verification, this is an industry association and non-profit membership body, not a commercial packaging company, consistent"}, {"name": "Atelier Rebul", "slug": "atelier-rebul", "country": "Turkey (Istanbul) — NOT Belgium; seed data's \"Turkey\" country tag was correct, but the .be website is a Benelux retail/e-commerce arm, not the company's headquarters", "categories": "consumer-education, refill", "priority": "★★ Low", "summary": "Atelier Rebul traces its history to 1895, when French pharmacist Jean César Reboul opened the Grande Pharmacie Parisienne on Istanbul's Istiklal Avenue, later run by his Turkish partner Kemal Müderrisoğlu and family. The pharmacy's signature cologne, Rebul Lavanda (1938), became a symbol of Istanbul heritage. The modern \"Atelier Rebul\" retail and lifestyle brand — soaps, colognes, home fragrance and skincare — launched in 2013, built on this 125+ year history, and now operates in roughly"}, {"name": "Avo & Co.", "slug": "avo-and-co", "country": "Singapore", "categories": "waste-reduction", "priority": "★★ Low", "summary": "Avo & Co. is a Singapore-based online grocery delivery company founded by brothers Clement and Cedric, who were dissatisfied with the quality of fruit and vegetables available through conventional supermarkets. The company sells curated and customisable fresh produce boxes — fruit, vegetables, organic items, microgreens, edible flowers and pantry staples — via subscription (weekly, fortnightly or monthly, with no lock-in) or one-off orders, delivered island-wide in Singapore. It positions itself on produce quality, direct sourcing"}, {"name": "AVOID", "slug": "avoid", "country": "Brazil (São Paulo)", "categories": "packaging-as-a-service, refill, waste-reduction", "priority": "★★★ Medium", "summary": "AVOID is a Brazilian greentech startup, headquartered in São Paulo and founded in 2020, that develops refill infrastructure for consumer goods companies. Its core proposition is removing water from liquid product formulas (e.g. cleaning or personal-care products) and combining the concentrate with water directly at in-store refill machines, converting retail locations from conventional points of sale into refill points. The company frames this as a way to cut transportation costs, fuel use and carbon emissions"}, {"name": "Babel Siem Reap", "slug": "babel-siem-reap", "country": "Cambodia (Siem Reap)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "Babel Siem Reap is an independently owned eco-focused guesthouse and boutique hotel in Siem Reap, Cambodia, operating since 2008. As part of its sustainability positioning, Babel runs an on-site \"Eco-shop and refill station\" in its lobby, described by the property as the country's first zero-waste shop and refill station of its kind. As noted in the seed data, this is a hotel/guesthouse sustainability initiative embedded within a hospitality business, not a standalone reuse company, and"}, {"name": "Babyloop", "slug": "babyloop", "country": "Portugal", "categories": "consumer-education, reverse-logistics, take-back, waste-reduction", "priority": "★★★ Medium", "summary": "Babyloop is a Portuguese circular-economy platform, launched in January 2019, that lets families buy and sell second-hand baby equipment — strollers, cots, bassinets, car seats and related gear. It originated as a challenge set by retailer Sonae MC (parent of Continente supermarkets) and was developed by Book in Loop, a Coimbra startup that had previously applied the same reuse model to second-hand school textbooks, with television presenter Carolina Patrocínio involved as the public face of"}, {"name": "BachserMärt", "slug": "bachsermaert", "country": "Switzerland (Zurich region; original shop in the village of Bachs)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "BachserMärt is a Swiss grocery retailer that began in 2008 when Patrick Honauer took over and refurbished a village shop in Bachs, a rural community roughly 20km north of Zurich, aiming to secure local food supply and support organic and local farmers. The concept expanded to urban Zurich in 2009 with a second shop in Albisrieden, and the company now operates five shops plus a warehouse around Zurich, including its largest location at Kalkbreite (opened"}, {"name": "Back to Basics (BtB Ecostore)", "slug": "back-to-basics", "country": "Philippines (Quezon City — 30 Maginhawa Street, U.P. Village)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Back to Basics Ecostore was founded in 2019 in Quezon City by five environmental advocates concerned about the wasteful packaging generated by conventional supermarket shopping. Operating as a women-led social enterprise, BtB Ecostore runs a refillery grocery store offering refill stations for household essentials alongside eco-friendly products, including goods sourced from indigenous communities and women-led, community-based enterprises. The store won the Quezon City Green Awards 2024 for Excellence in Climate Action."}, {"name": "Baedal Minjok (Baemin)", "slug": "baedal-minjok", "country": "South Korea (Seoul)", "categories": "consumer-education, reusable-packaging, reverse-logistics", "priority": "★★★ Medium", "summary": "Baedal Minjok (\"Baemin\") is South Korea's largest food delivery app, launched in 2010 by founder Kim Bong-jin and operated by Woowa Brothers Corp., which became a Delivery Hero subsidiary following Delivery Hero's acquisition (with Delivery Hero required to divest its other Korean platform, Yogiyo, to address antitrust concerns). Within this large conventional delivery business, Woowa Brothers began piloting a reusable-container (\"다회용기\") delivery order option on 29 August 2022, first available in Seoul's Gangnam district and"}, {"name": "Bak Packages", "slug": "bak-packages", "country": "Pakistan (Sundar Industrial Estate, Lahore)", "categories": "reusable-packaging", "priority": "★ Low relevance", "summary": "BAK Packaging (Pvt) Ltd. is a flexible packaging manufacturer based in Lahore, Pakistan, founded in 2019. The company provides printing, lamination and bag-making services, producing center-seal, 3-side-seal, 4-side-seal and flat-bottom box pouches for business customers, using in-house rotogravure printing and solvent-based/solvent-less lamination equipment. It positions itself as a full-service flexible-packaging supplier offering custom design and production for client brands."}, {"name": "Bamboo Straw Girl", "slug": "bamboo-straw-girl", "country": "Singapore", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Bamboo Straw Girl is a Singapore-based social enterprise founded in 2013 by Melissa Lam, who began distributing bamboo straws to family, friends and drinks-stall vendors after being struck by the irony of using single-use plastics during camping trips in nature. Described as Singapore's first \"zero-waste lifestyle\" store, predating the wider popularisation of the \"zero-waste\" term locally, the venture formally incorporated by 2018 and now supplies reusable, locally made lifestyle goods to resorts, hotels and lifestyle"}, {"name": "Bare Market", "slug": "bare-market", "country": "Canada (founded and headquartered in Toronto, Ontario)", "categories": "consumer-education, refill, reusable-packaging", "priority": "★★★ Medium", "summary": "bare market is a Canadian low-waste retailer founded in 2018 by Dayna Stein, who was inspired by Vancouver's The Soap Dispensary and her graduate research on food-waste mitigation. The business began as a series of farmers'-market stalls and pop-ups before opening a permanent storefront on Danforth Avenue in Toronto in January 2020. That physical location closed on May 19, 2024, after which bare market transitioned to an online, delivery-based model, partnering with several small east-Toronto"}, {"name": "Bare Necessities", "slug": "bare-necessities", "country": "India (Bengaluru, Karnataka)", "categories": "consumer-education, refill, take-back, waste-reduction", "priority": "★★★ Medium", "summary": "Bare Necessities is a zero-waste social enterprise founded by Sahar Mansoor, a Cambridge-educated environmental policy specialist, who launched the brand in 2016 and formally registered the company in 2019. Headquartered in Bengaluru, it produces personal-care (soap bars, shampoo/conditioner bars, deodorants, bath salts), face and hair care, and home-care products in low-waste, often waterless and concentrated formats. It is described as India's first FMCG-sector B Corporation and is also PETA-certified. The company combines retail, corporate gifting"}, {"name": "barePack", "slug": "barepack", "country": "Singapore (founded); now a subsidiary operating within &Repeat, headquartered in Stockholm, Sweden", "categories": "digital-tracking, packaging-as-a-service, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "barePack is a reusable-packaging service founded in Singapore in 2019 by Roxane Uzureau together with co-founders Maximilien Mason, Valerian Fauvel and Clement Hochart, after Uzureau's idea for a reusable-container sharing model gained traction at a Singapore zero-waste event. The company built a membership-based system letting customers order takeaway and delivery food in reusable containers rather than single-use packaging. In February 2022, barePack was acquired by Swedish circular-packaging company &Repeat, which itself merged with Helsinki-based Kamupak"}, {"name": "Battmen", "slug": "battmen", "country": "Netherlands (specific city not publicly available)", "categories": "rental", "priority": "★ Low relevance", "summary": "Battmen presents itself, via its own website, as \"the dutch battery swap,\" offering battery packs, docking stations, and charge/swap stations. Beyond this self-description, no independent press coverage, business-registry listing, social-media presence, or third-party directory entry could be found in this research pass. This is consistent with a very small or early-stage company with minimal public-facing presence, but it also means most factual claims about the organisation cannot currently be independently verified."}, {"name": "BDARI", "slug": "bdari", "country": "Malaysia (Puchong, Selangor)", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "BDARI is a Malaysian household-goods brand launched in August 2020, evolving out of an earlier household-essentials business, AZ Homefix PLT, which had been operating in household products since early in the COVID-19 pandemic. BDARI's core product is a range of designer stainless-steel tiffin carriers (multi-tier food containers), sold as a sustainable alternative to single-use plastic bags and containers for meals, gifting and events, alongside a broader catalogue of reusable food containers, bottles, bags and cutlery."}, {"name": "Bean Around", "slug": "bean-around", "country": "Ireland (Dún Laoghaire)", "categories": "consumer-education, material-recovery, waste-reduction", "priority": "★★★ Medium", "summary": "Bean Around is an Irish skincare company founded in 2020 by sisters Sadhbh and Aisling Wood while they were college students in Dún Laoghaire. The company collects used coffee grounds from local cafés and corporate canteens and repurposes them into handcrafted exfoliating soap bars, sold in plastic-free, recyclable packaging. The business has grown from a campus project into a nationally stocked brand, including selection for Lidl Ireland's \"Kickstart\" small-business programme, placing its products in 222"}, {"name": "Beautiful Store", "slug": "beautiful-store", "country": "South Korea (Seoul)", "categories": "consumer-education, material-recovery, take-back, waste-reduction", "priority": "★★★★ High", "summary": "Beautiful Store is a South Korean nonprofit charity-shop network launched in 2002 by People's Solidarity for Participatory Democracy, modelled in part on the Oxfam charity-shop concept, with its first store opening in the Anguk neighbourhood of Seoul. It became an independent nonprofit corporation in 2008. The organisation has since grown to more than 100 volunteer-run stores across some 16 cities in Korea, plus a small number of shops abroad. Stores collect donated secondhand goods —"}, {"name": "Beauty Kitchen", "slug": "beauty-kitchen", "country": "United Kingdom (Scotland)", "categories": "consumer-education, digital-tracking, refill, reverse-logistics", "priority": "★★★★ High", "summary": "Beauty Kitchen is a UK cosmetics manufacturer and retailer founded in 2014 by Jo Chidley, a chemist and circular-economy specialist. It manufactures and sells skincare, haircare and body-care products and describes itself as among the highest-scoring B Corp-certified companies in the UK beauty sector. Its \"Return for Reward\" (also communicated as \"Return · Refill · Repeat\") programme lets customers return empty full-size packaging — glass, aluminium or stainless-steel bottles, jars and pumps bearing the Return"}, {"name": "Beauty Society", "slug": "beauty-society", "country": "United States (Las Vegas, Nevada)", "categories": "consumer-education, refill", "priority": "★★ Low", "summary": "Beauty Society is a US skincare and cosmetics company founded in 2004 by Jeannie Lorin, headquartered in Las Vegas, Nevada. It operates as a direct-sales (multi-level marketing) business: independent \"Advisors\" sell products and build their own customer networks and downline teams in exchange for commissions, rather than the company selling through a conventional retail marketplace. Seed data's framing of the company as a \"sustainable beauty marketplace\" is not accurate — Beauty Society is a direct-selling/MLM"}, {"name": "Beg Destilaria Boutique", "slug": "beg-destilaria-boutique", "country": "Brazil (Joaquim Egídio district, Campinas, São Paulo)", "categories": "consumer-education, refill, reusable-packaging", "priority": "★★★ Medium", "summary": "BEG Destilaria Boutique — trading as \"Beg Gin\" — is a Brazilian gin producer founded in 2012 by four friends with a shared interest in spirits, who established a dedicated microdistillery in 2015 in the Joaquim Egídio district of Campinas, São Paulo, housed in a revitalised, historically listed former coffee-farm headquarters building dating to the mid-19th century. The brand name combines \"B\" for Brasil and \"G\" for gin. Beg produces artisanal, small-batch gins that have"}, {"name": "Benamôr 1925", "slug": "benamôr-1925", "country": "Portugal (Lisbon)", "categories": "consumer-education, refill", "priority": "★★ Low", "summary": "Benamôr is a Portuguese cosmetics and personal-care brand founded in 1925 in Lisbon, originally producing ointments and creams from a small laboratory. It became one of Portugal's largest cosmetics producers in its early decades before declining and being revived. In 2015 the brand was acquired by a group of investors (Pierre Stark, Filipe Serzedelo, Takehide Takasa) who relaunched and modernised it. Benamôr now sells face, body and hand-care products through its own retail stores in"}, {"name": "bettercup.", "slug": "bettercup", "country": "Australia (Melbourne, Victoria); also operates in New Zealand", "categories": "consumer-education, rental, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "bettercup is a Melbourne-founded, female-led enterprise that supplies reusable cups (and related dishware) plus a full-service reuse operating system — collection, washing, drying, storage and logistics — to events, venues, stadiums, universities and bars across Australia and New Zealand. Founded in 2018 by Sam Stone and Christie Kamphuis, the company (legally registered as Encoro Pty Ltd) designs and locally manufactures its own reusable cups. It has received Victorian government circular-economy grant funding to expand manufacturing"}, {"name": "Bio c' Bon (Japan)", "slug": "bio-c-bon", "country": "Not publicly available", "categories": "consumer-education, refill", "priority": "★★ Low", "summary": "Bio c' Bon Japon is the Japanese operating company of the French organic supermarket brand Bio c' Bon, established in 2016 as a joint venture between Japanese retail group Aeon and the French chain's owner, Marne & Finance Europe. It operates organic supermarkets in the Tokyo area (with locations also reported in Kanagawa) offering more than 1,000 certified-organic product lines spanning fresh food, grocery, beverages, cosmetics and household goods, several of which include in-store bulk/refill"}, {"name": "Bio-Home", "slug": "bio-home", "country": "Not publicly available", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Bio-home is a household cleaning product brand owned by Lam Soon Singapore, a heritage Singapore FMCG manufacturer founded in 1929. The brand offers dishwashing liquid, laundry detergent, floor cleaner, multi-surface cleaner and fruit-and-vegetable wash formulated with plant-based, biodegradable active ingredients. Several bio-home products carry Singapore Green Labelling Scheme (SGLS) certification. In 2025, bio-home partnered with sustainability platform Ecoworks to pilot an automated refill station at a Singapore campus, allowing consumers to dispense cleaning products into"}, {"name": "Bio Pac", "slug": "bio-pac", "country": "United States (Incline Village, Nevada, per business directories; not stated on official site)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "Bio Pac, Inc. is a small, family-run American manufacturer of biodegradable, super-concentrated cleaning products (laundry detergent, dish soap, household cleaners), founded in 1991 by Collin Harris. The idea originated from Harris's experience volunteering at a recycling center in Maine, where he observed large volumes of discarded cleaning-product containers; Bio Pac's first bulk soap filling station opened at the Belfast Co-op in Belfast, Maine, in spring 1991. In 1996 the company acquired Oasis Biocompatible Cleaners from"}, {"name": "BioBox (biobox.ch)", "slug": "biobox", "country": "Switzerland (Bouveret/Port-Valais, canton Valais)", "categories": "Not publicly available", "priority": "★ Low relevance", "summary": "Biobox Sàrl, based in Bouveret (Port-Valais), Switzerland, operates biobox.ch, a monthly subscription box service delivering 5-6 full-size natural/organic beauty, skincare and wellness products to subscribers in Switzerland and Liechtenstein. This is materially different from the seed-data description (\"refillable container solutions for household products\"): no evidence was found that Biobox Sàrl manufactures, sells, or supplies reusable/refillable containers, or that it operates in the household-products refill space at all. It appears to be a beauty-product discovery/subscription retailer,"}, {"name": "Biologique", "slug": "biologique", "country": "South Africa", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "Biologique is a South African direct-to-consumer company selling natural, toxin-free concentrated household cleaning products — all-purpose, kitchen, bathroom, laundry, dishwashing, pet-care and personal hygiene lines — designed around a refill model: customers buy an initial ready-to-use bottle, then purchase 200ml or 500ml concentrate refills that are diluted at home, extending the life of the original bottle. According to the company's own account, the founder, previously in hospitality management, started the brand after becoming a parent"}, {"name": "BioPak", "slug": "biopak", "country": "Australia (Sydney)", "categories": "consumer-education, material-recovery, waste-reduction", "priority": "★★ Low", "summary": "BioPak is an Australian-founded manufacturer and supplier of certified compostable food-service packaging (cups, containers, cutlery, bags), established in Sydney in 2006 by Richard Fine (a former plastics-industry executive from South Africa) and Gary Smith. The company has grown to serve a reported 10,000+ venues across Australia, New Zealand, Singapore, the UK and the US, with named enterprise customers including McDonald's, Woolworths, Aldi, Qantas and Commonwealth Bank cited in press coverage. BioPak is B Corp certified"}, {"name": "Biotherm", "slug": "biotherm", "country": "France (brand origin: Molitg-les-Bains, Pyrénées-Orientales; R&D/production historically centred in Monaco; ultimate parent L'Oréal S.A. headquartered in Clichy, France)", "categories": "consumer-education, refill", "priority": "★★ Low", "summary": "Biotherm is a French skincare brand founded in 1952 by biochemist Jeanine Marissal and collaborator Jos Jullien, who identified a \"thermal plankton\" microorganism in the spring waters of Molitg-les-Bains in the French Pyrenees and developed it into a cosmetic ingredient under owner Adrien Barthélémy. L'Oréal acquired Biotherm in 1970 and built a research and production centre for the brand in Monaco. Biotherm remains part of L'Oréal's Luxe division today, selling face and body skincare internationally,"}, {"name": "Bite", "slug": "bite", "country": "United States (Los Angeles / Marina del Rey, California)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Bite is a Los Angeles-based oral-care company founded in 2018 by Lindsay McCormick, who developed chewable toothpaste \"bits\" as an alternative to plastic toothpaste tubes after learning of the scale of tube waste going to landfill and ocean. The company sells toothpaste bits, mouthwash bits, whitening gel, deodorant and related personal-care products direct-to-consumer, packaged in a reusable glass jar refilled via compostable pouches. Bite is B Corp certified and gained mainstream visibility through a \"Shark"}, {"name": "Blueland", "slug": "blueland", "country": "Not publicly available", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Blueland is a US direct-to-consumer household-cleaning company co-founded in 2019 by CEO Sarah Paiji Yoo and John Mascari. Its core innovation is a refill system: customers buy a reusable bottle or container once (dispenser/tin/duraware), then reorder concentrated tablets, powders or paper-based refills that dissolve in water at home, eliminating repeated purchases of pre-filled single-use plastic bottles. The company reports $300 million in lifetime sales since launch and has expanded from an online-only DTC model into"}, {"name": "Bluewater", "slug": "bluewater", "country": "Sweden (Stockholm)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Bluewater is a Stockholm-founded water-purification technology company established in 2013 by Swedish entrepreneur Bengt Rittri, who previously founded and sold air-purification company Blueair to Unilever. Bluewater develops patented reverse-osmosis purification technology and sells hydration stations and purifiers for home, hospitality, workplace, wellness, and emergency-response use, aimed at reducing reliance on single-use bottled water. In April 2022 Bluewater merged with Denver-based FloWater to form a combined global group, with Rittri as CEO of the merged entity"}, {"name": "Boobalou", "slug": "boobalou", "country": "United Kingdom (Arundel, West Sussex)", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "Boobalou is a UK e-commerce retailer founded in 2014 by Jo Mack, a work-at-home mother who started the business selling reusable cloth nappies and reusable menstrual products after struggling to find genuinely plastic-free alternatives for her family. The business grew from a single room to a garden cabin and then multiple storage units and warehouses in Arundel, Sussex, as demand increased (the company's own account attributes part of this growth to increased public interest following"}, {"name": "Boomi", "slug": "boomi", "country": "China (Shanghai/Beijing)", "categories": "consumer-education, waste-reduction", "priority": "★★ Low", "summary": "Boomi (from the Indonesian word \"bumi,\" meaning earth) was a Shanghai-founded sustainability marketplace co-founded in 2018 by Emmanuel Dean and Miguel Boy, operating primarily through WeChat and serving Chinese consumers in cities including Shanghai and Beijing. It began by selling bamboo toothbrushes and grew into a curated platform listing more than 50 local sustainability-focused brands and businesses. As of this research (July 2026), Boomi's former website domain redirects to the unrelated Dell Boomi integration-software company,"}, {"name": "Boox", "slug": "boox", "country": "United States (Petaluma, California)", "categories": "consumer-education, packaging-as-a-service, reusable-packaging, reverse-logistics, take-back", "priority": "★★★★ High", "summary": "Boox is a US company, founded in 2020 and headquartered in Petaluma, California, that provides reusable shipping boxes and bags as a replacement for single-use cardboard boxes and poly mailers in e-commerce shipping. Co-founded by CEO Matt Semmelhack, the company sells a packaging-as-a-service model to direct-to-consumer and e-commerce brands: customers receive orders in a durable, reusable Boox container, then return it via a network of drop-off points for cleaning, refurbishment, and reuse on subsequent shipments."}, {"name": "Botánica Granel", "slug": "botanica-granel", "country": "Mexico (Mexico City)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Botánica Granel is a Mexico City-based zero-waste retailer described in local press as the city's first zero-waste mini-supermarket, operating physical bulk stores in the Condesa and Nápoles neighbourhoods alongside an e-commerce site. Founded by Silvana Huicochea, who was inspired by Germany's early zero-waste supermarkets, the business allows customers to bring their own containers to purchase more than 400 package-free products, spanning groceries, personal-care, and cleaning items. The company states that roughly 95% of the products"}, {"name": "Bottle Factory (보틀팩토리)", "slug": "bottle-factory", "country": "South Korea (Seodaemun-gu, Seoul)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Bottle Factory is a Seoul-based social enterprise founded in 2016 by CEO Jeong Da-woon, beginning as a reusable-cup café concept (\"Bottle Café\") in Yeonhui-dong before establishing its current base in Seodaemun-gu. The organisation operates a ground-floor café known as \"Bottle Lounge,\" which serves no disposable cups (lending tumblers to customers without their own, and discounting drinks for customers who bring bottles from home), alongside a basement \"Bottle Factory\" area that has run a packaging-free detergent"}, {"name": "Bottle None", "slug": "bottle-none", "country": "Canada (Kelowna, British Columbia)", "categories": "material-recovery, reusable-packaging, take-back, waste-reduction", "priority": "★★★ Medium", "summary": "Bottle None is a Canadian personal-care company based in Kelowna, British Columbia, selling solid, package-minimal haircare, skincare, and body-care products (shampoo and conditioner bars, deodorants, facial and body sticks) under the tagline \"more living...less waste.\" Its distinguishing reuse feature is a line of travel cases and soap dishes that are 3D-printed in Kelowna from 100% recycled Canadian plastic, paired with a stated end-of-life return program in which worn-out cases can be sent back to the"}, {"name": "Bout' à Bout'", "slug": "bout-a-bout", "country": "France (Nantes / Carquefou, Pays de la Loire)", "categories": "consumer-education, deposit-return, industrial-reuse, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "Bout' à Bout' is a French non-profit association founded in 2016 in Nantes to rebuild a regional glass-bottle reuse (consigne) system in western France. The organisation operates what is reported to be France's largest glass-container washing facility, a 2,500 m² plant in Carquefou powered by renewable electricity supplied by Enercoop, with capacity to wash around 60 million bottles and jars per year (roughly 10,000 per hour). Bout' à Bout' works with close to 100 beverage"}, {"name": "Bower Collective", "slug": "bower-collective", "country": "Not publicly available", "categories": "consumer-education, refill, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "Bower Collective is a UK direct-to-consumer company, founded by Nick Torday and Marcus Hill, that supplies natural household and personal-care products (laundry, home cleaning, body and personal care) in reusable, traceable \"BowerPack\" packaging delivered directly to customers' homes. The name references the bowerbird, known for repurposing colourful debris to decorate its nest. Marcus Hill previously founded and sold London Bio Packaging (a biodegradable food-packaging supplier) to Bunzl, while Nick Torday's background is in digital/technology consultancy"}, {"name": "BOXO", "slug": "boxo", "country": "Netherlands (Leeuwarden)", "categories": "deposit-return, material-recovery, reusable-packaging, reverse-logistics", "priority": "★★★ Medium", "summary": "BOXO is a Dutch start-up based in Leeuwarden that provides reusable shipping packaging (\"Boxobag\") for online retailers as an alternative to single-use cardboard boxes and plastic mailers. The company's packaging was originally developed from discarded big bags used by dairy producer FrieslandCampina, repurposing industrial textile waste into a durable, foldable, multi-use shipping bag. BOXO operates a deposit-based return system: consumers receive a €3.95 deposit refund via digital payment (Tikkie) or in-store when they return a"}, {"name": "Brabantia", "slug": "brabantia", "country": "Netherlands (Aalst, North Brabant)", "categories": "consumer-education, industrial-reuse, material-recovery, repair, waste-reduction", "priority": "★★★★ High", "summary": "Brabantia is a Dutch household-goods manufacturer founded in 1919 in Aalst, North Brabant, originally as Van Elderen & Co., a sheet-metal fabrication business making milk cans, jugs, sieves and funnels. The company has remained under continuous ownership of the van Elderen family across four generations, now employing roughly 1,000 people across four production units and selling in 85 countries. Brabantia is best known for durable, long-life household products — waste bins, laundry and ironing equipment,"}, {"name": "Branch Basics", "slug": "branch-basics", "country": "United States (Minneapolis, Minnesota — relocated 2022; originally associated with Texas)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Branch Basics is a US direct-to-consumer cleaning-products company built around a single \"Concentrate\" that customers dilute with water into refillable glass or plastic bottles, replacing multiple single-purpose, single-use cleaning products. It was founded in 2012 by Marilee Nelson, Allison Evans, and Kelly Love, whose personal health experiences motivated a focus on human-safe, plant-based formulations. The company paused sales in December 2015 over formula-transparency concerns with a licensed supplier, relaunched under its own proprietary formula in"}, {"name": "BROS", "slug": "bros", "country": "Malaysia (Petaling Jaya, Selangor)", "categories": "consumer-education, reusable-packaging, take-back", "priority": "★★★ Medium", "summary": "BROS is a Malaysian brand of reusable water bottles and food containers, founded in 2004 by Terence and Zoe, who began by selling colourful reusable bottles from a small kiosk in the One Utama shopping mall. Now operated by Living Wing Sdn Bhd and based in Petaling Jaya, Selangor, BROS markets itself as \"The Number 1 Brand of Refillable Water Bottles in Malaysia,\" selling across multiple product lines in stainless steel and plastic, including a"}, {"name": "Brush Naked", "slug": "brush-naked", "country": "Canada — Kelowna, British Columbia", "categories": "consumer-education, waste-reduction", "priority": "★★ Low", "summary": "Brush Naked is a small, privately held Canadian company based in Kelowna, British Columbia, that manufactures bamboo-handled toothbrushes for adults and families. The company markets itself as \"Canadian-owned\" and positions its products as an alternative to plastic toothbrushes, which it notes typically end up in landfill. Brush Naked offers bamboo toothbrushes with either biodegradable bristles or BPA-free nylon bristles, packaged in what the company describes as plastic-free packaging. Products are sold online direct-to-consumer with international"}, {"name": "Bulle Verte", "slug": "bulle-verte", "country": "France — Drôme Provençale, Rhône-Alpes region (not Belgium; distributed in Belgium via local distributors)", "categories": "refill, reusable-packaging", "priority": "★★★ Medium", "summary": "Bulle Verte is a French, family-owned manufacturer of ecologically certified cleaning products, hand cleaners, and (since 2019) cosmetics, based in the Drôme Provençale region. According to trade press (Bio Linéaires), the company originated in 1986 as CDS, a soap-distribution business serving mechanics, began manufacturing hand cleaners in 1988, and adopted the \"Bulle Verte\" brand in 1994. It initially built its business supplying professional clients (garages, dry cleaners, restaurants, local authorities) before expanding into organic/bio retail."}, {"name": "Bundle Packaging", "slug": "bundle-packaging", "country": "United Kingdom — Shelley, Huddersfield, West Yorkshire (not United States)", "categories": "reusable-packaging", "priority": "★★ Low", "summary": "Bundle Packaging Limited is a small, privately owned UK packaging supplier headquartered in Huddersfield, West Yorkshire, founded in 2019. It provides custom-branded packaging — boxes, mailers, tape, tissue paper, stickers, and bags — to e-commerce and small-to-medium brands, positioning itself around sustainability, stating its materials are \"fully recyclable and biodegradable\" and plastic-free. The company was founded by individuals with a combined background in the luxury packaging industry. Company size appears small (2–10 employees per LinkedIn),"}, {"name": "by Humankind", "slug": "by-humankind", "country": "United States — New York, NY", "categories": "consumer-education, refill, reusable-packaging", "priority": "★★★★ High", "summary": "by Humankind is a US direct-to-consumer personal care company, headquartered in New York, founded by Brian Bushell and Joshua Goodman. The company sells natural-ingredient deodorant, shampoo bars, and mouthwash tablets built around a reusable-container, subscription-refill model designed to reduce single-use plastic packaging. It raised a $4 million seed round led by Lerer Hippeau (announced February 2019), with participation from Red Sea Ventures, BoxGroup, SV Angel, Great Oaks, and individual investors including SoulCycle co-founder Elizabeth Cutler."}, {"name": "Capsa Packaging", "slug": "capsa-packaging", "country": "Spain — Canet de Mar, Barcelona (Catalonia)", "categories": "industrial-reuse, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Embalajes Capsa, S.L., trading as Capsa Packaging, is a privately held Spanish company founded in 1998 in Canet de Mar, Barcelona, by Manel López (CEO) and Olga Vidal (commercial director). The company designs, manufactures, and licenses corrugated-cardboard packaging solutions, with its flagship product being the patented Capsa 2in1® reusable box, which combines a shipping box and a storage/carrying container in one dual-closure design. The company holds a substantial patent portfolio (75 patents reported in trade"}, {"name": "Capsule Minimal", "slug": "capsule-minimal", "country": "Israel — associated with Karmiel (I4Valley Karmiel Incubator for Small Industry); precise HQ address not independently confirmed", "categories": "refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Capsule Minimal is an Israeli startup that develops water-soluble \"Active Capsules™\" — concentrated dry-form personal care and household product formulas that, when dropped into a reusable bottle with tap water, dissolve into a finished product such as shampoo, body wash, hand soap, toothpaste, mouthwash, or household cleaner. The company was co-founded by Yael Goethe (a biotechnology engineer and CEO) and Ami Krupik (Chairman), and developed through the I4Valley Karmiel Incubator for Small Industry, which is"}, {"name": "Carccu", "slug": "carccu", "country": "Finland — Ruskepääntie 4, 38100 Sastamala (Karkku village, Rautavesi landscape)", "categories": "Not publicly available", "priority": "★ Low relevance", "summary": "Carccu is a Finnish flexographic printing house and paper packaging manufacturer based in Sastamala, operating as EPP-Pack Oy. It is a family business, now in its fourth generation of ownership, with Lasse Borg as CEO and founder Olli Borg still involved. The company manufactures packaging papers, takeaway food containers, meat/fish/cheese wrapping papers, flower and gift wrapping papers, and paper bags, using flexographic printing with water-based inks. Its sustainability positioning centres on fossil-free manufacturing electricity, a"}, {"name": "Care by Nature", "slug": "care-by-nature", "country": "Denmark — Vestbygade 23, 9610 Nørager", "categories": "consumer-education, waste-reduction", "priority": "★★ Low", "summary": "Care by Nature is a Danish company, operating under the legal entity Nordic Beauty Supply ApS, based in Nørager, that sells natural laundry and household cleaning products centred on soap berries (sæbebær) — dried fruit shells containing natural saponins used as a chemical-free alternative to conventional liquid detergent. According to the company's own account, it was founded by a mother (named Camilla on the company's website) after finding soap berries resolved skin irritation caused by"}, {"name": "Carrefour", "slug": "carrefour", "country": "France — Massy", "categories": "consumer-education, deposit-return, reusable-packaging", "priority": "★★★ Medium", "summary": "Carrefour is a French multinational retail group operating hypermarkets, supermarkets, and convenience formats globally, with roughly 298,000–325,000 employees depending on source and year. As one of the world's largest retailers, its relevance to reuse comes from acting as a distribution channel for reuse systems rather than being a reuse operator itself: it hosts TerraCycle's Loop reusable-packaging platform at commercial scale in France (its largest market globally for Loop) and has piloted bring-your-own-container schemes in French"}, {"name": "CauliBox", "slug": "caulibox", "country": "United Kingdom — London, England", "categories": "deposit-return, digital-tracking, reusable-packaging, reverse-logistics, waste-reduction", "priority": "★★★★ High", "summary": "CauliBox (legal name Cauli Ltd) is a UK reuse-system operator providing reusable food containers and coffee cups (\"CauliCups\") to workplace canteens, hospitals, and offices as a substitute for single-use packaging. Founded in 2019 and headquartered in London, the company describes itself as running the largest reuse system for foodservice in the UK. Customers borrow containers via a mobile app using QR-code tracking, use them, and return them to be washed and redistributed. Confirmed clients include"}, {"name": "Cero Market", "slug": "cero-market", "country": "Argentina — Belgrano, Ciudad Autónoma de Buenos Aires", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Cero Market is described in Argentine press as the country's first \"container-free\" (package-free) supermarket, opened in 2020 in the Belgrano neighborhood of Buenos Aires at Avenida Monroe 2468. Co-founded by Ana Pierre and her partner Juan José, who researched similar bulk-retail models in Europe (citing a long-running example in Germany) before launching, the store lets customers bring their own containers — bags, jars, bottles, tuppers — to buy food, cleaning, and personal-care products by weight,"}, {"name": "Cero (Cero Tucson)", "slug": "cero", "country": "United States — Tucson, Arizona", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "Cero (branded \"Cero Tucson\") was a vegan, zero-waste retail store in Tucson, Arizona, describing itself as the city's first dedicated zero-waste shop. It began as a pop-up in May 2019, co-founded by Val Timin and Nelene Deguzman, and grew into a permanent retail and events space, later located along Tucson's Sunshine Mile (Broadway Boulevard) at 160 S. Avenida del Convento. The store centered on a refill bar for household and personal-care staples alongside local, handmade,"}, {"name": "Chakra Suthra", "slug": "chakra-suthra", "country": "Sri Lanka — Colombo", "categories": "consumer-education, material-recovery, reverse-logistics", "priority": "★★★ Medium", "summary": "Chakra Suthra (\"Chakra\" = circularity, \"Suthra\" = formulas) is a Sri Lankan circular-economy company whose flagship programme, Trash2Cash, operates reverse-vending machines that accept empty plastic bottles, aluminium cans, and Tetra Paks, rewarding depositors via a mobile app or at partner retailers. Founded and led by Himesh Fernando, the company also offers circular-economy consulting and business-model re-engineering services. Its stated aim is to make homes and businesses in Sri Lanka zero-waste by keeping materials in circulation."}, {"name": "Charoen Pokphand Group (CP Group)", "slug": "charoen-pokphand-group", "country": "Thailand — Bangkok", "categories": "Not publicly available", "priority": "★ Low relevance", "summary": "CP Group is a large Thai multinational conglomerate spanning agribusiness, food, retail, telecommunications, and other sectors across Thailand and ASEAN. In February 2025 it signed a memorandum of understanding with Mitsubishi Electric Corporation to collaborate on carbon neutrality and circular-economy initiatives, combining Mitsubishi Electric's technology/data capabilities with CP Group's business infrastructure. As of this research, the partnership is at the goal-setting and exploratory stage rather than an operating reuse system."}, {"name": "Chełpliwe Pudeła", "slug": "chelpliwe-pudela", "country": "Poland — Gdynia", "categories": "reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "Chełpliwe Pudeła is a small, independently run vegan meal-delivery catering business based in Gdynia, Poland. It delivers three meals a day to subscribers in reusable containers and bags rather than disposable packaging, with customers responsible for washing and returning the containers for reuse. The seed name spelling in our internal tracker (\"Chelpliwe Pudela\") was slightly incorrect — the verified name uses Polish diacritics: Chełpliwe Pudeła."}, {"name": "CHEP", "slug": "chep", "country": "Australia (global operations; Brambles parent dual-headquartered Australia/UK)", "categories": "industrial-reuse, reusable-packaging, reverse-logistics, sharing", "priority": "★★★★★ Essential", "summary": "CHEP is the world's leading pallet and container pooling company, operating as the core brand of Australian-listed Brambles Limited. Its origins trace to 1945, when the Australian Federal Government took ownership of a pool of pallets left behind by US forces after WWII, naming it the Commonwealth Handling Equipment Pool; Brambles acquired the business from the government in 1958. CHEP now manages a pool of roughly 348 million pallets, crates, and containers through a network"}, {"name": "Cia Muller", "slug": "cia-muller", "country": "Brazil — Pirassununga/Porto Ferreira region, São Paulo state", "categories": "deposit-return, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "Companhia Müller de Bebidas is a large Brazilian beverage producer best known for the Cachaça 51 brand, producing over 100 million bottles annually and exporting to 60+ countries. Distinct from marketing-only sustainability claims, the company operates a substantial physical reverse-logistics system: approximately 57% of its packaging is returnable, with roughly 20 trucks arriving daily nationwide to deliver used bottles back to the factory for sanitization, inspection, and refilling."}, {"name": "Circolution", "slug": "circolution", "country": "Germany — Frankfurt", "categories": "digital-tracking, packaging-as-a-service, reusable-packaging, reverse-logistics", "priority": "★★★ Medium", "summary": "Circolution is a German startup offering \"packaging-as-a-service\": reusable stainless-steel packaging that grocery and FMCG brands rent instead of purchasing single-use containers, with circolution handling collection, cleaning, tracking, and redistribution of the containers. Founded by Max Bannasch, Kirils Jegorovs, and Alessandro Marchiaro, the company is small (reported 1-10 employees) but has secured a pilot partnership with Nestlé and recognition from Amcor's packaging innovation programme."}, {"name": "Circular&Co.", "slug": "circular-and-co", "country": "United Kingdom — Cornwall", "categories": "consumer-education, material-recovery, reusable-packaging", "priority": "★★★ Medium", "summary": "Circular&Co. is a UK reusable-drinkware company founded in 2003 by Dan Dicker, a former Dyson designer, based in Cornwall. It manufactures reusable coffee cups and travel mugs made from recycled single-use paper cups, plus water bottles made from recycled stainless steel, selling both direct-to-consumer and as branded corporate merchandise. The company states its mission as making circular design the global standard for drinkware."}, {"name": "Circular Brain", "slug": "circular-brain", "country": "Brazil — Jundiaí, São Paulo state", "categories": "digital-tracking, industrial-reuse, material-recovery, reverse-logistics, take-back", "priority": "★★★ Medium", "summary": "Circular Brain is a Brazilian digital platform (\"Circularidade como Serviço\" / Circularity as a Service) coordinating reverse logistics, residential and corporate e-waste collection, trade-in programmes, and traceability for the electronics industry. It connects brand manufacturers, collection points, and recycling operators through a management platform (Plataforma Circulare), reporting a network of 17,000+ collection points and 38+ recycling-operator partners as of 2024. Customer brands include major appliance and electronics manufacturers such as Whirlpool, Gree, Ventisol, Hytera, and"}, {"name": "Circular City Labs", "slug": "circular-city-labs", "country": "Implemented by Deutsche Gesellschaft für Internationale Zusammenarbeit (GIZ), Germany, on behalf of the Federal Ministry for Economic Cooperation and Development (BMZ); ICLEI World Secretariat (Bonn, Germany) is the municipal-engagement partner. Pilot activities run in Tirana (Albania), Tbilisi (Georgia), Medellín (Colombia), and South Africa", "categories": "consumer-education, reusable-packaging, reverse-logistics", "priority": "★★★ Medium", "summary": "Circular City Labs is not an independent company but a German government-funded development-cooperation project. It is implemented by GIZ on behalf of BMZ, funded through the BMZ Initiative for Climate and Environmental Protection (IKU), with ICLEI – Local Governments for Sustainability acting as the main partner for municipal engagement. The project runs accelerator programmes for local, often female-led, small and medium enterprises (SMEs) in four locations — Tirana, Tbilisi, Medellín, and South Africa — to"}, {"name": "Circular Economy Portugal", "slug": "circular-economy-portugal", "country": "Portugal — Lisbon (Casa do Impacto, Travessa de São Pedro, 8, 1200-432 Lisboa)", "categories": "consumer-education, material-recovery, repair, reusable-packaging", "priority": "★★★ Medium", "summary": "Circular Economy Portugal (CEP) is a Lisbon-based non-profit association working to advance a circular economy and a \"society without waste\" in Portugal. It focuses on waste prevention, reuse, and repair through knowledge-sharing, research, capacity-building, and project implementation grounded in social innovation and collaborative action. CEP supports public and private-sector entities — including businesses, government bodies, and civil society groups — with consultancy, training, and applied research on circular economy transitions, including reusable packaging systems. It"}, {"name": "Clean Kiss Lifestyle", "slug": "clean-kiss-lifestyle", "country": "Canada — Ontario", "categories": "Not publicly available", "priority": "★ Low relevance", "summary": "Clean Kiss Lifestyle is a Canadian, women-owned skincare and personal-care brand founded in 2014, based in Ontario with small-batch, in-house manufacturing. It targets midlife women and those experiencing menopause under a \"pro-aging\" positioning, selling skincare, body care, hair care, and bar soaps direct-to-consumer. Its sustainability messaging emphasises clean ingredients and \"responsible packaging\" rather than a documented refill or reuse system."}, {"name": "Cleancult", "slug": "cleancult", "country": "United States", "categories": "consumer-education, material-recovery, refill, reusable-packaging", "priority": "★★★★ High", "summary": "Cleancult is a US household-cleaning brand founded by Ryan Lupberger and Zachary Bedrosian, following roughly four years of R&D into formula and packaging before its 2019 public launch. Its distinguishing feature is refill packaging: customers buy one reusable glass bottle/vessel and then purchase plant-derived soap and cleaning-product refills shipped in plastic-free, paper-based milk cartons — cited as the first company to successfully apply this packaging format to soap and detergent. The company raised $25 million"}, {"name": "CleanCup", "slug": "cleancup", "country": "France", "categories": "reusable-packaging, sharing, waste-reduction", "priority": "★★ Low", "summary": "CleanCup is a French reuse initiative operating what is described as the first automated, eco-friendly water fountain system to distribute and wash reusable glasses, targeting campuses, businesses, and public institutions. It positions itself as a solution to eliminate the more than four billion disposable cups reportedly used annually in France, replacing single-use cups with an automated reusable-glass distribution and washing loop."}, {"name": "Cleanomic", "slug": "cleanomic", "country": "United States", "categories": "refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Cleanomic is a US household-cleaning brand selling concentrated cleaning tablets that customers dissolve in water inside a reusable glass spray bottle or soap bottle, rather than repeatedly buying pre-mixed liquid cleaner in single-use plastic containers. Its product range spans multi-surface, glass/mirror, wood/flooring, fruit-and-vegetable-wash, and bottle-wash cleaning tablets, sold direct-to-consumer and via Amazon."}, {"name": "Clicko-Brick", "slug": "clicko-brick", "country": "Israel", "categories": "industrial-reuse, material-recovery", "priority": "★★ Low", "summary": "Clicko-Brick is an Israeli startup, founded in 2015 by Yaron Toren and Gilead Meroz, that redesigns used plastic liquid containers into interlocking modular building blocks. The containers connect via a firm mechanism in all directions (including top and bottom) and are available in square, hexagonal, and triangular shapes ranging from 250ml to 4.5 litres, fillable with air, liquids, or granular solids to give the resulting structure different properties — targeting applications in construction, agriculture, and"}, {"name": "Climate-KIC (EIT Climate-KIC)", "slug": "climate-kic", "country": "Netherlands (pan-European network; seed's \"Netherlands\" HQ is consistent)", "categories": "consumer-education, industrial-reuse", "priority": "★★ Low", "summary": "EIT Climate-KIC was established in 2010 as one of the European Institute of Innovation and Technology's first Knowledge and Innovation Communities, funded predominantly by the EU's EIT body. It brings together 400+ partners from business, academia, and the public/non-profit sectors to develop and scale climate-relevant innovation, including — but not limited to — circular-economy ventures. Its remit spans business acceleration, municipal climate-entrepreneurship support, leadership upskilling, and innovation-project funding across the whole climate-action space, of which"}, {"name": "Club Saludable", "slug": "club-saludable", "country": "Argentina — Buenos Aires (Av. Callao 836, Barrio Norte)", "categories": "refill, waste-reduction", "priority": "★ Low relevance", "summary": "Club Saludable (formally \"Dietética Club Saludable\") is a small independent health-food and bulk-goods shop in the Barrio Norte area of Buenos Aires, Argentina, selling dried fruits, cereals, legumes, organic products, and vegetarian/vegan items, including options sold by weight (\"a granel\") — a bulk-refill format that reduces packaging compared to pre-packaged goods. During this research pass, its online store (mitiendanube.com) displayed a notice that the store had been discontinued (\"la tienda fue dada de baja\"), while"}, {"name": "Clubzero", "slug": "clubzero", "country": "UK (New Malden / London area)", "categories": "consumer-education, deposit-return, digital-tracking, packaging-as-a-service, reusable-packaging, reverse-logistics, waste-reduction", "priority": "★★★★ High", "summary": "Clubzero (formerly CupClub) is a UK-founded reuse-system company that provides returnable, serialised packaging — cups, containers and other food-service items — tracked via QR code, RFID or barcode, for the food & beverage sector. Founded by Safia Qureshi, the company began with reusable to-go cup infrastructure and has since expanded into a broader \"Reuse System\" covering on-trade (restaurants, stadiums), retail, and online-order channels. It positions itself as a \"Reuse Scheme Administrator,\" handling packaging serialisation, washing/logistics"}, {"name": "CMG (Czyste Miasto Gdańsk)", "slug": "cmg", "country": "Poland — Gdańsk", "categories": "consumer-education, digital-tracking, waste-reduction", "priority": "★★ Low", "summary": "Czyste Miasto Gdańsk (\"Clean City Gdańsk,\" abbreviated CMG in seed data) is the City of Gdańsk's municipal waste-management programme, running public education initiatives under a \"Less Waste\" banner. Its core public-facing tools are a free mobile app teaching residents the \"6R\" principle (Refuse, Reduce, Reuse, Repair, Rot, Recycle) and guidance on the city's 5-bin waste-sorting system, alongside broader conditions to support reduce/reuse/recycle practice across the city."}, {"name": "Coca-Cola Returnables (Brazil)", "slug": "coca-cola-returnables", "country": "Not publicly available", "categories": "consumer-education, deposit-return, material-recovery, refill, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "\"Retornáveis\" is Coca-Cola's returnable-bottle packaging initiative in Brazil, under which consumers buy beverages in glass or \"RefPET\" (returnable PET) bottles, return the empty bottle at point of sale, and pay only for the liquid content on subsequent purchases. It is not a separate company but a packaging and marketing program operated by The Coca-Cola Company's Brazilian trademark licensee bottlers. Returnable formats are offered in glass (200ml, 290ml, 1000ml, 1250ml) and RefPET (1500ml, 2000ml) across Coca-Cola,"}, {"name": "Cokodeal", "slug": "cokodeal", "country": "Nigeria (Abuja)", "categories": "Not publicly available", "priority": "★ Low relevance", "summary": "Cokodeal is a Nigeria-headquartered B2B e-commerce marketplace that lets African traders, manufacturers, farmers and small businesses create self-managed online stores to market and export locally-produced goods — agricultural commodities, foodstuffs, textiles, crafts, solid minerals and similar categories — to buyers within Africa and internationally. Founded by Mike Dola, the platform describes its mission as connecting intra-African and Africa-to-global trade, targeting price disparities and limited market access faced by African producers and exporters. It is frequently"}, {"name": "Coles Local (Chatswood store)", "slug": "coles-local-chatswood-store", "country": "Australia — Sydney, New South Wales", "categories": "material-recovery, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Coles Local Chatswood is a concept supermarket store operated by Coles Group, opened 11 November 2020 in Westfield Chatswood, Sydney. It features what Coles describes as Australia's first in-supermarket refill station for shampoo, conditioner, body wash, and laundry liquid, alongside a broader locally-focused format sourcing from 35+ Sydney-based suppliers and additional sustainability features (recycled-material trolleys, food composting)."}, {"name": "Colombia Plastics Pact", "slug": "colombia-plastics-pact", "country": "Colombia", "categories": "consumer-education, material-recovery, waste-reduction", "priority": "★★★★ High", "summary": "The Colombia Plastics Pact is a national multi-stakeholder initiative launched in 2023, coordinated by CEMPRE (Business Commitment to Recycling, Colombia) and the UK-based Waste and Resources Action Programme (WRAP), with UK Research and Innovation (UKRI) support. It is the second Plastics Pact in Latin America and sets four 2030 targets: eliminate 100% of problematic/unnecessary plastics; make 100% of plastic packaging reusable, recyclable, or compostable; achieve a 50% effective recycling rate; and ensure 30% recycled content"}, {"name": "Common Good", "slug": "common-good", "country": "United States — New York/Brooklyn", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Common Good is a plant-based soap, detergent, and cleaner brand founded in 2010 by Sacha Dunn (an Australian-born founder based in Brooklyn, New York), built around reducing single-use plastic through in-store refill infrastructure. The company operates more than 100 physical refill stations at retail partners, where customers can bring back and refill bottles rather than purchasing new packaged product each time, alongside conventional retail and wholesale product sales."}, {"name": "Conatural", "slug": "conatural", "country": "Pakistan — Lahore", "categories": "consumer-education, waste-reduction", "priority": "★★ Low", "summary": "Conatural is described as Pakistan's first 100% natural and organic hair and skincare brand, founded in 2014 in Lahore (sources vary on exact founder names — reported as either sisters-in-law Rema Taseer and Shehrbano Taseer, or sisters Myra Qureshi and Rema Taseer). The company sells naturally-derived skincare and haircare products free from sulfates, parabens, and silicones, positioned around sustainability and eco-friendly packaging, and raised $825,000 in pre-Series A funding (MENAbytes reporting) to grow the brand."}, {"name": "conTeyor", "slug": "conteyor", "country": "Belgium (conTeyor); Germany — Saarlouis (KTP); combined group operates across both", "categories": "industrial-reuse, packaging-as-a-service, reusable-packaging", "priority": "★★★★ High", "summary": "conTeyor was founded in 1995 by Jos van Bree in Belgium, developing a textile-based hanging/folding packaging system originally designed to protect delicate automotive parts through repeated reuse cycles. In October 2024, conTeyor merged with Germany's KTP Kunststoff Palettentechnik GmbH (founded 1988 by Horst Wintrich, originally a recycling operation for a Ford plant before evolving into reusable foldable-container systems) to form a combined group with approximately 1,000 employees and roughly €200 million in sales, combining KTP's"}, {"name": "Coop", "slug": "coop", "country": "Switzerland — Basel", "categories": "refill, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "Coop is one of Switzerland's two largest retail groups, structured as a cooperative with roots tracing to Switzerland's first consumer cooperative (founded 1864 in Schwanden, canton of Glarus) and the 1890 formation of the Verband Schweizerischer Konsumvereine (Federation of Swiss Consumer Cooperatives), the direct predecessor of today's Coop. With 90,000+ employees, Coop operates bulk-goods dispensers in some stores for products like nuts, grains, and pulses, encouraging customers to bring reusable bags or jars rather than"}, {"name": "Cosmogen", "slug": "cosmogen", "country": "France — Paris", "categories": "material-recovery, packaging-as-a-service, refill", "priority": "★★★★ High", "summary": "Cosmogen is a French cosmetics-applicator and packaging specialist based in Paris, founded roughly 35 years ago (circa 1990-1991), specialising in refillable and reusable applicator systems for colour cosmetics — including its patented \"Powder Pack\" (an airtight, refillable compact with paper refills) and \"Tense Cushion\" dual-sided applicator for concealer, blush, and highlighter. The company reported record 2025 turnover (+16% growth), with the US accounting for 20% of sales, driven by product launches with major beauty brands"}, {"name": "Costa Brazil", "slug": "costa-brazil", "country": "United States (brand headquartered in the US; sources sustainable ingredients from Brazil)", "categories": "Not publicly available", "priority": "★ Low relevance", "summary": "Costa Brazil is a luxury beauty and personal-care brand founded in 2016 by Francisco Costa, former creative director of Calvin Klein Collection. The brand sells body oils, creams, fragrances, face serums, candles, and haircare products formulated around Brazilian ingredients — notably Kaya oil from sapucaia trees in northern Brazil — sold across 30+ countries, with sustainability positioning built around FSC-certified packaging, vegan/cruelty-free formulation, and partnerships with Conservation International and Brazil's Yawanawá tribe."}, {"name": "Cup Club", "slug": "cup-club", "country": "United Kingdom — London", "categories": "digital-tracking, reusable-packaging, reverse-logistics", "priority": "★★ Low", "summary": "CupClub was the original brand name of what is now Clubzero, founded in 2018 by UCL alumnus Safia Qureshi with the goal of replacing single-use cup packaging with a reusable, tracked cup system for hot and cold beverages. Operating initially in London offices and later rolling out a retail network in Palo Alto, California, CupClub's operations were disrupted by the COVID-19 pandemic; the company subsequently returned to London and rebranded as Clubzero, broadening its positioning"}, {"name": "Cupable", "slug": "cupable", "country": "India — Mumbai", "categories": "digital-tracking, rental, reusable-packaging, reverse-logistics, sharing", "priority": "★★★ Medium", "summary": "Cupable is a Mumbai-based startup, founded in 2019, that designs and manufactures reusable cups and food containers from crop-waste materials such as rice husk and bamboo fibre, as an alternative to single-use plastic at restaurants, cafés, and events. Each unit is designed for up to roughly 250 uses. The company offers both outright purchase (including customised branded cups for corporate events) and a rental model where clients pay only washing charges, with Cupable handling delivery,"}, {"name": "Cupkita", "slug": "cupkita", "country": "Indonesia — Jakarta", "categories": "deposit-return, digital-tracking, reusable-packaging", "priority": "★★ Low", "summary": "Cupkita was a Jakarta-based reusable-cup deposit-return pilot, developed as a venture within Enviu's Zero Waste Living Lab programme and explicitly described in sourcing as \"a replication of Muuse,\" a similar reusable-cup company operating in San Francisco, Singapore, and Hong Kong. The service let coffee-shop customers receive drinks in reusable cups against a refundable digital deposit paid via QR code, returning cups to participating shops or smart bins to reclaim the deposit, with Cupkita handling collection,"}, {"name": "CupLoop", "slug": "cuploop", "country": "Estonia — Tallinn", "categories": "deposit-return, digital-tracking, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "Cuploop is an Estonian reusable-packaging company, founded by CEO Lauri Luik and CTO Christopher Juul, based in Tallinn. It operates \"smart kiosks\" using RFID technology that let customers deposit empty reusable cups and receive instant refunds via phone or card under a \"Drop, Tap & Go\" model, supported by a cloud-based inventory-management system (LoopMate®) and a monthly service package including automated deposit transactions and ESG reporting for client businesses."}, {"name": "Cyclic Design", "slug": "cyclic-design", "country": "Germany — Leipzig", "categories": "material-recovery, refill, reusable-packaging", "priority": "★★ Low", "summary": "Cyclic Design is a Leipzig, Germany-based sustainable-design consultancy founded in 2019, specialising in sustainable packaging design and lifecycle analysis for the circular economy. Its best-documented product is Nepenthes, a capless, refillable personal-care bottle for hair and body-care products made from roughly 50% bio-based polyethylene derived from sugarcane, positioned as a space- and plastic-saving refillable packaging design."}, {"name": "Czyste Miasto Gdansk (CMG)", "slug": "czyste-miasto-gdansk", "country": "Poland (Gdańsk)", "categories": "consumer-education, material-recovery, repair, sharing, waste-reduction", "priority": "★★ Low", "summary": "Czyste Miasto Gdańsk (\"Clean City of Gdańsk,\" abbreviated CMG) is a public-facing brand and communications/education programme operated by the Department of Municipal Economy of Gdańsk City Hall, in Poland. Rather than being an independent company, CMG is the city's umbrella identity for municipal waste-management services, resident communication (collection schedules, sorting rules, a mobile app) and — under a \"Circular Economy\" and \"Less Waste Idea\" strand — public education encouraging residents to reduce consumption, repair goods,"}, {"name": "Damn Plastic", "slug": "damn-plastic", "country": "Austria — Salzburg", "categories": "consumer-education, material-recovery, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Damn Plastic is an Austrian sustainability retailer founded by co-founders referred to on the company's site as Victoria and Steph, operating physical stores (Salzburg flagship, Linz, and additional locations), an e-commerce platform, B2B event consulting and corporate gifting services, and a franchise system extending into Slovenia. It sells curated \"impact items\" across beauty, household, accessories, kids, and travel categories, under a stated philosophy of \"passive sustainability\" — positioning itself as handling the sustainability effort so"}, {"name": "Dari Hulu Store", "slug": "darihulu-store", "country": "Indonesia — Balikpapan", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "Dari Hulu is a Balikpapan, Indonesia-based zero-waste initiative founded by Ronald and Oda, combining a bulk-refill store with broader waste-reduction education. The name is reported to mean \"From Yourself\" (per one source), reflecting a philosophy of individual responsibility for waste reduction. The initiative began through social media before expanding into two physical facilities: Halte Sampah (a waste-sorting shelter/facility) and Dari Hulu Bulk Store, which operates a bring-your-own-container refill model by appointment."}, {"name": "Day by Day", "slug": "day-by-day", "country": "France", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Day by day is described as France's first bulk-grocery (\"vrac\") retail network, founded in 2011 by Didier Onraita and David Sutrat under the company My Retail Box, with the first store opening in Meudon in May 2013. It operates as a franchise model selling 750+ products without packaging, letting customers buy exactly the quantity they need using reusable or returnable containers. The network has grown to more than 70 stores across France, with locations also"}, {"name": "Delivery-Refillery", "slug": "delivery-refillery", "country": "United States", "categories": "refill, waste-reduction", "priority": "★★ Low", "summary": "Delivery Refillery is a US refill-delivery service allowing customers to order household and personal-care products priced and sold \"per ounce\" (by weight), with orders delivered to the customer's home — part of a wider category of regional US \"refillery\" delivery businesses (alongside comparable services such as The Daisy Refillery in California, Mi Mobile Refillery in Michigan, and Wonderfill Refillery in Tennessee) that emerged to bring bulk/refill retail's waste-reduction benefits to a delivery-based model rather than"}, {"name": "Delterra", "slug": "delterra", "country": "United States (global non-profit; Argentina programmes based in Buenos Aires Province)", "categories": "consumer-education, material-recovery, waste-reduction", "priority": "★★ Low", "summary": "Delterra is a global environmental non-profit that spun out of McKinsey & Company's philanthropic arm, McKinsey.org, in 2021, inheriting the \"Rethinking Recycling\" initiative launched in 2018. Led by CEO Shannon Bouton, a former McKinsey.org executive, Delterra designs and operates municipal recycling and waste-management systems in emerging-market cities. In Argentina, its two flagship programmes are \"A Todo Reciclaje\" in Barrio Mugica (an informal Buenos Aires community, since 2019) and GIRO in Olavarría, plus an innovation cohort"}, {"name": "Despensa R - Granel Sustentável", "slug": "despensa-r", "country": "Portugal (Algés, Oeiras municipality, Lisbon metro area)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Despensa R is a bulk-goods (\"granel\") retail store in Algés, Portugal, that opened in June 2023 with a mission to revive traditional package-free shopping in a modern setting. Customers bring their own containers, jars or bags to fill with organic and artisanal food products — legumes, dried fruits, flours, herbs, spices, cereals, granola, teas and fresh-ground coffee — as well as home and personal-care items. The store also features an in-store nut-butter machine allowing customers"}, {"name": "Desplastifícate", "slug": "desplastificate", "country": "Mexico (Mexico City / CDMX)", "categories": "consumer-education, deposit-return, refill, reusable-packaging, reverse-logistics", "priority": "★★★ Medium", "summary": "Desplastifícate (\"De-plasticize yourself\") is a Mexico City-based social enterprise that sells biodegradable, non-toxic cleaning and home-care products in returnable glass containers. Its circular model charges a small deposit (reported as 10 Mexican pesos per container) that is refunded or credited when customers return empties with their next order. The company positions itself against single-use plastic and chemical-heavy cleaning products, offering formulas described as biodegradable within 14 days. It is recognised as a social enterprise by"}, {"name": "DiFOLD", "slug": "difold", "country": "Bulgaria", "categories": "consumer-education, reusable-packaging", "priority": "★★★ Medium", "summary": "DiFOLD is a Bulgarian startup that designed the \"Origami Bottle,\" a foldable, reusable 750ml bottle made from bio-based thermoplastic polymer that collapses to roughly 20% of its expanded size for portability. Co-founded by ad-industry veteran Radina Popova and architect/designer Petar Zaharinov after they met through the Climate-KIC clean-tech accelerator in 2018, the company combines origami-inspired folding mechanics with recyclable, multi-use plastic to create an alternative to single-use plastic bottles. The product line has expanded to"}, {"name": "Dilute", "slug": "dilute", "country": "Finland (Nokia, Finland)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Dilute is a Nordic cleaning-products brand that sells concentrated cleaning solutions in paper-based, water-soluble sachets designed to be dissolved into a reusable spray bottle rather than shipped as a pre-mixed liquid in a new plastic bottle each time. The brand is operated by EkoEkoShop Trading Oy, based in Nokia, Finland, and offers three core product lines — Kitchen Cleaner, All-Purpose Cleaner and Bathroom Cleaner — sold as starter kits (bottle plus refill sachets) or standalone"}, {"name": "Dispo Plastik", "slug": "dispo-plastik", "country": "Turkey (Esenyurt, Istanbul)", "categories": "Not publicly available", "priority": "★ Low relevance", "summary": "Dispo Plastik is a Turkish thermoform-plastics manufacturer based near Istanbul, producing plates, cups, cutlery, food containers, fruit-packaging trays, nursery/seedling trays and related disposable tableware products at reported production volumes exceeding 1,000 tons per month. It supplies business customers through B2B trade channels and international marketplace/directory listings such as Europages and Netetrade. Available public sources — including its own marketplace listings — describe Dispo Plastik's core product range as **disposable/single-use** plastic tableware and packaging, in contrast"}, {"name": "Divers Clean Action", "slug": "divers-clean-action", "country": "Indonesia (Jakarta)", "categories": "consumer-education, material-recovery, refill, reverse-logistics, waste-reduction", "priority": "★★★ Medium", "summary": "Divers Clean Action (DCA) is an Indonesian non-profit founded in 2015 by diver and marine conservationist Swietenia Puspa Lestari, alongside co-founders Nesha Ichida and Adi Septiono, following a beach/underwater clean-up mapping activity that drew over 100 volunteers. Legally registered as Yayasan Penyelam Lestari Indonesia, DCA works across research, community campaigns/workshops, community development and corporate CSR/EPR collaboration to reduce marine plastic pollution. Its \"Toko Cura\" (\"Reuse and Refill\" shop) initiative, launched in Jakarta's Kepulauan Seribu (Thousand"}, {"name": "Dizzie", "slug": "dizzie", "country": "United Kingdom — registered office London NW1; operational HQ Nuneaton, England (per LinkedIn)", "categories": "consumer-education, digital-tracking, packaging-as-a-service, refill, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "Dizzie was a UK reusable-packaging company, legally registered as Good Clubs Limited, founded by Ben Patten. It began in 2019 as Good Club, a direct-to-consumer online grocer delivering products in reusable containers that were collected, washed, and refilled. In September 2022 the company rebranded as Dizzie and pivoted to a B2B \"reusable packaging as a service\" model, supplying empty and filled reusable containers, collection, washing, and tracking services to grocers and brands. It closed its"}, {"name": "dotch", "slug": "dotch", "country": "Germany (Berlin)", "categories": "packaging-as-a-service, reusable-packaging, reverse-logistics, take-back", "priority": "★★★★ High", "summary": "dotch is a Berlin-based startup founded in 2022 that builds a reusable packaging system for cooking oils, vinegars, preserves and sauces. It supplies producers with a standardised, unbreakable bottle designed for up to 50 reuse cycles, and operates the full reverse-logistics loop — pool management, empties collection, industrial cleaning and redistribution — as a service to food producers and retailers, so that \"reusable\" becomes as operationally simple as single-use packaging. Its flagship deployment is with"}, {"name": "DPD (Germany)", "slug": "dpd", "country": "Germany (Aschaffenburg)", "categories": "reusable-packaging, reverse-logistics, take-back", "priority": "★★★ Medium", "summary": "DPD Deutschland is one of Germany's largest private parcel-delivery companies, founded in 1976 and now a subsidiary of Geopost (La Poste Group), operating roughly 81 parcel-sorting centres and around 8,000 employees domestically (with Geopost group-wide headcount considerably larger internationally). While DPD's core business is conventional single-use parcel shipping, this profile focuses on two specific reuse-relevant initiatives it has piloted: a reusable shipping-packaging partnership with Berlin startup hey circle, and clothing-donation collection through its delivery network."}, {"name": "DSF L&I", "slug": "dsf-lsi", "country": "South Korea (Jongno-gu, Seoul; also operates a facility in Chungcheongbuk-do)", "categories": "deposit-return, digital-tracking, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "DSF L&I is a South Korean company, established in 2017 and headquartered in Seoul, that develops and commercialises a reusable-container and cup return system using near-field communication (NFC) technology for restaurants and food-service businesses. The company expanded its reuse-infrastructure capacity by acquiring Happy Bridge in August 2021 — a firm specialising in washing and cleaning reusable cups and containers for clients including Starbucks — and completed a processing plant in Yongin, Gyeonggi Province, in a"}, {"name": "Dükkan (Atıksız Yaşam Dükkanı) - Kadıköy Municipality", "slug": "dukkan-kadikoy", "country": "Turkey (Kadıköy district, Istanbul)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★★ High", "summary": "The Atıksız Yaşam Dükkanı (\"Zero Waste Life Shop\") is a municipally-run retail initiative of Kadıköy Belediyesi (Kadıköy Municipality) in Istanbul, described in Turkish press and municipal sources as the country's first and only local-government zero-waste store. The first location opened on 5 June 2020 (World Environment Day) at the Feneryolu fixed market, with a second branch opening in 2022 at the Caddebostan Culture Centre (CKM). The shop sells unpackaged or minimally-packaged food, cleaning, kitchen and"}, {"name": "E-Mart", "slug": "e-mart", "country": "South Korea (Seoul)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★★ High", "summary": "E-Mart is South Korea's oldest and largest discount-store chain, founded in 1993 by Shinsegae and now a publicly listed subsidiary (KRX: 139480) operating Emart discount stores, Emart Traders wholesale-style stores, and online retail (Emart Mall/Traders Mall). While E-Mart's core business is conventional grocery/discount retail, this profile focuses on its \"Eco Refill Station\" pilot: a laundry-detergent and fabric-softener refill vending system launched in September 2020 at E-Mart Seongsu and Traders Anseong, developed with detergent brand SugarBubble,"}, {"name": "EarthHero", "slug": "earthhero", "country": "United States (Colorado)", "categories": "consumer-education", "priority": "★★ Low", "summary": "EarthHero is a Colorado-based online marketplace launched in 2017 that curates sustainably made consumer products from vetted, independent brands. Founded by Ryan Lewis (CEO), the company positions itself as a \"one-stop shop\" for eco-friendly alternatives across home, beauty, cleaning, baby, pet, apparel and tech categories. EarthHero screens vendor brands through a proprietary \"5-Pillar Sourcing Methodology\" before listing them, is a Climate Neutral Certified company, and is a member of 1% for the Planet."}, {"name": "Earthware (Earthware Eco Lifestyle)", "slug": "earthware", "country": "South Africa (Randburg, Johannesburg)", "categories": "material-recovery, waste-reduction", "priority": "★ Low relevance", "summary": "Earthware Eco Lifestyle is a South African e-commerce retailer specialising in disposable tableware made from fallen areca palm leaves. The company markets its plates, bowls and platters as fully biodegradable and organic, made without harming trees or using chemicals or artificial additives, converting an agricultural waste by-product into single-use dinnerware. The business is based in North Riding, Randburg, Johannesburg, and ships nationally within South Africa. No founding date, founders, or ownership structure was found on"}, {"name": "EarthWay Refill", "slug": "earthway-refill", "country": "Ireland (Midleton, County Cork)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "EarthWay Refill is a small, independently owned package-free refill store in Midleton, East Cork, Ireland, opened in summer 2020 by Wendy Hickey and her partner Andrea Sivieri. Wendy was inspired by refill dispensers she encountered in an Italian health food shop and, as a parent of a large family struggling to reduce single-use plastic, set out to bring the same model to East Cork. The shop sells dry goods, oils, cleaning products and body-care items"}, {"name": "ebebek", "slug": "ebebek", "country": "Turkey (Istanbul); UK subsidiary at https://ebebek.co.uk/", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "ebebek is Turkey's largest mother-and-baby products retail chain, founded in 2001 as an e-commerce site and expanding into physical stores from 2003. Majority-owned by the Topbaş family since 2011 and publicly listed via IPO in 2023, ebebek operates 300+ stores across 71 Turkish cities plus recent international expansion into the UK (2024) and Iraq (2025). Under its \"baby me\" private label, ebebek has installed in-store detergent refill stations across a subset of its Turkish stores,"}, {"name": "EC30", "slug": "ec30", "country": "United States (Procter & Gamble, Cincinnati, Ohio)", "categories": "waste-reduction", "priority": "★★ Low", "summary": "EC30 is a cleaning-products brand developed within Procter & Gamble's P&G Ventures innovation incubator, first launched around 2019 and later repositioned under the \"Clean 3.0\" banner (2023) as the successor to Ivory Soap (1879) and Tide (1946) in P&G's cleaning-product lineage. Instead of liquid products shipped in plastic bottles, EC30 sells dry, compact single-use pads/strips — for body wash, hand wash, shampoo, conditioner, laundry detergent and toilet-bowl cleaner — that activate into a usable cleaning"}, {"name": "Ecandi (Eco Create and Innovate)", "slug": "ecandi", "country": "Kenya (Rosslyn, Nairobi)", "categories": "consumer-education, material-recovery, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Ecandi (Eco Create and Innovate) is a zero-waste eco-shop based at Rosslyn Gates Centre on Limuru Road in Nairobi, Kenya, founded by Amos Njiraini. It positions itself as Nairobi's premier zero-waste retailer, selling ethically sourced, sustainable everyday products, and operates what is described in industry coverage as the first dedicated bulk refill station of its kind in Kenya, part of its \"Eco Bulk Bar\" offering. The business has been recognised through participation in the Nairobi"}, {"name": "ECCBC / UNIDO PET Pilot (Morocco)", "slug": "eccbc-unido-pet-pilot", "country": "Not publicly available", "categories": "industrial-reuse, material-recovery, reverse-logistics, waste-reduction", "priority": "★★★ Medium", "summary": "The ECCBC/UNIDO PET pilot is a three-year industrial project in Morocco aiming to build a scalable, financially viable system for collecting and recycling PET bottles back into new food-grade bottles (bottle-to-bottle recycling), rather than downcycling into lower-value plastic. It is led by Equatorial Coca-Cola Bottling Company (ECCBC) in partnership with the United Nations Industrial Development Organization (UNIDO), under the EU- and Finland-funded SWITCH to Circular Economy Value Chains (SWITCH2CE) programme. The pilot combines household- and"}, {"name": "eco+amour", "slug": "eco-and-amour", "country": "Canada (originally Scarborough, Toronto, Ontario; more recently associated with a Muskoka, Ontario location)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "eco+amour is a Canadian sustainable-living beauty and home-care refillery, opened in August 2018 by co-founders Sarah Marcus, Laura Craig and Julianne Robicheau. Originally based at 30 Bertrand Ave, Scarborough (Toronto), it was described in contemporary press as a \"concept shop\" combining green beauty retail with a full-service refill model for bath, body and home products, letting customers bring their own clean containers and pay by weight. Secondary sources indicate the original Scarborough pop-up has since"}, {"name": "Eco&More", "slug": "eco-and-more", "country": "China (unconfirmed — inferred from seed data; not independently verified)", "categories": "refill", "priority": "★ Low relevance", "summary": "Eco&More could not be substantively verified. The only located public presence is an Instagram account (@ecoandmore, styled \"{eco&more}\"), which returns image-based content that could not be parsed for text (bio, location, or product details). No standalone company website, press coverage, business registry entry, or secondary source describing operations, founding, or ownership was found through targeted searches in English or Chinese. The seed claim that it offers refill dispensers for soaps, shampoo, and cleaning products could"}, {"name": "Eco Blocks and Tiles", "slug": "eco-blocks-and-tiles", "country": "Kenya (Gilgil, Nakuru County)", "categories": "industrial-reuse, material-recovery, waste-reduction", "priority": "★★★ Medium", "summary": "Eco Blocks and Tiles is a Kenyan social enterprise, founded in 2016 by environmental scientist Hope Mwanake and co-founder Kevin Mureithi, that manufactures roofing tiles and other construction materials from recycled plastic and glass waste. Mwanake's experience running a waste-collection service in Gilgil, where she observed large volumes of discarded plastic bottles, buckets and jerrycans, motivated the venture. The company melts waste plastic (e.g. shampoo and vegetable-oil bottles) and combines it with crushed glass waste"}, {"name": "Eco-Eclectic", "slug": "eco-eclectic", "country": "United States (Jacksonville Beach, Florida)", "categories": "consumer-education, refill, reusable-packaging, sharing", "priority": "★★ Low", "summary": "Eco Eclectic is a small, independently owned sustainable retail business founded in 2020 by Sara Fagen in the Jacksonville Beach/Neptune Beach area of Florida. Founded to make sustainable living more accessible and affordable to her coastal community, the business combines an e-commerce platform, \"microshop\" physical pickup/self-service locations, and community events such as pop-up markets and children's clothing swaps. It markets itself as \"Jacksonville's Zero Waste Shop.\""}, {"name": "Eco Ego", "slug": "eco-ego", "country": "Poland (Bolechowo/Owińska, near Poznań)", "categories": "material-recovery, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "ECO EGO is a Polish brand of household cleaning tools — brooms, mops, buckets and related accessories — manufactured by YORK PL, a Polish company based in Bolechowo near Poznań. The brand is built around closed-loop-economy principles: products are made with a minimum of 60% recycled raw material (using certified regranulate under RecyClass/EuCertPlast and GRS/Global Recycled Standard schemes), and the manufacturing facility recycles 100% of its own polypropylene production waste back into new products. Rather"}, {"name": "Eco Product", "slug": "eco-product", "country": "Pakistan (Karachi)", "categories": "material-recovery, waste-reduction", "priority": "★★ Low", "summary": "Eco Product is a Karachi, Pakistan-based e-commerce business supplying sustainable and biodegradable packaging plus eco-friendly lifestyle products to consumers and businesses across Pakistan. Its catalogue spans kraft standup pouches (45+ variants) for food, cosmetics and beverage packaging, bakery and burger-box packaging, coffee cups, biodegradable food containers, e-commerce shipping boxes, and bamboo/lifestyle items such as toothbrushes, cutlery, cosmetic brushes and soap dishes. No founding date, founders, or ownership structure could be verified from the website or"}, {"name": "Eco Refillery", "slug": "eco-refillery", "country": "Canada (Burnaby, British Columbia — Metro Vancouver)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Eco Refillery is a bricks-and-mortar BYOB (bring-your-own-bottle) refill store located in Burnaby, British Columbia (Metro Vancouver), operated as a retail division of Eco Sanitizer Inc., a company founded by Matthew Nowak in 2020 that originally produced cruelty-free, plant-based cleaning and sanitizing products. The Eco Refillery storefront held its grand opening on June 24, 2022, offering proprietary in-store filling stations where customers refill and reuse their own containers with locally sourced and manufactured cleaning and personal-care"}, {"name": "Eco Tienda Verde", "slug": "eco-tienda-verde", "country": "Spain (León) — NOT Mexico (seed country corrected; see Verification Notes)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "Eco Tienda Verde is an ecological retail store based in León, Spain, at Avenida Padre Isla 107, operating both a physical store and an e-commerce site (ecotiendaverde.es). It sells certified organic and ecological products across Spain, including organic and vegan foods, natural cosmetics, bio hygiene products, eco-friendly household cleaners, medicinal plants/herbal supplements and aromatherapy products. The company holds ecological certification (registration ES-ECO-028-CL.724-0070674.2026.001) and offers some Demeter-certified (biodynamic) food products, alongside 24-48 hour delivery within mainland"}, {"name": "Eco Trace", "slug": "eco-trace", "country": "Kenya", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "EcoTrace is a Kenyan refill startup founded by Donatus Njoroge, who previously headed Innovations, Intellectual Property, and Community Engagement at Mount Kenya University (MKU), where he ran incubation programmes supporting over 1,000 entrepreneurs. EcoTrace delivers refills of everyday consumer necessities — hygiene products, detergent, and cooking oil — via mobile and stationary refill stations, eliminating single-use plastic packaging and lowering costs for low-income customers. The company has been recognised in innovation/climate challenge circles, including a"}, {"name": "EcoAlf (Venezuela)", "slug": "ecoalf-venezuela", "country": "Venezuela (per seed data; unverified)", "categories": "refill", "priority": "★ Low relevance", "summary": "This entry refers to a purported Venezuelan refill-station venture for detergents and cleaning supplies, seeded with the domain ecoalf.com.ve. Direct access to that domain failed (DNS could not resolve the host), and targeted web searches — in both English and Spanish — returned no independent evidence of a Venezuelan company by this name, no press coverage, no social media presence, and no registry record. All search results referencing \"Ecoalf\" instead point exclusively to the unrelated,"}, {"name": "EcoAmigos (Venezuela)", "slug": "ecoamigos", "country": "Venezuela (per seed data; unverified)", "categories": "consumer-education, refill", "priority": "★ Low relevance", "summary": "EcoAmigos is seeded as a Venezuelan initiative running refill pop-ups and community environmental drives, associated with the Instagram handle @ecoamigos.ve. Attempts to access and extract readable content from this specific handle returned only image-encoded data with no parseable bio, post captions, or contact details. Broader searches surfaced numerous unrelated \"EcoAmigos\"-named groups across Latin America (El Salvador, Mexico, Bolivia, Panama, Colombia), none of which could be confirmed as the same Venezuelan entity referenced in the seed"}, {"name": "EcoBag", "slug": "ecobag", "country": "France (Livron-sur-Drôme, Drôme department)", "categories": "reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "EcoBag is a small French company based in Livron-sur-Drôme that has specialised for over two decades in personalised, reusable bags and gift packaging made from natural materials — primarily jute canvas, cotton, kraft paper, and non-woven fabric. Registered as a SARL (SIREN 432 086 437) since July 2000, the company supplies businesses, retailers, producers, and public institutions with custom-branded, durable bags intended to replace single-use packaging, positioning environmental durability alongside client branding and design."}, {"name": "Ecoceno", "slug": "ecoceno", "country": "Portugal (Vila Nova de Gaia)", "categories": "deposit-return, digital-tracking, reusable-packaging, reverse-logistics, waste-reduction", "priority": "★★★★ High", "summary": "Ecoceno is a Portuguese reusable-packaging startup, developed in 2022 and launched commercially in early 2023, created out of Embal, an existing aluminium packaging manufacturer. Based in Vila Nova de Gaia (legal entity Ecoceno Unipessoal Lda, NIF 517334542), it provides a deposit-return system of reusable food and drink containers for restaurants, takeaway venues, stadiums, and events, allowing consumers to return containers to collection points instead of using single-use packaging. The company has received financial support from"}, {"name": "Ecocitex", "slug": "ecocitex", "country": "Chile (Santiago; retail point at MUT/Mercado Urbano Tobalaba, Las Condes; production in Macul)", "categories": "consumer-education, material-recovery, waste-reduction", "priority": "★★★★ High", "summary": "Ecocitex is a Chilean social enterprise founded by Rosario Hevia and Daniela Ehijo, who discovered old spinning machinery in 2019 and by January 2020 had acquired a mill in the Macul district of Santiago to industrially recover textiles too damaged for resale. The company converts post-consumer clothing waste into 100%-recycled yarn, produced without water or dyes — a globally distinctive process — while running a social-reintegration employment programme for women, including formerly incarcerated women, who"}, {"name": "Ecodis", "slug": "ecodis", "country": "France (Saint-Nolff, Morbihan, Brittany)", "categories": "consumer-education, refill", "priority": "★★★ Medium", "summary": "Ecodis is a French distributor and multi-brand manufacturer based in Saint-Nolff, Brittany, founded in 2000 as a pioneer in designing and distributing ecological products to organic and specialty shops. The company supplies roughly 2,000 products across France and Europe, manufactured in France or Western Europe using natural mineral or plant-based materials and maximised organic ingredients, including refillable household cleaning capsules and personal-care items. It operates several in-house brands, including \"La droguerie éco,\" Ah! Table!, Anaé,"}, {"name": "Ecoelephant", "slug": "ecoelephant", "country": "South Africa (Cape Town)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Ecoelephant is a Cape Town-based online zero-waste retailer founded in 2018 by Tina Beyer, describing itself as one of the oldest zero-waste businesses in South Africa. It sells reusable, plastic-free alternatives to everyday disposable items — from reusable market bags and bamboo toothbrushes to stainless steel lunch boxes — aimed at helping consumers build sustainable habits incrementally. The business operates via e-commerce with an additional wholesale inquiry channel for bulk/business buyers."}, {"name": "EcoEnclose", "slug": "ecoenclose", "country": "United States (Louisville, Colorado)", "categories": "consumer-education, material-recovery, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "EcoEnclose was founded in 2010 by Erin Kimmett, initially to supply sustainable packaging for her own cloth-diaper company, Thirsties, before growing into a standalone sustainable packaging business. In 2015, current owners Saloni Doshi and Kyle Wente acquired the company, scaling it from three employees in a 2,000 sq ft Louisville, Colorado warehouse into a Certified B Corporation (score 94.3, top 10% globally for environmental performance) serving more than 25,000 business customers of all sizes with"}, {"name": "EcoLiving", "slug": "ecoliving", "country": "United Kingdom (Worthing, West Sussex)", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "ecoLiving was founded in 2014 by Jo Mack, registered under the legal entity Dani & Jo Ltd and based in Worthing, West Sussex. It has grown into one of the largest vegan, zero-waste/plastic-free non-food product brands in the UK and EU, offering plastic-free alternatives across kitchen, bathroom, and household categories, with all packaging designed to be reused, recycled, or composted. The company operates direct-to-consumer e-commerce alongside B2B wholesale/trade distribution to retailers, including via the Faire"}, {"name": "EcoNowCA (Eco Now)", "slug": "econowca", "country": "Not publicly available", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Eco Now is a Southern California zero-waste retailer and bulk refill shop, founded in 2018 by Thea Merritt, initially selling hand-sewn reusable alternatives to single-use plastics at a farmers' market in Placentia, California. It grew into brick-and-mortar stores across Orange County and the Inland Empire — Anaheim, Costa Mesa, Laguna Beach and Riverside were all opened at various points between 2018 and 2021 — offering fill-up refill stations for household cleaning, personal care and hygiene"}, {"name": "EcoPanplas", "slug": "ecopanplas", "country": "Brazil — Hortolândia, São Paulo", "categories": "industrial-reuse, material-recovery, reverse-logistics", "priority": "★★★ Medium", "summary": "Eco Panplas is a Brazilian industrial recycling company based in Hortolândia, São Paulo, specialising in the recycling of post-consumer plastic lubricant-oil containers — a packaging stream that is typically hard to recycle due to residual oil contamination. Using a patented, odourless, water-free degreasing and grinding process, the company converts contaminated HDPE containers into high-quality recycled resin suitable for new packaging manufacture. It is a Certified B Corporation and has received national and international recognition, including"}, {"name": "EcoPost", "slug": "ecopost", "country": "Kenya — Nairobi", "categories": "consumer-education, industrial-reuse, material-recovery, waste-reduction", "priority": "★★★ Medium", "summary": "EcoPost is a Kenyan social enterprise, founded in 2009 by Lorna Rutto (with co-founder Charles Kalama), that converts recycled plastic waste and agricultural biomass into durable \"plastic lumber\" building materials, most notably fencing posts, as an alternative to timber. Based in Nairobi, the company addresses urban plastic pollution, deforestation and youth unemployment simultaneously by purchasing plastic waste from waste pickers and collectors, giving informal waste workers an income source, and manufacturing long-lasting construction and landscaping"}, {"name": "EcoRoots", "slug": "ecoroots", "country": "United States — Phoenix, Arizona", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "EcoRoots is a US e-commerce retailer of plastic-free personal care and household products, founded by Alin Turcea and Antonia Pitica, originally based in Aspen, Colorado, and now operating out of Phoenix, Arizona. The company sells vegan, small-batch, cruelty-free items such as soap and shampoo bars, dental floss refills, laundry detergent sheets, and reusable/refillable alternatives to conventional plastic personal-care products, shipping all orders using plastic-free packaging materials (cardboard, paper, compostable fill). It positions itself as a"}, {"name": "ecostore Japan", "slug": "ecostore-japan", "country": "Japan", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "ecostore JAPAN Co., Ltd. is the Japanese licensee of the New Zealand natural home and body-care brand ecostore, bringing its plant-based cleaning and personal-care products, and in particular its refill-station model, to the Japanese market. Trade press dates the Japan operation's founding to around 2017, with its \"Refill Station\" concept introduced to Japanese retail — including convenience-store partnerships (Natural Lawson) — from August 2020. It is a distinct, separately incorporated licensee rather than an ecostore-owned"}, {"name": "ecostore papalagi", "slug": "ecostore-papalagi", "country": "Japan — Fujisawa, Kanagawa Prefecture", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "ecostore papalagi is a small, independently run zero-waste retail shop in Fujisawa, Kanagawa Prefecture, Japan, launched in January 2019 by a professional diver and three colleagues as a form of climate action advocacy. It operates under cooperative governance via the Plastic Free Promotion Association (a worker cooperative, ワーカーズコープ) rather than as a conventional profit-driven company or franchise. Despite the name's resemblance to the New Zealand ecostore brand and its Japanese licensee ecostore JAPAN Co., Ltd.,"}, {"name": "ecostore", "slug": "ecostore", "country": "New Zealand — Auckland (founded in Northland)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★★ High", "summary": "ecostore was founded in 1993 by Malcolm and Melanie Rands on a permaculture eco-village on New Zealand's Northland coast, initially as a mail-order natural cleaning and body-care business. It moved to Auckland in 1997 and opened its first retail refill point the same year. The brand expanded into Australia in 2004 and across Asian markets (China, Japan, Singapore, South Korea, Malaysia, Taiwan, Hong Kong, Philippines) from around 2010–2016. Ownership transferred from the Rands family to"}, {"name": "Ecotutu", "slug": "ecotutu", "country": "Nigeria", "categories": "rental, sharing, waste-reduction", "priority": "★★★ Medium", "summary": "Ecotutu is a Nigerian cleantech startup founded in 2020 by Babajide Oluwase (CEO) and Michael Akinsete, providing off-grid, solar-powered cold storage units for perishable agricultural produce. Rather than selling cooling equipment outright, Ecotutu operates a \"pay-as-you-chill\" service model, deploying its units into open-air markets and farm clusters across Nigeria to reduce post-harvest food loss for smallholder farmers and traders who otherwise lack access to capital-intensive refrigeration. The company has been recognised in several cleantech/social-enterprise competitions,"}, {"name": "EcoU", "slug": "ecou", "country": "Singapore", "categories": "Not publicly available", "priority": "★ Low relevance", "summary": "EcoU is a Singapore-based supplier of disposable cutlery, plates, bowls, cups, straws and takeaway packaging, marketed as an eco-friendlier alternative to plastic disposables. Its core products are FSC-certified plantation-birch wooden cutlery (compostable in around 90 days under ideal conditions) and sugarcane-bagasse tableware, which upcycles a sugar-industry by-product into biodegradable/compostable plates and bowls (compostable in as little as 60 days). The company serves both retail (online shop) and wholesale/commercial customers, including hospitality and food-service businesses, with"}, {"name": "Ecourage", "slug": "ecourage", "country": "Unresolved — seed data states Portugal; one independent secondary source states Stavanger, Norway. Not confirmed by a primary source in this pass.", "categories": "digital-tracking, packaging-as-a-service, refill, reusable-packaging", "priority": "★★★★ High", "summary": "Ecourage is a refill-technology company providing a B2B2C \"refill-as-a-service\" platform: smart, NFC-enabled reusable packaging and dispensing hardware that retailers and consumer brands can deploy to offer in-store or in-machine refills while capturing data on individual customer refill behaviour. Its named retail and brand partners/pilots include Colruyt, Albert Heijn, Lidl, Delhaize, ecostore and Cargill, and it has piloted deployments in Europe, Asia (including AEON stores in Tokyo from October 2025, per industry press) and, via the"}, {"name": "Ecover", "slug": "ecover", "country": "Belgium — Malle", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★★ High", "summary": "Ecover is a Belgian manufacturer of ecological cleaning products, founded in 1979 by Frans Bogaerts in response to concerns about phosphates in conventional detergents damaging aquatic ecosystems. Headquartered in Malle, Belgium, where it built what it described as the world's first \"ecological factory\" (with a green roof) in 1992, Ecover has long been recognised for sustainability leadership, including a 1993 UNEP Global 500 Roll of Honour listing and a 2008 Time magazine \"Hero of the"}, {"name": "EcoVibe", "slug": "ecovibe", "country": "United Kingdom — London (Covent Garden)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "EcoVibe is a UK-based e-commerce retailer, founded in 2018 and headquartered in London, selling plastic-free and refillable cleaning and personal-care products as an alternative to conventional single-use plastic packaging. Its core offering is concentrated cleaning-product sachets — made from plant-derived, sustainably sourced ingredients and manufactured in the UK — that dissolve in water and are used to refill reusable spray bottles, reducing packaging weight and the carbon footprint of transporting mostly-water cleaning products. The company"}, {"name": "Ecoworks", "slug": "ecoworks", "country": "Singapore", "categories": "consumer-education, digital-tracking, refill, waste-reduction", "priority": "★★★★ High", "summary": "Ecoworks is a Singaporean company operating a growing network of automated household-product refill kiosks (\"Ecofill Refill Stations\") placed in everyday community locations such as HDB (public housing) void decks, community centres and university campuses. Founder Sean Lam, a repeat entrepreneur, started the company after learning that Singapore is one of the world's largest per-capita producers of single-use plastic waste, seeking a venture with deeper long-term environmental impact. The company rolled out its first refill station"}, {"name": "Effecorta", "slug": "effecorta", "country": "Italy (origin: Capannori, Province of Lucca, Tuscany; Milan store: Via Franco Faccio 11, Milan)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Effecorta is an Italian bulk-grocery retail concept that opened its first shop in Capannori (Lucca) in August 2009, offering over 100 products — wine, oil, flours, legumes, detergents and more — sold loose (\"alla spina\") in customer-supplied or reusable containers, sourced through short supply chains. The concept was recognised by the Province of Lucca as an innovative start-up and by the Tuscany Region in 2010 as an \"eco-efficient\" enterprise. A related but separately incorporated shop,"}, {"name": "EKOH-Store", "slug": "ekoh-store", "country": "New Zealand (Auckland)", "categories": "consumer-education, refill, reusable-packaging", "priority": "★★ Low", "summary": "EKOH-Store (Ekohstore NZ Limited) is a small, privately owned New Zealand company, incorporated in Auckland in November 2020, selling reusable and refillable household, personal-care and pet-care products online. Its range includes refillable glass spray/pump bottles, Swedish dishcloths, reusable produce bags, beeswax-style wraps, and natural/vegan personal-care items under its \"HealthyClean\" and EKOH lines. The company markets itself as \"100% NZ owned and operated\" and a family business, ships internationally (site references NZ, Australia, Canada, US and"}, {"name": "Ekolo", "slug": "ekolo", "country": "Finland (Jyväskylä)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "Ekolo is a Finnish company based in Jyväskylä, founded in 2004 with the stated purpose of promoting sustainable consumption and production. It operates both a physical store (Kauppakatu 18, Jyväskylä) and an online shop selling household, food, beauty and lifestyle products aligned with zero-waste and sustainability principles, including refillable and bulk options. The seed-provided directory URL (mediterrolio.com listing) was not the company's own site; the verified official domain is ekolo.fi."}, {"name": "Ekoplaza", "slug": "ekoplaza", "country": "Netherlands (Veghel); also operates in Belgium", "categories": "consumer-education, material-recovery, waste-reduction", "priority": "★★★ Medium", "summary": "Ekoplaza is the largest organic supermarket chain in the Benelux region, tracing its roots to a single Amsterdam organic shop opened by Gerard Does in 1980; the modern Ekoplaza supermarket formula itself was developed by Jos Kamphuys, whose first trial store opened in Alkmaar in April 2005. Following Kamphuys' death in 2011, parent company Udea B.V. became full owner. By 2018 the chain operated around 74 stores in the Netherlands, and it has since expanded"}, {"name": "Ekopullo", "slug": "ekopullo", "country": "Finland", "categories": "deposit-return, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "Ekopulloyhdistys ry (branded Ekopullo) is a Finnish non-profit association established in 2004 that manages the deposit-based return system for refillable glass bottles and associated transport/crate units used by Finnish beverage producers. While closely affiliated with Suomen Palautuspakkaus Oy (Palpa) — from whom it sources staff and operating premises — Ekopullo is governed as a distinct, separately constituted membership association funded by entrance and membership fees from participating beverage companies. Its system is officially approved and"}, {"name": "Elamise Kergus", "slug": "elamise-kergus", "country": "Estonia (Viimsi, Harju County)", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "Elamise Kergus OÜ is a small Estonian company, registered in February 2018 and based in Viimsi (near Tallinn), that sells household, cosmetics and lifestyle products described as environmentally conscious, recyclable and durable. It operates primarily as an e-shop, supplemented by a small representative store in Viimsi, and ships customer orders in cardboard/paper packaging (avoiding plastic), including reused packaging materials where possible. The company has stated ambitions to expand sales into Latvia, Finland and other markets"}, {"name": "Elate Cosmetics", "slug": "elate-cosmetics", "country": "Canada", "categories": "consumer-education, reusable-packaging, take-back", "priority": "★★★ Medium", "summary": "Elate Cosmetics is a Canadian vegan and cruelty-free cosmetics brand founded in 2014 by Melodie Reynolds, a 20-year beauty-industry veteran, with a stated mission to redefine \"low-waste\" beauty and reject shame-based marketing common in the cosmetics industry. The brand is built around bamboo-based, refillable makeup compacts and packaging designed to be reusable, recyclable or plantable, with a free take-back program allowing customers to return empty packaging to the company for refilling or proper recycling rather"}, {"name": "Embol", "slug": "embol", "country": "Bolivia (plants in La Paz, Cochabamba, Santa Cruz and Oruro)", "categories": "deposit-return, reusable-packaging, reverse-logistics", "priority": "★★★ Medium", "summary": "Embol (Embotelladoras Bolivianas Unidas S.A.) is Bolivia's exclusive Coca-Cola bottler, formed in 1995 through a merger of previously separate Bolivian bottling operations with the involvement of Chilean bottling entrepreneur Hernán Vicuña Reyes. It operates four bottling plants (La Paz, Cochabamba, Santa Cruz, Oruro) and states its distribution network covers roughly 75% of Bolivian territory, reaching about 95% of the national population. A core part of its operations is a returnable-bottle system for both glass and"}, {"name": "Emmaus France", "slug": "emmaus-france", "country": "France (Paris)", "categories": "consumer-education, reverse-logistics, take-back, waste-reduction", "priority": "★★★★★ Essential", "summary": "Emmaüs France is the French national federation of the Emmaus movement, founded by Abbé Pierre in 1949 when he began housing and working alongside destitute individuals (\"compagnons\") at Neuilly-Plaisance, funding the community by collecting, repairing and reselling discarded goods (\"chiffonniers\"). The umbrella association Emmaüs France was formally established in 1985 (loi de 1901) to federate France's Emmaus-affiliated groups. In 2023 the movement encompassed dozens of community and insertion structures nationwide, involving more than 38,000 people"}, {"name": "Envie", "slug": "envie", "country": "France (Strasbourg origin; national federation network)", "categories": "material-recovery, repair, reverse-logistics, take-back, waste-reduction", "priority": "★★★★ High", "summary": "Réseau Envie is a French federation of social-insertion enterprises founded in Strasbourg in 1984, specialising in the collection, repair, refurbishment and resale of used household appliances (and, more recently, medical equipment), alongside collection, sorting and recycling of waste electrical and electronic equipment (WEEE). As of 2024 the network comprised 53 insertion enterprises across more than 100 sites in France, all holding ESUS (\"Entreprise Solidaire d'Utilité Sociale\") accreditation, combining environmental and social-inclusion missions by employing people"}, {"name": "Enviu", "slug": "enviu", "country": "Netherlands (Rotterdam)", "categories": "consumer-education, industrial-reuse", "priority": "★★★ Medium", "summary": "Enviu is a Rotterdam-headquartered non-profit venture-building studio founded in 2004. Rather than operating a single product or service, Enviu designs, launches and scales new companies (\"ventures\") intended to solve environmental and social problems through commercially viable, circular business models. It operates across food, textiles, plastics/zero-waste, and mobility domains, with additional offices in Nairobi (Kenya), Bangalore (India) and Jakarta (Indonesia) supporting ventures in East Africa, South Asia and Southeast Asia. Enviu is the parent organisation behind"}, {"name": "Ernie's Zero Waste Shop", "slug": "ernies-zero-waste-shop", "country": "United Kingdom (Norwich, England)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Ernie's Zero Waste Shop is an independent refill and zero-waste retailer based in Norwich, England, founded by Graham Rutherford in 2019 (originally trading as \"Ethical Ernie's\"). Now located at 62 Castle Quarter, Norwich, the shop stocks over 900 plastic-free, plant-based, and cruelty-free products, including bulk dry food and liquid refills for cleaning and personal-care items. It describes itself as Norwich's dedicated zero-waste shop, positioning itself as a local, community-facing alternative to conventional packaged retail."}, {"name": "Estado Natural", "slug": "estado-natural", "country": "Mexico (Mexico City)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Estado Natural is a Mexican bulk-grocery retail chain that opened its first store in Roma Norte, Mexico City, in October 2017, selling nuts, grains, cereals, flours, superfoods, dried fruit, spices, and personal-care/household-cleaning products entirely in bulk (\"100% a granel\"). The company has since expanded to multiple neighbourhoods within Mexico City (Condesa, Del Valle Centro, Polanco, Álvaro Obregón, and others) as well as locations in Puebla and Querétaro, positioning itself around affordable, healthy food and reduced"}, {"name": "ETEE", "slug": "etee", "country": "Canada (Ontario)", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "etee is a Canadian sustainable-products brand founded in Ontario in 2015 by Steve Reble, after an encounter with plastic pollution while kayaking on a local river prompted him to develop plastic-free alternatives to everyday household items. The brand's name and philosophy — \"Everything Touches Everything Else\" — reflect a \"from the earth and back to the earth\" design ethos. Its best-known product is a reusable, biodegradable beeswax-alternative food wrap used in place of plastic cling"}, {"name": "Ethique", "slug": "ethique", "country": "New Zealand (Christchurch); majority owner Bansk Group is US-based", "categories": "consumer-education, waste-reduction", "priority": "★★★ Medium", "summary": "Ethique is a New Zealand-founded personal care brand created by Brianne West in Christchurch in 2012 while she was a science undergraduate. The company makes concentrated solid bars — shampoo, conditioner, body wash, cleanser, deodorant and household bars — designed to replace liquid products sold in plastic bottles. Ethique is a certified B Corporation and Living Wage employer, and is majority-owned by US investment firm Bansk Group since 2020, though it retains its New Zealand"}, {"name": "Event Cup", "slug": "event-cup", "country": "France (Orvault, near Nantes) — NOT United Kingdom as seeded", "categories": "reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "Event Cup is an e-commerce brand offering customisable reusable plastic and cardboard cups (10–60cl), pitchers and cup holders for weddings, birthdays, sports events, festivals and corporate functions. It operates as part of Imprim' & Com', a French printing/customisation business based in Orvault, France, with production described as \"made and printed in Europe (France & Portugal).\" The site offers online cup design tools, no minimum order quantity, and references a B Corp certification and corporate social"}, {"name": "everdrop", "slug": "everdrop", "country": "Germany (Munich)", "categories": "refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "everdrop GmbH is a Munich-based start-up founded in 2019 by David Löw, Daniel Schmitt-Haverkamp and Christian Becker. It develops dissolvable cleaning and laundry tablets, dishwasher tabs, and laundry powder designed to be used with reusable spray bottles and containers, cutting the plastic and water/weight footprint of conventional liquid cleaning products. everdrop is a certified B Corporation and has been recognised (including by the Ellen MacArthur Foundation) as a circular-economy product example."}, {"name": "Evy Café", "slug": "evy-cafe", "country": "Switzerland (Yverdon-les-Bains, Canton of Vaud)", "categories": "Not publicly available", "priority": "★ Low relevance", "summary": "Evy Café is a small, independent café located at Rue de l'Hôpital 31B (also listed under Av. des Quatre Marronniers 28), 1400 Yverdon-les-Bains, Switzerland. Public listings (local.ch, Uber Eats) describe it as a \"bar à café / petite restauration\" serving coffee, waffles, milkshakes and ice cream. This research could not independently verify the seed dataset's classification of the business as focused on \"reusable products\" — no evidence of a reusable-cup deposit scheme, refill system, or"}, {"name": "Excess Materials Exchange", "slug": "excess-materials-exchange", "country": "Netherlands (Amsterdam)", "categories": "digital-tracking, industrial-reuse, material-recovery", "priority": "★★★★ High", "summary": "Excess Materials Exchange (EME) is an Amsterdam-based digital platform founded in 2017 by Maayke-Aimée Damen and Christian van Maaren. It matches companies' surplus materials and waste streams with other businesses seeking inputs, aiming to find the highest-value reuse option for each material rather than defaulting to recycling or disposal. After several years of piloting, EME's digital platform officially launched in June 2020. A central feature is the \"Resource Passport\" — a digital identity record for"}, {"name": "ExpandFibre", "slug": "expandfibre", "country": "Finland", "categories": "material-recovery", "priority": "★★ Low", "summary": "ExpandFibre was a large-scale Finnish research and development ecosystem launched in 2020 by Metsä Group and Fortum, with major public co-funding from Business Finland, to accelerate development of sustainable bioproducts from renewable pulp fibres, hemicellulose and lignin sourced from straw and northern wood. It was structured as a \"leading company\" (Veturi) programme comprising 35 publicly funded projects and 108 participating organisations — companies, universities, research institutes, associations and venture capital investors. The programme concluded in"}, {"name": "Ezaar Collective", "slug": "ezaar-collective", "country": "India (Assam) — NOT Pakistan as seeded", "categories": "material-recovery, waste-reduction", "priority": "★★ Low", "summary": "Ezaar Collective is a small social enterprise based in Assam, India (the brand explicitly states \"WE ARE PROUDLY INDIAN\"), founded by entrepreneur Barsha Sharma. It upcycles discarded fabric waste sourced from handloom manufacturers into lifestyle accessories — pouches, bags, wallets, home décor, stationery and other utility products — under a \"Waste to Wealth\"/\"Dream Stitch\" positioning. The company has gained some regional media attention, including a feature on Jio Hotstar, and describes empowering women artisans as"}, {"name": "Faerly", "slug": "faerly", "country": "Ireland — Kilcullen, Co. Kildare (registered office: 1033 Nicholastown, Kilcullen, Co. Kildare, R56 Y299)", "categories": "consumer-education, deposit-return, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Faerly is an Irish online retailer of sustainable-living products, founded by married couple James Byrne and Eoin Houlihan and launched in October 2020 from their home in Kilcullen, Co. Kildare. The legal entity trading as Faerly, Simply Good Fair Limited, was incorporated on 27 May 2020. The business curates several hundred products — bamboo and metal personal-care items, natural cleaning and body-care concentrates, and refillable containers — sourced from small Irish makers and eco-conscious international"}, {"name": "Fairphone", "slug": "fairphone", "country": "Netherlands (Amsterdam)", "categories": "consumer-education, repair, take-back", "priority": "★★★★★ Essential", "summary": "Fairphone is an Amsterdam-based social enterprise founded in January 2013 by Bas van Abel, Tessa Wernink and Miquel Ballester, following two and a half years operating as an awareness campaign about conflict minerals and e-waste. It designs and sells modular smartphones engineered for easy repair, upgrade and disassembly, with a focus on longer device lifespans, ethically-sourced materials (including conflict-free minerals) and fair labour conditions in its supply chain. Fairphone became a certified B Corporation in"}, {"name": "Faith In Nature", "slug": "faith-in-nature", "country": "United Kingdom (Scotland-registered company; brand founded in West Yorkshire)", "categories": "consumer-education, refill, reusable-packaging", "priority": "★★★★ High", "summary": "Faith In Nature is a long-established UK natural personal-care brand, tracing its origin to 1974, making shampoo, conditioner, body wash and household products from naturally-derived, cruelty-free ingredients. Its registered company (Faith In Nature Limited, Companies House number SC068493) was incorporated in 1979. The brand is best known in the reuse/circular-economy space for two things: its \"refill reuse repeat\" aluminium bottle refill system, and a landmark 2022 governance move in which it amended its constitution to"}, {"name": "Fill it Forward", "slug": "fill-it-forward", "country": "Canada (Guelph, Ontario)", "categories": "consumer-education, digital-tracking, reusable-packaging", "priority": "★★★★ High", "summary": "Fill it Forward is a Guelph, Ontario-based company founded by CEO Matt Wittek that created what it describes as the world's first scannable reusable products. Customers or organisations attach QR-coded tags/stickers to reusable water bottles, cups and bags; scanning the tag on each reuse logs the action in an app, unlocks a charitable donation, and lets individuals and organisations track cumulative environmental impact (single-use items avoided). The company is a certified B Corporation and 1%"}, {"name": "Fill Refill Co", "slug": "fill-refill-co", "country": "United Kingdom (Finedon, Northamptonshire)", "categories": "deposit-return, refill, reverse-logistics", "priority": "★★★★ High", "summary": "Fill Refill Co is a small, independent, family-run UK manufacturer based at its own factory in Finedon, Northamptonshire. It produces refillable household cleaning, laundry, hand/body and hair-care products, sold in closed-loop returnable glass bottles and bulk returnable containers under its \"Washtainer\" system. The company was incorporated in November 2018 (Companies House no. 11683937) and launched its closed-loop rinse-and-return model in 2020. It holds B Corp certification, is a 1% for the Planet member, and is"}, {"name": "Fill Up Buttercup", "slug": "fill-up-buttercup", "country": "United States (Costa Mesa, California)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "Fill Up Buttercup is a non-toxic, zero-waste refill shop founded in August 2020 in Costa Mesa, California, by Jamie Lake and business partner Kristina Guccione. It sells bulk household and personal-care products (shampoo, conditioner, body wash, all-purpose cleaner, laundry detergent and more) that customers can refill using their own containers, alongside a curated online store of plastic-free, non-toxic branded products. The company grew from a single Costa Mesa location to a second store (Huntington Beach,"}, {"name": "Fillaree Refill", "slug": "fillaree-refill", "country": "United States (Durham, North Carolina)", "categories": "consumer-education, refill, reusable-packaging, reverse-logistics, waste-reduction", "priority": "★★★ Medium", "summary": "Fillaree is a Durham, North Carolina-based maker of natural, vegan soaps and household cleaning products, founded in 2014 by Alyssa Cherry. It began as a home-kitchen operation making nontoxic refillable soap for the founder's family and grew into a small manufacturing operation with a retail storefront (opened around three years after founding). Fillaree positions itself as an early mover in circular-economy personal care, built around a \"wash, sanitize, refill\" reuse loop for its liquid soap"}, {"name": "FillGood", "slug": "fillgood", "country": "New Zealand (Wellington — Hnry Stadium / 2 Forresters Lane)", "categories": "consumer-education, digital-tracking, reusable-packaging, reverse-logistics, sharing, waste-reduction", "priority": "★★★★ High", "summary": "FillGood is a Wellington-based reusable-serviceware system for events, venues, and hospitality businesses, developed by a cross-sector working group and operated as an initiative of Sustainability Trust, a Wellington charitable trust. Officially launched in 2024 after several years of feasibility work, FillGood supplies reusable cups, plates, trays, and bowls to festivals, stadiums, and other events, and manages their delivery, collection, commercial washing, tracking, and reporting. Its stated mission is to make reusable serviceware \"the new standard\""}, {"name": "Finline Furniture", "slug": "finline-furniture", "country": "Ireland (Emo, Co. Laois)", "categories": "material-recovery, repair, reverse-logistics, take-back, waste-reduction", "priority": "★★★ Medium", "summary": "Finline Furniture is a family-run Irish sofa, chair, and footstool manufacturer founded in 1979 by Kieran and Bridget Finane in Emo, County Laois, to fill a gap in the market for stylish, high-quality, Irish-made upholstered furniture. The company sells through its own showrooms in Dublin, Cork, and Galway as well as its headquarters. In addition to new furniture manufacturing, Finline runs \"Revive,\" a take-back and reupholstery scheme that recovers worn Finline sofas from customers, restores"}, {"name": "First Green Store", "slug": "first-green-store", "country": "Singapore", "categories": "consumer-education, material-recovery", "priority": "★★ Low", "summary": "The First Green Store is a Singapore-based, women-led retailer specialising in sustainable, ethical, and eco-friendly promotional products for socially responsible companies. Its best-known product line is the Sprout Pencil — described as the world's first plantable pencil, replacing the standard eraser with a seed capsule — alongside recycled-newspaper pencils and other eco stationery. The company partners with schools to promote conscious-consumption awareness alongside its retail business."}, {"name": "Flo Hygiene", "slug": "flo-hygiene", "country": "Nepal", "categories": "refill, waste-reduction", "priority": "★★ Low", "summary": "Flo Hygiene is a Nepalese household-cleaning products brand offering dishwashing liquid, glass cleaner, and floor cleaner, sold under the tagline \"Best Dishwash Glass & Floor Cleaner Product Nepal.\" Search-engine indexing of the company's own site describes Flo Hygiene as \"a quality product of TNT Hygiene,\" a Nepalese manufacturer reported to have been established in Nepali calendar year 2077 B.S. (approximately 2020–2021 CE) with a stated mission to promote Nepal-made products and support the local economy."}, {"name": "FloWater", "slug": "flowater", "country": "United States", "categories": "material-recovery, refill, waste-reduction", "priority": "★★★ Medium", "summary": "FloWater is a US company operating purified-water refill stations built around mostly-stainless-steel construction, deployed in offices, gyms, schools, and other business/institutional settings (including at least one confirmed US school district, Oakland Unified School District). Its stations use a \"7x Advanced Purification\" filtration system claimed to remove up to 99.9% of contaminants including microplastics, lead, PFAS, chlorine, pharmaceuticals, and heavy metals, holding seven gallons of purified water on tap at all times with automatic refill and"}, {"name": "For Earth's Sake", "slug": "for-earths-sake", "country": "United Kingdom — Shamley Green, Guildford, Surrey, England (GU5 0SX). Note: seed data listed country as India, but this is incorrect — the organisation is UK-based; its website is registered on the .co.uk domain and its registered office is in Surrey, England", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "For Earth's Sake CIC is a not-for-profit, community-interest refill shop based in Shamley Green, near Guildford, Surrey, England. Incorporated in November 2018 and opened to the public in April 2019 by founder Vanessa Ford-Robbins, the business relocated in April 2024 to a barn premises powered entirely by an on-site solar array. It offers plastic-free, refillable groceries and household goods alongside a personal shopping/delivery service, positioning itself as a community-focused alternative to conventional packaged retail with"}, {"name": "Forest Garden Soap & Sundry", "slug": "forest-garden-soap", "country": "Canada — Shuswap region, British Columbia", "categories": "Not publicly available", "priority": "★ Low relevance", "summary": "Forest Garden Soap & Sundry is a family-owned soap maker operating from an off-grid homestead in the Shuswap region of British Columbia, Canada. Its sea-salt-based soaps use wildcrafted herbs, ingredients grown on the family's own property, and honey/beeswax from their own bees. The company was started, per its own materials, out of a desire for a soap product completely free of artificial ingredients."}, {"name": "Foreword Coffee", "slug": "foreword-coffee", "country": "Singapore", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "Foreword Coffee is a Singapore-based social enterprise café chain founded in 2017 by Lim Wei Jie and Nadi Chan. Its stated mission is to \"mainstream disability and normalise inclusion\" — Foreword was Singapore's first café specifically designed to train and employ persons with disabilities (including autism, intellectual disability, physical disability, deafness and mental-health conditions) as baristas. Alongside its social mission, the company sources green coffee directly from smallholder farms and cooperatives in Asia (reported sourcing"}, {"name": "Friendlier", "slug": "friendlier", "country": "Canada — Guelph, Ontario", "categories": "deposit-return, digital-tracking, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "Friendlier is a Guelph, Ontario deposit-return reusable food and beverage packaging system founded by Kayli Dale and Jacqueline Hutchings, both University of Waterloo chemical engineering graduates. Customers pay a $0.50 deposit when receiving a meal in a Friendlier container, then scan a QR code (via app or online) after returning it to a collection bin to reclaim the deposit via e-transfer 1-2 weeks later. The company has grown to 200+ partner businesses across Ontario, including"}, {"name": "fritz-kola", "slug": "fritz-kola", "country": "Germany — Hamburg", "categories": "deposit-return, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "fritz-kola is a German soft drink brand founded in a Hamburg student dorm in 2002 (some sources say 2003), built from its outset around returnable glass bottle packaging at a time when the beverage industry was trending toward single-use containers. The company distributes cola and other soft drinks in glass bottles designed to be returned and refilled up to 20 times before recycling, working with regional bottlers and suppliers to keep the returnable-glass logistics loop"}, {"name": "Fundación Basura", "slug": "fundacion-basura", "country": "Chile (Santiago)", "categories": "consumer-education, material-recovery, waste-reduction", "priority": "★★★ Medium", "summary": "Fundación Basura is a Chilean non-profit founded in 2015 by Macarena Guajardo after she observed the contrast between German and Chilean waste management practices while studying sustainable architecture, and after witnessing severe waste problems in Haiti. Its mission is to protect planetary health through responsible waste management, working toward a \"Zero Waste Circular Economy\" where materials are re-inserted into new cycles via ecodesign, reuse, recycling, composting and biodigestion. The foundation operates through three pillars: environmental"}, {"name": "Fundación Lenga", "slug": "fundacion-lenga", "country": "Chile (active in the Magallanes region, expanded to Araucanía region; precise registered HQ city Not publicly available)", "categories": "consumer-education, digital-tracking, waste-reduction", "priority": "★★★ Medium", "summary": "Fundación Lenga is a Chilean non-profit that has worked since 2019 to promote \"Zero Waste\" practices in the tourism sector across southern Chile, beginning in the Magallanes region (Patagonia) and later expanding north into the Araucanía region. Its name is inspired by the native lenga tree (Nothofagus pumilio) of Chile's austral forests, whose saplings grow in clusters, supporting one another — a metaphor for the foundation's collaborative approach with tourism businesses, residents and visitors. The"}, {"name": "Furugishion", "slug": "furugishion", "country": "Japan (exact HQ city Not publicly available)", "categories": "consumer-education", "priority": "★ Low relevance", "summary": "Furugishion (ふるぎっしょん, \"furugi\" = secondhand/used clothing) was a Japanese-language content and media website covering secondhand/vintage fashion, retro style guides, and rankings of clothing resale and buyback (\"kaitori\") services. Search-engine indexing shows articles such as \"80s Retro Fashion Styles,\" \"Recommended Ranking of Used-Clothing Home-Pickup Buyback Services,\" and shopping guides pointing readers to third-party resale shops and apps. Based on available evidence, Furugishion functioned as an affiliate/editorial media property that directed readers to other companies' marketplaces and"}, {"name": "Fussy", "slug": "fussy", "country": "United Kingdom", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Fussy is a UK company that makes a refillable natural deodorant designed to eliminate single-use plastic from the bathroom. Founded in 2020 and launched via a record-breaking Kickstarter campaign, the brand sells a reusable outer case paired with compostable cardboard-and-paper refill cartridges. Fussy has since expanded into refillable body wash and hand wash. It is a certified B Corporation and ships direct-to-consumer to more than 30 countries, positioning itself as a plastic-free, \"clean\" alternative to"}, {"name": "Fuwa3e", "slug": "fuwa3e", "country": "Vietnam (Thanh Hoa)", "categories": "consumer-education, industrial-reuse, refill, waste-reduction", "priority": "★★★★ High", "summary": "Fuwa3e (FUWA Biotech Co., Ltd) is a Vietnamese company that ferments discarded pineapple peels into \"eco-enzyme,\" a plant-based cleaning agent used across a range of household and industrial cleaning products. Headquartered in Thanh Hoa, the company was co-founded by Do Xuan Tien, Le Duy Hoang, and CEO Bui Thi Bich Ngoc, growing out of eco-enzyme research that began around 2016 before formal incorporation in 2019. Since 2020, Fuwa3e has pioneered a network of refill stations"}, {"name": "GAIA Bags", "slug": "gaia-bags", "country": "Pakistan (Islamabad — King's Arcade, 20-A, F-7 Markaz, Islamabad, ICT 46000)", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "GAIA International (Private) Limited, trading as GAIA Bags, is a Pakistani company founded in 2017 and headquartered in Islamabad. It manufactures reusable, recyclable bags made from woven polypropylene yarn, positioned as a sturdier, longer-lasting alternative to single-use plastic shopping bags. The company frames its offering around the waste hierarchy's \"3 Rs,\" arguing its bags reduce waste through durability, are reusable across many shopping trips, and are recyclable at end of life. GAIA operates primarily as"}, {"name": "Gcwalisa", "slug": "gcwalisa", "country": "South Africa (Alexandra township, Johannesburg — first outlet)", "categories": "consumer-education, deposit-return, refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Gcwalisa (isiZulu for \"fill up\" or \"refill\") is a South African bulk-food and household-essentials retail model founded by entrepreneur Miles Kubheka, who also founded the Wakanda Food Accelerator in 2020. Conceived during COVID-19 lockdowns to address rising food insecurity in low-income communities, Gcwalisa operates a \"weigh-and-pay\" model from shipping-container-based stores, letting customers buy staples like maize meal, sugar, cooking oil and detergent in the exact quantities they can afford, cutting packaging costs out of the"}, {"name": "Genomma Lab", "slug": "genomma-lab", "country": "Mexico (Mexico City)", "categories": "consumer-education, material-recovery, take-back, waste-reduction", "priority": "★★ Low", "summary": "Genomma Lab Internacional, S.A.B. de C.V. is a publicly listed Mexican pharmaceutical, personal-care and consumer-health company incorporated in 1996, headquartered in Mexico City and trading on the Bolsa Mexicana de Valores under ticker LABB. It develops and markets a broad portfolio of over-the-counter health, dermatological, hair-care and personal-care brands (including Tío Nacho) across Mexico and other Latin American markets. Since publishing its \"Sustainability Strategy 2025,\" Genomma Lab has run a multi-year programme to incorporate recycled"}, {"name": "Get Joni", "slug": "get-joni", "country": "Canada (Victoria, British Columbia)", "categories": "consumer-education, packaging-as-a-service", "priority": "★★ Low", "summary": "joni is a Canadian period-care company founded in March 2020 by co-founders Linda Biggs and Jayesh Vekariya, headquartered in Victoria, British Columbia. It is a B Corp-certified company selling organic, plant-based, biodegradable and compostable pads, tampons and period underwear, aiming to eliminate conventional plastic from menstrual products (which can otherwise take over 300 years to break down). Beyond direct-to-consumer sales, joni supplies over 450 Canadian retailers and offers \"Model V,\" a free-vend period-care dispenser for"}, {"name": "Gjenge Makers", "slug": "gjenge-makers", "country": "Kenya (Nairobi)", "categories": "industrial-reuse, material-recovery, waste-reduction", "priority": "★★★★ High", "summary": "Gjenge Makers Ltd is a Nairobi-based Kenyan company founded by mechanical engineer and entrepreneur Nzambi Matee, who quit her job as a data analyst in 2017 after being struck by the volume of plastic waste littering Nairobi's streets. Working initially from a small lab in her mother's backyard, she developed a process — and eventually a self-built production machine (completed 2019) — for combining recycled plastic waste with sand to manufacture paving bricks (\"pavers\") that"}, {"name": "Glassia", "slug": "glassia", "country": "Vietnam (Da Nang, with operations extending to Hoi An)", "categories": "refill, reusable-packaging, reverse-logistics, take-back", "priority": "★★★★★ Essential", "summary": "Glassia is a Vietnamese social enterprise that began operations in Da Nang in March 2021, incubated by Evergreen Labs. It supplies purified drinking water in 100% reusable, refillable glass bottles, replacing single-use PET water bottles for hospitality and office customers. Its model closes the loop through a \"re-collection – sterilization – refill\" cycle: Glassia delivers full bottles, collects empties from the same customers on the next delivery run, and returns them to its decentralized bottling"}, {"name": "Go Zero Waste", "slug": "go-zero-waste", "country": "Spain (Barcelona) — operates internationally, including Argentina, Chile and 7 other countries", "categories": "consumer-education, digital-tracking, repair", "priority": "★★★ Medium", "summary": "Go Zero Waste is a mobile app founded in Barcelona, Spain, by Martí Morató and Magda Cebrián, and published in May 2020 in partnership with Sparsity Technologies, a spin-off of the Data Management Group at the Universitat Politècnica de Catalunya (UPC). The app provides an interactive, crowdsourced map that lets users locate nearby shops, markets and services offering plastic-free or zero-waste alternatives — including bulk/refill stores, package-free markets, thrift and secondhand shops, and repair, reuse"}, {"name": "GoBEBA", "slug": "gobeba", "country": "Kenya (Nairobi)", "categories": "digital-tracking, refill, reverse-logistics", "priority": "★★★★ High", "summary": "GoBEBA is a Nairobi-based Kenyan startup founded in 2019 by Peter Ndiang'ui (a former OLX general manager) and Lesley Mbogo (a former Amazon head of product). It is an e-commerce platform for \"unpiped\" bulky household utilities — principally drinking water and cooking gas (LPG) — that are conventionally distributed via bulky, refillable containers requiring two-way delivery trips. GoBEBA built a distributed network of AI-enabled micro-fulfillment hubs across Nairobi to shorten this loop, enabling customers to"}, {"name": "Goodfill", "slug": "goodfill", "country": "South Africa (Cape Town)", "categories": "refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Goodfill is a Cape Town-based eco-friendly cleaning products startup that makes biodegradable, plant-based concentrated cleaning tablets designed to be dissolved in tap water inside a reusable spray bottle. The model avoids the environmental cost of manufacturing and transporting single-use plastic bottles filled mostly with water. Products are locally made in Cape Town and sold direct via the company's own website as well as through South African natural/organic retailer Faithful to Nature. No independently verifiable founding"}, {"name": "GoUnpackaged", "slug": "gounpackaged", "country": "United Kingdom (London)", "categories": "consumer-education, refill, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "GoUnpackaged is a UK-based reuse-and-refill consultancy tracing its roots to Unpackaged, a zero-waste shop founded by Catherine Conway in 2006 — widely credited as the world's first modern zero-waste retail concept, originally a market stall before becoming a bricks-and-mortar shop in London stocking around 700 products, roughly 80% of them refillable. Following a 2015 supermarket trial with Planet Organic, the business transitioned from retail into consultancy, rebranding over time (via \"Just Unpackaged\") to GoUnpackaged. It"}, {"name": "Gra de Gràcia", "slug": "gra-de-gracia", "country": "Spain (Barcelona)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Gra de Gràcia is a zero-waste bulk grocer founded in 2012 in Barcelona's Gràcia district, among the earlier \"botigues a granel\" (bulk shops) in the city. Co-founded by Sara Ingelmo and Jordi Escoriza, it began as a single store on Carrer Puigmartí and expanded to three Barcelona locations (Puigmartí, Bonanova, and Cigne) as the concept proved popular. The shop sells roughly 600 organic, natural, and locally-sourced dry and prepared goods — rice, pasta, legumes, spices,"}, {"name": "Gracz", "slug": "gracz", "country": "Thailand (Bangkok, HQ; manufacturing in Chai Nat Province)", "categories": "consumer-education, material-recovery, waste-reduction", "priority": "★★ Low", "summary": "Gracz is the consumer-facing brand of BPE (Biodegradable Packaging for Environment Co., Ltd.), a Thai manufacturer founded in 2005 that produces compostable tableware — plates, bowls, cups, clamshells, and cutlery — made from bagasse (sugarcane pulp fibre) and bamboo fibre blends. Originally sold under the \"Biochanaoy\" name, the brand was relaunched as \"Gracz\" in 2012. Manufacturing takes place in Chai Nat Province, Thailand, with products distributed regionally, including through the gracz.my e-commerce site serving Malaysia."}, {"name": "Gram Malmö", "slug": "gram-malmo", "country": "Sweden (Malmö)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Gram Malmö, founded in 2016 by Rowan Drury, was Sweden's first package-free grocery store. Located at Sankt Knuts Torg in Malmö, it sells over 300 items — food staples, produce, soaps, detergents, and household goods — entirely without pre-set packaging. Customers bring their own jars, boxes, or bags (or use provided paper bags) and buy loose goods by weight, paying only for what they need. The shop emphasises local and organic sourcing from Swedish producers"}, {"name": "Great Wrap", "slug": "great-wrap", "country": "Australia (Tullamarine, Victoria)", "categories": "material-recovery, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Great Wrap was an Australian manufacturer of compostable cling wrap, catering wrap, and pallet (stretch) wrap made using food waste and potato-starch-derived bioplastics, founded in 2019 by married couple Jordy and Julia Kay (an architect and a former winemaker) after meeting in Melbourne. The company aimed to replace fossil-fuel-based plastic film with a compostable alternative and raised substantial venture and non-dilutive funding — including a reported AU$24 million Series A round and AU$13 million in"}, {"name": "Green Bubble", "slug": "green-bubble", "country": "Ireland (Dublin)", "categories": "material-recovery, reusable-packaging, reverse-logistics, waste-reduction", "priority": "★★★ Medium", "summary": "Green Bubble is a Dublin-based enterprise founded by Peter Gregory that gives previously-used packaging materials — bubble wrap, foam roll, hexacomb cardboard board, and acetate sheet — a second life rather than allowing them to be incinerated or landfilled. The company collects discarded bubble wrap from furniture warehouses and relocation companies in Dublin, cleans and repackages it (removing tape, rolling it into resalable lengths), and sells it at a discount to households and businesses via"}, {"name": "Green Come True", "slug": "green-come-true", "country": "United States (Lawrence, Kansas, with delivery into Kansas City/Overland Park)", "categories": "consumer-education, refill, reusable-packaging, reverse-logistics", "priority": "★★ Low", "summary": "Green Come True is a small, family-run zero-waste soap and household-product refill business based in Lawrence, Kansas, described in local coverage as Lawrence's original zero-waste soap refill store. It makes its own locally-crafted household cleaning and personal-care soaps, sold plastic-free through a physical storefront, seasonal farmers-market stalls (Lawrence and Overland Park), online ordering, and a \"milkman-style\" free home-delivery route serving Lawrence and the greater Kansas City area. The business also frames itself around broader \"climate"}, {"name": "Green Joy", "slug": "green-joy", "country": "Vietnam — Long An, Mekong Delta (registered office: Ho Chi Minh City)", "categories": "consumer-education, material-recovery, waste-reduction", "priority": "★★ Low", "summary": "Green Joy is a Vietnamese company that manufactures compostable drinking straws and food-service utensils from grey sedge (Lepironia) grass and other natural materials native to the Mekong Delta, alongside handicrafts from bamboo, wood, and palm leaf. Founded by CEO Vo Quoc Thao Nguyen, it positions itself as a plastic-straw replacement for the hospitality industry and consumer market. The company sources raw material from smallholder farmers in Long An province and exports the majority of its"}, {"name": "Green Kulture", "slug": "green-kulture", "country": "Singapore", "categories": "consumer-education, material-recovery, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Green Kulture is a Singapore-developed and -manufactured natural household cleaning brand built around proprietary \"Multi-Enzyme Technology\" derived from fruit and vegetable enzymes rather than harsh synthetic chemicals. According to the company, the brand was created by a founder (identified publicly only as \"Roy\") motivated by concerns over the chemical content of household products after becoming a father. Its core sustainability practice is sourcing unsold, disposal-bound fruit and vegetables from wholesalers as feedstock for its enzyme"}, {"name": "Green Lady Vietnam", "slug": "green-lady-vietnam", "country": "Vietnam", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Green Lady Vietnam is a social enterprise established in 2017 by Bui Thi Minh Ngoc to produce reusable cloth menstrual pads designed specifically for Vietnamese women, addressing both plastic waste from disposable sanitary products and access to affordable, comfortable menstrual care. Ngoc developed the product after struggling to source suitable fabric — naturally made, absorbent, washable, and quick-drying — and built the venture around both product sales and educational courses on ecological living and reproductive"}, {"name": "Green Pear Eco", "slug": "green-pear-eco", "country": "United Kingdom (Clare, near the Essex/Suffolk/Cambridgeshire borders)", "categories": "consumer-education, refill, reusable-packaging, reverse-logistics", "priority": "★★★ Medium", "summary": "Green Pear Eco is a UK plastic-free retail business founded in 2019 by husband-and-wife team Dan and Gab, who were inspired toward eco-conscious living after a career-break backpacking trip. The couple launched a mobile bulk-refill delivery van in 2020 — funded, according to press coverage, by redirecting their wedding fund during the COVID-19 pandemic — to deliver plastic-free household and personal-care refills across the Essex/Suffolk/Cambridgeshire border area. The business has since grown to include a"}, {"name": "Green Revolucia", "slug": "green-revolucia", "country": "Bulgaria", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Green Revolucia was founded in 2017 by Vera Markova as Bulgaria's first zero-waste shop, with a mission to make a zero-waste lifestyle affordable and accessible. It has since evolved into an online retailer focused substantially on sustainable menstrual health products — menstrual cups, discs, and swimwear/underwear, organic cotton pads — alongside natural cosmetics, children's reusable items (organic cotton/hemp underwear), and educational materials on menstrual health and sustainability. The company received EU regional development funding in"}, {"name": "Green Upshot", "slug": "green-upshot", "country": "Pakistan (Lahore)", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Green Upshot is a Lahore-based e-commerce startup founded in 2023, started, per its own account, \"in a small garage\" by an environmentalist founder after witnessing plastic pollution in local rivers and trees. The company sells eco-friendly, reusable lifestyle products — including bamboo toothbrushes and hairbrushes, reusable bottles and travel accessories (straws, cutlery, tumblers), and sustainable corporate gifting sets — shipping nationwide across Pakistan from its Lahore head office. It has grown into what it describes"}, {"name": "GreenChar", "slug": "greenchar", "country": "Kenya", "categories": "material-recovery, waste-reduction", "priority": "★★ Low", "summary": "GreenChar is a Kenyan social enterprise founded in December 2013 by Tom Osborn, who was 17–18 years old at the time and living in a rural area affected by household air pollution from wood-fuel cooking (his mother was diagnosed with a wood-smoke-related respiratory infection). GreenChar produces smokeless, high-energy fuel briquettes — sold under the brand \"MakaaPoa\" for household jikos (cookstoves) and \"Long Burn\" for institutional/industrial use — made by compressing agricultural waste such as sugarcane"}, {"name": "Greenpeace Philippines", "slug": "greenpeace-philippines", "country": "Philippines (Metro Manila)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★★★ Essential", "summary": "Greenpeace Philippines is the Philippine national office of the international environmental NGO Greenpeace, formally established in Metro Manila in March 2000 as part of Greenpeace Southeast Asia (alongside Thailand and Indonesia offices). Within its plastic-free-future campaign work, Greenpeace Philippines runs \"Kuha sa Tingi\" (\"get it in small portions\"), a reuse-and-refill initiative launched in November 2022 in partnership with the San Juan City local government and Impact Hub Manila. The project reintroduces the traditional Filipino \"tingi\""}, {"name": "GRIN", "slug": "grin", "country": "Norway (Gaustadalléen 21, 0349 Oslo)", "categories": "deposit-return, digital-tracking, reusable-packaging, reverse-logistics, take-back", "priority": "★★★★ High", "summary": "GRIN is a Norwegian circular-economy technology company founded in 2018 in Oslo. It designs and manufactures smart collection machines — branded Revore™ — that use image recognition and machine learning to identify and validate returned reusable items such as food boxes and takeaway cups, similar to a reverse vending machine but generalized to many packaging types. GRIN positions itself as a hardware-and-software infrastructure provider for reuse operators, brands, and foodservice chains that want to run"}, {"name": "Grove Collaborative", "slug": "grove-collaborative", "country": "United States (San Francisco, California; additional office in Portland, Maine)", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Grove Collaborative was founded in 2012 in San Francisco by Stuart Landesberg, Chris Clark and Jordan Savage as ePantry, an online subscription retailer for household staples, rebranding as Grove in 2016. It is a Certified B Corporation and Delaware public benefit corporation that sells natural personal-care, cleaning and household products via a direct-to-consumer subscription e-commerce model. The company went public via a SPAC merger with a Virgin Group-backed acquisition vehicle, completing its NYSE listing (ticker"}, {"name": "Grums Aarhus", "slug": "grums-aarhus", "country": "Denmark (Mejlgade 49, 8000 Aarhus C)", "categories": "consumer-education, material-recovery, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Grums Aarhus is a Danish skincare company, founded in Aarhus in 2018 by Rasmus and Simon, that collects used espresso coffee grounds from local cafés and upcycles them — extracting fibers, oils and a water-based extract in its own in-house lab — into body scrubs and related skincare products. Products are packaged in tubes described as roughly 86% plant-based, made from sugarcane rather than conventional petroleum plastic, reducing associated CO2 emissions. The brand sells direct-to-consumer"}, {"name": "Grupo Boticário", "slug": "grupo-boticario", "country": "Brazil (São José dos Pinhais, Paraná)", "categories": "consumer-education, refill, reusable-packaging, reverse-logistics", "priority": "★★★ Medium", "summary": "Grupo Boticário, founded in 1977 in Curitiba, Brazil, is one of Latin America's largest beauty and cosmetics conglomerates, operating a multi-brand portfolio (O Boticário, Eudora, Quem Disse Berenice?, O.U.i, The Beauty Box, Vult) through a large franchise retail network across Brazil and internationally. Its flagship brand, O Boticário, has for decades sold \"Refil\" (refill) versions of its cologne/deodorant (\"desodorante colônia\") lines — customers keep a decorative bottle and purchase cheaper refill units to replenish it"}, {"name": "Grupo Modelo", "slug": "grupo-modelo", "country": "Mexico (Mexico City)", "categories": "consumer-education, deposit-return, material-recovery, reverse-logistics", "priority": "★★★★ High", "summary": "Grupo Modelo is Mexico's largest brewer, founded in 1925 and best known internationally as the maker of Corona, Modelo Especial and Victoria. It has been a wholly owned subsidiary of AB InBev since the completion of AB InBev's acquisition in 2013. Within Mexico, Grupo Modelo operates a large-scale returnable (\"retornable\") glass bottle system for its core domestic beer brands, in which consumers return empty bottles to retailers for a deposit-linked discount, supported by a network"}, {"name": "Guppyfriend", "slug": "guppyfriend", "country": "Germany (Berlin)", "categories": "consumer-education, waste-reduction", "priority": "★★★ Medium", "summary": "Guppyfriend GmbH, founded in 2016 in Berlin by Oliver Spies and Alexander Nolte, is a German-developed, patented reusable washing bag designed to trap microplastic fibres shed by synthetic clothing during machine washing, preventing them from entering wastewater and, ultimately, oceans and waterways. Independent testing by the Fraunhofer Institute UMSICHT found that clothes washed inside the bag shed on average 86% fewer microfibres. The product is manufactured in Europe — filter fabric sourced from Italy, other"}, {"name": "HACARI", "slug": "hacari", "country": "Japan (Nakameguro, Meguro-ku, Tokyo)", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "HACARI is an independent greengrocer (\"yaoya\") in the Nakameguro district of Tokyo, described in Japanese consumer and industry media as Japan's only produce shop selling fresh vegetables by weight (\"量り売り\"). Founded by Yoshitaka Katayama to connect consumers directly with small farmers producing outside conventional mass-market supply chains, HACARI sources from a network reported at over 200 producers nationwide. The shop also sells prepared side dishes and partner products such as \"Traveling Cheesecake\" and a vegetable"}, {"name": "Haeckels (now rebranding as Dulcie)", "slug": "haeckels", "country": "United Kingdom (Margate, Kent)", "categories": "consumer-education, refill, reusable-packaging", "priority": "★★★ Medium", "summary": "Haeckels was founded in Margate, Kent in 2012 by Dom Bridges, a volunteer beach warden, who began experimenting with seaweed (bladderwrack, kelp and dulse) hand-harvested from the local shoreline; the brand's first small lab opened on Cliff Terrace in 2013. Haeckels grew into a marine-derived skincare, fragrance and homeware brand sold through its own stores, \"Community Hubs\" in Margate and London, and wholesale/retail partners. In November 2024 the company announced it would remove the \"Haeckels\""}, {"name": "Happi Earth", "slug": "happi-earth", "country": "Australia (Molendinar, Gold Coast, Queensland)", "categories": "consumer-education, refill, reusable-packaging, take-back, waste-reduction", "priority": "★★★★ High", "summary": "Happi Earth is an Australian-owned company, manufacturing from a factory in Molendinar on the Gold Coast, Queensland, that produces a certified-organic (food-grade certified), concentrated laundry liquid delivering up to 400 washes per pouch. Founded by Alf Orpen, the company was already established and being covered in industry media by May 2019. Its packaging is a kraft-paper pouch with a fine plastic lining and integrated handle/spout, designed explicitly for return and refill rather than single use,"}, {"name": "HAVU Cosmetics", "slug": "havu-cosmetics", "country": "Finland (Espoo — Tekniikantie 12, 02150 Espoo)", "categories": "consumer-education, material-recovery, refill, reusable-packaging", "priority": "★★★ Medium", "summary": "HAVU Cosmetics is a Finnish natural cosmetics brand founded by Lumi Maunuvaara, who developed the original concept — a natural lipstick in a simple wooden case — as a chemical engineering student at Aalto University, together with classmate and co-founder Tatu Fontell who encouraged bringing the product to market. The brand's name derives from the Finnish word for an evergreen sprig or needle. HAVU produces its lipsticks in its own lab in Espoo, using PLA"}, {"name": "Havu Solutions", "slug": "havu-solutions", "country": "Finland (per seed data; unverified)", "categories": "Not publicly available", "priority": "★ Low relevance", "summary": "The seed data for this profile described \"Havu Solutions\" as a Finland-based consultancy for reusable/refillable packaging systems, potentially related to HAVU Cosmetics. Extensive searching found no verifiable evidence of this organisation: the seed website domain (havusolutions.com) currently resolves to an unrelated Finnish-language online gambling site (\"Reipas Casino\"), with no historical connection to packaging consultancy found. No mentions of \"Havu Solutions\" as a packaging/reuse consultancy appeared in web search results, industry press, or Finnish business registries."}, {"name": "Hearth and Harvest", "slug": "hearth-and-harvest", "country": "United States (Florida; specific city not confirmed)", "categories": "Not publicly available", "priority": "★ Low relevance", "summary": "Search engine indexing shows a business at hearthandharvestfl.com titled \"Hearth & Harvest – Evelyn & Co.,\" associated with hosting the \"Heritage Harvest Farmers Market\" on the first Sunday of each month, described as offering fresh goods, handmade essentials, and locally-grown/gathered products from local farmers and artisans. At the time of this research, the website itself could not be reached directly (DNS lookup failure), so this profile relies entirely on third-party search-result summaries rather than direct"}, {"name": "Hello Everist", "slug": "hello-everist", "country": "Canada (Toronto, Ontario)", "categories": "consumer-education, refill, reusable-packaging, take-back, waste-reduction", "priority": "★★★ Medium", "summary": "Everist (marketed as \"Hello Everist\") is a Toronto-based beauty company that makes patent-pending, 3x-concentrated shampoo, conditioner and body wash pastes, packaged in 100ml aluminium tubes rather than plastic bottles filled mostly with water. Customers add water in the shower to activate the product. Founded by Jayme Jenkins and Jessica Stevenson and launched publicly in January 2021, the company has since won multiple sustainability and innovation awards, including a TIME Best Inventions recognition, and positions itself"}, {"name": "HelloEco", "slug": "helloeco", "country": "Kazakhstan (Almaty)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "HelloEco describes itself as \"the first and only zero-waste concept store in Kazakhstan,\" based in Almaty's Samal district. It sells eco-friendly beauty, home, and grocery products both pre-packaged and in bulk/refill format, encouraging customers to bring their own containers. The store's stated philosophy centers on waste reduction and reuse, and it maintains both a small transactional website (helloeco.kz) and an active Instagram presence (@helloecokz) that appears to be its primary customer-facing channel."}, {"name": "Het Goed", "slug": "hetgoed", "country": "Netherlands (Deventer / multi-region)", "categories": "consumer-education, material-recovery, reverse-logistics, take-back, waste-reduction", "priority": "★★★★ High", "summary": "Het Goed is a long-running Dutch \"kringloop\" (circular) warehouse network that collects donated furniture, electronics, clothing, and household goods and resells them through around 30 stores across the Netherlands. Originating in 1982 in Emmeloord under the name Goedzooi, the network took the \"Het Goed\" name in 1992 when it expanded to Deventer. Individual locations are typically run by independent regional foundations rather than a single corporate owner, sharing branding, logistics, and sorting infrastructure. The organisation"}, {"name": "hey circle", "slug": "hey-circle", "country": "Germany (Munich)", "categories": "digital-tracking, packaging-as-a-service, reusable-packaging, reverse-logistics, waste-reduction", "priority": "★★★★ High", "summary": "hey circle is a Munich-based startup founded in 2021 by Doris Diebold, Morris Kurz, Christian Krawczyk, and Rebecca Steinke, offering reusable shipping packaging — boxes and bags in eight sizes (XS–XXL) — as a drop-in replacement for single-use cardboard cartons in e-commerce and logistics. Its packaging is designed for at least 50 reuse cycles and is intended to be used \"like cardboard\" but returned, cleaned, and recirculated. The company raised a €1.5 million seed round"}, {"name": "HiBAR", "slug": "hibar", "country": "United States (Saint Paul, Minnesota)", "categories": "consumer-education, waste-reduction", "priority": "★★★ Medium", "summary": "HiBAR was founded in 2018 in the Minneapolis–Saint Paul area by parents whose children attended school together, with a mission to eliminate single-use plastic bottles from personal care. The company makes waterless, solid-format shampoo, conditioner, deodorant, face wash, and body wash bars designed to perform like conventional liquid products while removing the plastic bottle entirely. HiBAR products are sold online and reportedly stocked in over 11,000 retail locations in the US, positioning the brand within"}, {"name": "Himalayan Chef", "slug": "himalayan-chef", "country": "Pakistan", "categories": "consumer-education, reusable-packaging", "priority": "★★ Low", "summary": "Himalayan Chef is a Pakistani food brand specializing in Himalayan pink salt, organic flours, ghee, honey, spices, rice and pulses. It markets itself on purity, HACCP-certified hygienic processing, and sustainable packaging. The company sells through its own e-commerce sites (himalayanchef.pk and a US-facing himalayanchef.com) as well as major retail partners internationally, including Whole Foods, Walmart, Carrefour, Metro and Costco, alongside online marketplaces such as Daraz and Amazon."}, {"name": "Hispack", "slug": "hispack", "country": "Spain (Barcelona)", "categories": "consumer-education", "priority": "★★ Low", "summary": "Hispack is a biennial trade fair held at Fira de Barcelona's Gran Via venue, dedicated to packaging technology, machinery, labelling/bottling, logistics/automation and brand packaging. It is organized by Fira de Barcelona, the same institution behind Mobile World Congress, and bills itself as one of the leading packaging fairs in Southern Europe and a commercial gateway between Iberian, Mediterranean and Latin American markets. It is an event, not a manufacturer or service provider, and does not"}, {"name": "Hoa Đất – Tiêu dùng an lành", "slug": "hoa-dat-tieu-dung-an-lanh", "country": "Vietnam", "categories": "refill, reusable-packaging", "priority": "★★ Low", "summary": "Hoa Đất – Tiêu dùng an lành (\"Hoa Đất – Healthy/Clean Consumption\") is a small Vietnamese business operating primarily through a Facebook page rather than a dedicated website. The name signals a focus on healthy, low-toxin consumption, and the seed data associates it with reusable/refillable packaging for food and personal-care products. Public information about this business is very limited; no independent press coverage, registry record, or detailed \"About\" content could be located beyond the Facebook"}, {"name": "Home Ec. Market", "slug": "home-ec-market", "country": "United States (Presque Isle, Maine)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Home Ec. Market is a zero-waste refillery based in Presque Isle, Maine, selling household, personal-care, and family products described as toxin-free and plastic-free. It positions itself around local sourcing and reducing single-use packaging, operating both an e-commerce storefront and an active social presence (Instagram, Facebook). It appears to be a small independent retailer serving a regional/rural Maine market plus online customers, rather than a large national chain."}, {"name": "Homethings", "slug": "homethings", "country": "United Kingdom", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Homethings is a UK direct-to-consumer cleaning products company founded by Matt Aubrey and Tim Keaveney. Its core innovation is concentrated cleaning \"tabs\" (for sprays, laundry, dishwashing and toilet cleaning) that customers dissolve in tap water inside reusable bottles, eliminating the need to ship and dispose of mostly-water single-use plastic bottles. The company is B Corp certified, gained national visibility via a 2021 Dragons' Den appearance, and has expanded from pure online sales into UK retail,"}, {"name": "HRK Group", "slug": "hrk-group", "country": "Vietnam (Ho Chi Minh City)", "categories": "material-recovery, waste-reduction", "priority": "★★ Low", "summary": "HRK Group is a Vietnamese sustainable-packaging manufacturer founded in 2019 to develop alternatives to conventional plastic packaging. It operates through its Turn Green brand and platform, and has invested in dedicated production facilities — including GPS Plas (biodegradable/compostable resins) and PVA Pro (water-soluble PVA resin and flexible film packaging), the latter described as Vietnam's first factory producing water-soluble PVA resin. The company positions itself as a \"one-stop sustainable packaging\" supplier to F&B and retail brands"}, {"name": "Humusz Szövetség", "slug": "humusz-szovetseg", "country": "Hungary (Budapest)", "categories": "consumer-education, waste-reduction", "priority": "★★★ Medium", "summary": "Humusz Szövetség is a Hungarian environmental NGO alliance dedicated to waste prevention and the transition toward zero waste. Headquartered in Budapest (\"Humusz Ház\"), it grew out of a long-running waste working group of Hungarian environmental organisations. It is a member of Zero Waste Europe and is listed among RREUSE's network of organisations. Its work spans policy advocacy, public education, and coordination of a national network of grassroots zero-waste initiatives."}, {"name": "Hygiene of Sweden", "slug": "hygiene-of-sweden", "country": "Sweden (Bromma)", "categories": "refill, reusable-packaging", "priority": "★★★ Medium", "summary": "Hygiene of Sweden, founded in 2012 by Philip Wilhelmsson and based in Bromma, Sweden, develops non-alcoholic disinfection and hygiene products for professional and everyday use. Its formulations are marketed as gentler on skin and materials than alcohol-based alternatives while remaining effective against viruses including coronaviruses and norovirus. The company supplies both branded products and private-label hygiene solutions, and participated in the IFMA Innovation award programme with its \"BioPolymer+\" alcohol-free hand hygiene product."}, {"name": "iKasa", "slug": "i-kasa", "country": "Japan — Tokyo", "categories": "digital-tracking, sharing, waste-reduction", "priority": "★★★★ High", "summary": "iKasa is an umbrella-sharing service launched in 2018 in Tokyo by Nature Innovation Group. Users rent durable, glass-fibre umbrellas via the iKasa smartphone app, scanning a QR code at umbrella stands located in stations, office buildings, and other public spaces, paying 140 yen per use or 280 yen/month for a subscription. The service has grown to over 1,600 locations across the Tokyo metropolitan area plus Kansai, Nagoya, and Fukuoka, with approximately 600,000 members."}, {"name": "IFCO", "slug": "ifco", "country": "Germany (Grunwald/Pullach, near Munich) — global operations across 50+ countries", "categories": "industrial-reuse, reusable-packaging, reverse-logistics, waste-reduction", "priority": "★★★★★ Essential", "summary": "IFCO is the world's leading pooler of reusable plastic containers (RPCs) for fresh food, founded in Germany in 1992. It pioneered an outsourced, closed-loop pooling model — branded \"SmartCycle\" — that replaces single-use cardboard and plastic packaging in fresh produce, protein, dairy, egg and bakery supply chains. IFCO operates a pool of over 370 million RPCs, used for roughly 2 billion shipments annually, serving grocery retailers and suppliers across Europe, the Americas and Asia-Pacific. It"}, {"name": "Ilma Pood", "slug": "ilma-pood", "country": "Estonia (Tallinn, Telliskivi 60a/2)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "Ilma Pood (\"store without\" in Estonian) opened in Tallinn in 2020 as one of Estonia's first package-free/zero-waste retail concepts. It sold dry foods, cosmetics and household products in bulk, encouraging customers to bring their own reusable containers, and it ran a \"Can Bank\" where customers could borrow donated containers if they didn't have their own. A second, crowdfunded location opened in Tartu. The business marked its fifth anniversary around 2025, framed publicly as a closing"}, {"name": "IMA Group", "slug": "ima-group", "country": "Italy (Ozzano dell'Emilia, Metropolitan City of Bologna)", "categories": "reusable-packaging", "priority": "★★ Low", "summary": "IMA Group is a large Italian multinational, founded in 1961 and headquartered near Bologna, that designs and manufactures automatic processing and packaging machinery for pharmaceuticals, cosmetics, food, tobacco, tea and coffee. It employs roughly 6,000 people worldwide (over 2,800 outside Italy) and reported consolidated revenues above €1.6 billion in recent years. IMA is overwhelmingly a machinery manufacturer, not a reuse-system operator; its connection to reusable packaging is narrow and recent, stemming from a 2024 collaboration"}, {"name": "ImpacX", "slug": "impacx", "country": "Israel (Rehovot)", "categories": "consumer-education, digital-tracking", "priority": "★★ Low", "summary": "ImpacX (now operating and trading as Water.io) is an Israeli IoT technology company founded in 2015 and based in Rehovot. It builds a connected-packaging platform centered on smart caps — Bluetooth-enabled lids for reusable water bottles and vitamin/supplement containers — that measure liquid level or dosage and sync usage data to a companion mobile app. Its two product lines are Water.io (smart hydration) and Vitamins.io (smart supplement tracking). The company is publicly traded on the"}, {"name": "Incrediballs", "slug": "incrediballs", "country": "New Zealand (Ōtautahi Christchurch)", "categories": "consumer-education, waste-reduction", "priority": "★★ Low", "summary": "Incrediballs is a New Zealand consumer-goods startup founded by Brianne West (previously founder of plastic-free beauty brand Ethique) after she stepped down as Ethique's CEO in 2023. It makes small, concentrated, dissolvable \"balls\" of flavouring that turn a glass of tap or sparkling water into a flavoured drink, marketed as the \"world's first plastic-free, waste-free drink.\" The product is designed to eliminate the need for single-use plastic beverage bottles and to cut the weight/emissions cost"}, {"name": "Indigo River & Co.", "slug": "indigo-river-and-co", "country": "United States (Cedar Rapids, Iowa)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "Indigo River & Co. is a small, independently owned low-waste retail shop in Cedar Rapids, Iowa, selling handmade soaps, personal care items, and refillable household and cleaning products. Reported to be among the first (or one of very few) low-waste refill shops in the state, it operates both a physical storefront with an in-store refill station and an online store. The business is run by co-owners Rachel and Tim, with Tim producing the shop's in-house"}, {"name": "Indo Sole (Indosole Singapore)", "slug": "indo-sole", "country": "Singapore (regional storefront); global brand headquartered in California, USA, with manufacturing in Bali, Indonesia", "categories": "industrial-reuse, material-recovery, waste-reduction", "priority": "★★★ Medium", "summary": "\"Indo Sole\" (indosole.com.sg) is the Singapore-market storefront of Indosole, a footwear brand founded by American entrepreneur Kyle Parsons after discovering tire-sole sandal craftsmanship in Bali in 2004; the brand commercially launched in 2009. Indosole makes flip-flops, slides and sandals with soles made largely from upcycled waste tires (roughly 40% recycled tire content, blended with natural rubber and other materials), manufactured by artisans in Bali and sold globally — reportedly in nearly 400 stores across 27"}, {"name": "Indorama Ventures (IVL)", "slug": "indorama-ventures", "country": "Thailand (Bangkok)", "categories": "material-recovery", "priority": "★★ Low", "summary": "Indorama Ventures is a Bangkok-headquartered global petrochemicals group founded in 1994, publicly listed on the Stock Exchange of Thailand since 2008. It is the world's largest producer of PET (polyethylene terephthalate) resin and describes itself as the world's largest producer of recycled PET (rPET) for beverage bottles. The company operates over 100 manufacturing sites across more than 30 countries and reports around 28,000 employees (2024). Its business spans three core segments: Integrated Oxides and Derivatives,"}, {"name": "Inokem", "slug": "inokem", "country": "Portugal (Forte da Casa, Vila Franca de Xira)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Inokem is a Portuguese brand producing ultra-concentrated, biodegradable household cleaning and disinfecting products. Its central proposition is concentration: because its detergents are sold in a highly concentrated form, one Inokem package is marketed as replacing up to 100 packages of conventional ready-to-use detergent. The company sells both direct-to-consumer concentrate bottles and offers in-store refill of empty Inokem packaging at partner retail points, including notable retail alliances with Lidl Portugal and Auchan. Inokem has received Portuguese"}, {"name": "InPost", "slug": "inpost", "country": "Poland — Krakow (holding company InPost S.A. registered in Luxembourg)", "categories": "consumer-education, reusable-packaging, reverse-logistics", "priority": "★★ Low", "summary": "InPost is Poland's largest last-mile delivery and parcel-locker (Automated Parcel Machine/APM) network operator, founded in 2006 and listed on Euronext Amsterdam since January 2021. The company's core business — over 20,000 parcel lockers across Poland and expanding European markets — is not itself a reuse activity. Separately, InPost developed EkoBox, launched in December 2021 with fashion retailer MODIVO (CCC Group), Poland's first reusable secondary-packaging (returnable shipping box) system for e-commerce, developed with Danish packaging company"}, {"name": "Interzero", "slug": "interzero", "country": "Germany (registered office Berlin; operational headquarters Cologne)", "categories": "consumer-education, material-recovery, packaging-as-a-service, reusable-packaging, reverse-logistics, take-back", "priority": "★★★★ High", "summary": "Interzero is a German environmental-services group tracing its roots to Interseroh AG, founded in Cologne in 1991 by a consortium of waste-management companies. In 2022, following a split of the ALBA Group between brothers Eric and Axel Schweitzer, the plastics-recycling and related circular-economy businesses were carved out and rebranded as Interzero, under Axel Schweitzer's control. The group operates across roughly 61 subsidiaries in 10 European countries, employs about 2,000 people, and organizes its business into"}, {"name": "IpohRefill", "slug": "ipohrefill", "country": "Malaysia (Ipoh Garden South, Ipoh, Perak)", "categories": "consumer-education, material-recovery, refill, waste-reduction", "priority": "★★★ Medium", "summary": "IpohRefill is Malaysia's first zero-waste store in Ipoh, Perak, founded by Peisee and opened in February 2024 after she was selected for the Perak Environmental Accelerator Program 2023 (run by Biji-Biji Initiative), which provided funding to establish refill stations. The flagship store, located at Ipoh Garden South, sells package-free household and personal-care products and operates a refill system where customers bring their own containers to refill cleaning products, shampoos, detergents and dishwashing liquids. Beyond retail,"}, {"name": "IRN Surplus (The Reuse Network)", "slug": "irn-surplus", "country": "United States (Concord, New Hampshire)", "categories": "reverse-logistics, sharing, take-back, waste-reduction", "priority": "★★★ Medium", "summary": "IRN (Institution Recycling Network), operating as \"The Reuse Network,\" is a small US-based nonprofit-style organisation that connects institutions — schools, colleges, corporations, healthcare facilities, and government agencies — with surplus furniture and equipment to nonprofit organisations and communities in need. Originally a recycling cooperative for education and healthcare institutions, it pivoted toward furniture reuse after founder Mark Lennon observed usable furniture being discarded while people lacked basic furnishings. It is based in Concord, New Hampshire,"}, {"name": "IstaPack", "slug": "istapack", "country": "Turkey (Istanbul)", "categories": "material-recovery, reusable-packaging", "priority": "★★ Low", "summary": "IstaPack is an Istanbul-based B2B packaging manufacturer that has operated since 2005, producing cotton tote bags alongside luxury paper bags and premium packaging (boxes, custom-printed packaging) for brand clients. The company markets itself around sustainability credentials — citing certifications such as OEKO-TEX, GRS (recycled content), and GOTS (organic cotton) — and reports serving a client base that is approximately 99% European, concentrated in luxury/fashion, cosmetics/beauty, and jewelry/accessories sectors. It positions cotton totes as a reusable,"}, {"name": "ItsBio", "slug": "itsbio", "country": "Estonia (Pärnu)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "It's Bio (ItsBio) is a package-free retail shop operating from Port Artur shopping centre in Pärnu, Estonia, run by the registered company Biokaup OÜ. It sells organic and local food (nuts, seeds, dried fruits, grains, spices, superfoods) largely in bulk/package-free form, alongside natural cosmetics and personal-care products, home items, and children's products. Its stated mission is to reduce packaging use and offer plastic-free products, summarised in its own tagline \"Vähem prügi, kergem elu!\" (\"Less waste,"}, {"name": "Izifill", "slug": "izifill", "country": "Indonesia", "categories": "digital-tracking, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Izifill is an Indonesian startup, founded 2 February 2020 by CEO/co-founder Ichsan Mulia Pertama, providing IoT-based, touchless public water refill stations accessible via smartphone. The service lets tumbler users refill their own containers hygienically, without physically touching the dispenser, at automated water-station machines — reducing single-use plastic bottle consumption while also addressing hygiene concerns around shared touchpoints (a design consideration that became especially relevant during COVID-19). The company was incubated through LPIK ITB (the Bandung"}, {"name": "Izzy Zero Waste Beauty", "slug": "izzy-zero-waste", "country": "United States — New York City", "categories": "consumer-education, reusable-packaging", "priority": "★★★ Medium", "summary": "Izzy Zero Waste Beauty is a New York City-based direct-to-consumer cosmetics brand co-founded by industry veteran Shannon Goldberg (former leadership roles at Peter Thomas Roth Clinical Skin Care and Madonna's MDNA Skin) and engineer/inventor Chris Tarling. Marketed as \"the first fully reusable, sustainable, direct-to-consumer beauty brand,\" its flagship product is a prestige mascara described as 100% reusable and 100% recyclable, addressing the cosmetics industry's typically disposable packaging model. The brand name derives from Tarling's young"}, {"name": "JDL (JD Logistics)", "slug": "jdl", "country": "China (Beijing)", "categories": "digital-tracking, reusable-packaging, reverse-logistics, waste-reduction", "priority": "★★★ Medium", "summary": "JD Logistics is the logistics and supply-chain subsidiary of Chinese e-commerce giant JD.com. Originally built to serve JD.com's own delivery network, it became an independent, externally-facing logistics provider in 2017 and listed on the Hong Kong Stock Exchange in 2021. As part of its \"Green Stream Initiative\" (launched 2017), JDL has developed one of the largest reusable-packaging programs in e-commerce logistics, replacing single-use cartons and tape with durable, trackable delivery boxes across its warehousing and"}, {"name": "Jean Bouteille", "slug": "jean-bouteille", "country": "France (Lille)", "categories": "consumer-education, refill, reusable-packaging", "priority": "★★★★ High", "summary": "Jean Bouteille is a French company founded in Lille that pioneered a returnable-bottle, bulk-liquid dispensing system for retail stores. Named as a play on founder Gérard Bellet's name, the company provides in-store dispensing fixtures and reusable glass or plastic bottles so shoppers can buy liquid products (wine, oil, juice, detergent, shampoo, cleaning products) without single-use packaging. It has certified \"Entreprise à Mission\" and ESUS (social utility) status since 2018, reflecting its stated purpose of accompanying"}, {"name": "Jentli", "slug": "jentli", "country": "United States — Elgin, Illinois", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "Jentli (branded \"JENTLI ZERO WASTE\") is a small independent zero-waste refillery based in downtown Elgin, Illinois, describing itself as the Fox Valley region's dedicated refill shop. It offers a bring-your-own-container (BYOC) refill station for household and personal-care products alongside a curated selection of pre-packaged eco-friendly goods (e.g., safety razors, utensil sets, deodorant). The shop sells both in-store and online with nationwide shipping via its own website and third-party marketplaces such as Marketspread. Public information about"}, {"name": "Join The Pipe", "slug": "join-the-pipe", "country": "Netherlands — Amsterdam", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Join The Pipe is an Amsterdam-based non-profit foundation operating a social-enterprise model: it sells branded reusable water bottles (including sugarcane-material variants) and refill tap stations to hotels, events, municipalities, retailers, and offices, using that commercial revenue to fund water and sanitation projects — including refill infrastructure, water kiosks at schools, and hand-pump distribution in rural areas — primarily in developing regions of Africa and Asia. Its mission statement centres on \"refill, reuse, reduce\" to combat"}, {"name": "Jolly Eco", "slug": "jolly-eco", "country": "Singapore", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "Jolly Eco is a Singapore homegrown eco-friendly retailer with a physical store at Parkway Parade (80 Marine Parade Road) selling reusable, non-toxic, ethically sourced kitchen and bathroom products, as well as reusable period-care items (menstrual cups, period underwear). Its stated aim is to promote sustainable living and reduce single-use \"disposal culture\" through everyday reusable alternatives."}, {"name": "Just Good Refills", "slug": "just-good-refills", "country": "Cambodia — Phnom Penh", "categories": "refill, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "Just Good Refills is a refill shop based in Phnom Penh, Cambodia, offering refillable and swappable containers for personal-care and home-care products. It operates via both a dedicated website and a Facebook presence (justgoodcambodia), positioning itself around product quality alongside its refill/reuse model."}, {"name": "Kamupak", "slug": "kamupak", "country": "Finland — Helsinki", "categories": "deposit-return, digital-tracking, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "Kamupak was a Finnish reusable-takeaway-packaging company founded in 2018 (some sources say 2019) to combat single-use plastic food packaging via a digital deposit-return system. Its flagship product, the KamuDish (a 1.2-litre reusable flat container), launched in 2020 and by 2021 had replaced 10,000 single-use containers across 50 restaurants, cafés, and supermarkets in Finland. In August 2023, Kamupak merged with Stockholm-based competitor &Repeat to form a combined Nordic circular-packaging leader with 500+ customers across Sweden and"}, {"name": "Kao", "slug": "kao", "country": "Japan", "categories": "consumer-education, material-recovery, refill, reusable-packaging", "priority": "★★★★★ Essential", "summary": "Kao Corporation is a major Japanese household and personal-care products manufacturer, founded in 1887, publicly listed on the Tokyo Stock Exchange (4452), with 33,000+ employees globally. Kao released its first refill packs in 1991 and has since built one of the largest and longest-running refill programmes in the consumer goods industry, encompassing 423 distinct refill products as of December 2023 spanning shampoo, liquid detergent, and other categories, alongside its proprietary \"Smart Holder\" system for the"}, {"name": "KarmaMarkt", "slug": "karmamarkt", "country": "Belgium — Bruges", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "KarmaMarkt is an independently owned, packaging-free retail store in Bruges, Belgium, run by shopkeeper/owner Isabelle. It sells organic and locally sourced bulk goods without packaging, letting customers bring their own containers or purchase reusable ones in-store. Distinctively, the business also incorporates a wellness space offering massages, sound baths, and workshops alongside its zero-waste retail operation, and maintains an online webshop in addition to its physical store."}, {"name": "KazakhUpack", "slug": "kazakhunpack", "country": "Kazakhstan — Shymkent", "categories": "industrial-reuse", "priority": "★★ Low", "summary": "KazakhUpack is a Kazakhstani packaging company based in Shymkent, operating since 2003 (20+ years), specialising in polymer pails, buckets, and containers for the safe storage and transport of food, chemical, and paint/varnish products. The seed tracker's description of \"reusable containers and bags\" is only partially supported — verified sources describe the company primarily as a durable-container manufacturer/trader rather than a documented reuse-loop operator."}, {"name": "KeepCup", "slug": "keepcup", "country": "Australia — Melbourne", "categories": "consumer-education, reusable-packaging", "priority": "★★★★ High", "summary": "KeepCup was founded in 2009 in Melbourne by siblings Abigail and Jamie Forsyth, who previously ran Bluebag, a Melbourne CBD sandwich-shop chain founded in 1998. Observing the volume of disposable cups generated by their café customers, they designed what is described as the world's first \"barista-standard\" reusable coffee cup — engineered to work efficiently with espresso machines and café service — and sold the first units at an independent Melbourne market in 2009. The brand"}, {"name": "Khaadi", "slug": "khaadi", "country": "Pakistan (with UK and US retail presence)", "categories": "material-recovery, waste-reduction", "priority": "★ Low relevance", "summary": "Khaadi is a major Pakistani fashion and lifestyle retail brand known for handcrafted textiles promoting Pakistani culture and heritage, with retail presence in Pakistan, the UK, and (recently) the US. Its sustainability initiatives include \"The Green Hub\" in Mardan — described as Pakistan's first net-zero-energy retail space — where the company has shifted to e-receipts and uses recycled shopping bags in place of plastic packaging."}, {"name": "Khaalisisi", "slug": "khaalisisi", "country": "Nepal — Kathmandu", "categories": "digital-tracking, material-recovery, reverse-logistics", "priority": "★★ Low", "summary": "Khaalisisi is a Nepali digital platform founded by Aayushi KC, who left a role at USAID Nepal to start the company, registering it in February 2017 and launching the live service in June 2017. It connects households and businesses in Kathmandu (\"waste sellers\") with independent local waste entrepreneurs (\"Khaalisisi friends\") who collect, sort, and recycle trash, with users able to schedule pickups and choose to sell or donate their waste. The company's stated mission is"}, {"name": "KidV (now Verpact)", "slug": "kidv", "country": "Netherlands — The Hague", "categories": "consumer-education, material-recovery, reusable-packaging", "priority": "★★★ Medium", "summary": "KidV (Kennisinstituut Duurzaam Verpakken) is a Dutch knowledge institute focused on helping organisations make informed, realistic decisions about sustainable packaging, including reusable-packaging collaboration and standards. In November 2025, the organisation rebranded to \"Verpact,\" continuing the same mission under a new name — a notable status change not reflected in the seed tracker, which still lists it as \"KidV.\""}, {"name": "Kiima", "slug": "kiima", "country": "Canada — Montreal, Quebec", "categories": "packaging-as-a-service, refill, reusable-packaging", "priority": "★★★★ High", "summary": "Kiima is a Montreal-based startup co-founded by Jenny Essiambre and Samuel Lemire-Dupont, developing a refillable deodorant applicator designed to last 10 years, manufactured in Quebec. The applicator uses a unique mechanism enabling plastic-free refilling, and the company has built an ecosystem of cosmetics partners who design compatible refills for the applicator format. Within two years of launch, Kiima expanded to hundreds of points of sale, including Jean Coutu, Avril, and Simons in Canada, plus international"}, {"name": "Kilogram S.I.S.", "slug": "kilogram-sis", "country": "Luxembourg", "categories": "deposit-return, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Kilogram S.I.S. describes itself as the first \"bio e-shop sustainable and zero waste\" in Luxembourg — an online organic grocery store delivering products (beauty/personal care, beverages, bakery, fresh produce, dairy, wine, home/garden items, and more) in returnable containers that customers send back for refill cycles, with 24-48 hour delivery. The company claims to avoid up to 90% of packaging waste compared to conventional grocery delivery."}, {"name": "Kinfill", "slug": "kinfil", "country": "Netherlands — Rotterdam", "categories": "refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Kinfill is a Dutch cleaning-products brand founded in 2020 in Rotterdam by Reda Jouahri, following roughly four years of development after an idea sparked in conversation with friends. The company manufactures environmentally-friendly cleaning concentrates — biodegradable, free of chemicals, palm oil, glue, chlorides, and dyes — sold in reusable, refillable glass bottles made from high-quality Italian glass with a minimalist design, reducing plastic household-cleaning waste."}, {"name": "Kinkō (KinkoCare)", "slug": "kinkocare", "country": "United States", "categories": "Not publicly available", "priority": "★ Low relevance", "summary": "Kinkō (referred to in seed data as \"KinkoCare\") is a US natural-deodorant brand built around its proprietary \"MICROBIOMIX\" technology — a patent-pending blend of prebiotics and postbiotics designed to balance the underarm microbiome and prevent odour naturally rather than mask it. Products are aluminium-free, non-toxic, biodegradable, 100% vegan, and PETA-approved. The brand has been featured in publications including Allure, Yahoo Lifestyle, and BeautyStat, and offers a subscription purchasing model."}, {"name": "Kita Refill", "slug": "kita-refill", "country": "Malaysia — Petaling Jaya", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Kita Refill is the trading name of Cleancycle Enterprise, an unpackaged bulk refill store based in Petaling Jaya, Malaysia. The brand was rebranded from its original name \"Bring YOUR Own Bottle\" (BYOB) to \"Kita Refill\" — \"Kita\" meaning \"we\" in Malay — reflecting a collective, community-oriented sustainability positioning. Customers reuse their own containers to refill floor/kitchen cleaners, laundry detergents, specialty cleaning solutions, gardening products, and personal-care items at affordable prices."}, {"name": "Kjaer Weis", "slug": "kjaer-weis", "country": "United States — New York, New York", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Kjaer Weis is a luxury beauty brand founded in 2010 by Danish makeup artist Kirsten Kjaer Weis in New York City. It is widely credited as the first luxury beauty brand to introduce fully refillable, certified-organic makeup packaging, launching its \"Iconic Edition\" line (cream blush, lip tint, eye shadow) in reusable metal compacts. The brand's products are certified organic, gluten-free, and cruelty-free, with recyclable and compostable packaging elements alongside the refillable cases. In 2021, private"}, {"name": "Kleen Hub", "slug": "kleen-hub", "country": "Denmark — Copenhagen", "categories": "consumer-education, deposit-return, digital-tracking, packaging-as-a-service, reusable-packaging", "priority": "★★★★ High", "summary": "Kleen Hub is a Copenhagen-based circular-economy technology company founded in 2019 by Simone Favorito, Robert Dichtl and Giuseppe Lanzafame after the founders were struck by the volume of single-use plastic generated by a Thai takeaway dinner. The company builds reusable-packaging infrastructure for the food-service sector, evolving from an early app-based cup/container borrowing system into \"TAP&REUSE™,\" a contactless bank-card-tap system using RFID/NFC-embedded stainless-steel cups and containers. The system lets customers borrow and return reusable packaging without"}, {"name": "KM Packaging", "slug": "km-packaging", "country": "United Kingdom — Oundle/Peterborough, England", "categories": "consumer-education, material-recovery, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "KM Packaging Services Ltd. is a UK flexible-packaging manufacturer founded in 1984, based in Oundle, near Peterborough, England. The company supplies lidding films, skin films, pouches, bags, foils and flow-wrap packaging to food manufacturers across sectors including prepared meals, fresh produce, meat/poultry/seafood, bakery, confectionery, dairy and plant-based protein, operating through proprietary brands (KPEEL®, KSEAL®, KSKIN®, KFOIL®, KRESEAL®, KNATURE®) and a compostable \"C-Range.\" The company converted to an Employee Ownership Trust structure to secure long-term independence."}, {"name": "KOKO Networks", "slug": "koko-networks", "country": "Kenya — Nairobi (operations also in Rwanda; formerly Uganda)", "categories": "consumer-education, refill, reverse-logistics", "priority": "★★★ Medium", "summary": "KOKO Networks was a Nairobi-headquartered clean-cooking company that distributed bioethanol cooking fuel as a substitute for charcoal, sold through a network of ATM-like \"KOKO Point\" fuel-dispensing stations. Customers used a reusable, chip-enabled \"KOKO Canister\" paired with a KOKO Cooker (stove) to refill bioethanol fuel repeatedly rather than purchasing new containers. At its peak (mid-2023) the company reported roughly 1 million household customers across eight Kenyan cities plus Rwanda, and employed approximately 1,800 people. In 2026,"}, {"name": "Kooperatywa (Kooperatywa Dobrze)", "slug": "kooperatywa", "country": "Poland — Warsaw", "categories": "consumer-education, refill, sharing, waste-reduction", "priority": "★★★ Medium", "summary": "Kooperatywa Dobrze is Poland's first grassroots consumer food cooperative, founded as an association in Warsaw in July 2013 before opening its first member-run shop in 2014 and a second in 2016. The cooperative sources organic, seasonal food directly from around 40 small-scale Polish farms annually, cutting out conventional retail intermediaries. As of 2023 it comprised roughly 206 member households (around 500 individual members), employed 18 staff, and operated two Warsaw shops (Andersa 27 and Polna"}, {"name": "Kooshoo", "slug": "kooshoo", "country": "Canada (co-founder also linked to Norfolk Island; design based in Canada)", "categories": "consumer-education, material-recovery, waste-reduction", "priority": "★★ Low", "summary": "KOOSHOO is a Canadian direct-to-consumer brand that designs and sells plastic-free hair accessories — hair ties, scrunchies and headbands — marketed as the world's first 100% plastic-free hair elastics, launched around 2012. Products are handmade using Fairtrade-certified organic cotton (GOTS certified) and natural tree rubber sourced from a Fair Rubber Association-certified, FSC (Forest Stewardship Council)-certified sustainable rubber plantation in southern India, dyed with OEKO-TEX-certified low-impact, non-toxic dyes. The company ships orders in 100% plastic-free packaging"}, {"name": "Korea Zero Waste Movement Network", "slug": "korea-zero-waste-movement-network", "country": "South Korea — Seoul (national network)", "categories": "consumer-education, deposit-return, waste-reduction", "priority": "★★★★ High", "summary": "The Korea Zero Waste Movement Network (KZWMN) is a South Korean non-profit NGO network founded in 1997, comprising approximately 180 grassroots environmental, citizens' and women's-movement organisations, organised into roughly 5 regional networks with 53 constituent organisations nationwide. It advocates for alternative waste policy — including deposit-return systems for glass bottles, mandatory refunds on plastic-bag charges, packaging-reduction regulation, and prohibitions on single-use cups, bags and containers — with the stated goal of building an \"ecological society\""}, {"name": "Kuradashi", "slug": "kuradashi", "country": "Japan — Tokyo (Shinagawa Ward), with a secondary site in Ichinoseki, Iwate Prefecture", "categories": "consumer-education, waste-reduction", "priority": "★★★ Medium", "summary": "Kuradashi Co., Ltd. is a Tokyo-based e-commerce company founded in 2014 by Tatsuya Sekito after he witnessed large volumes of food waste at processing facilities while working for a Japanese trading firm in China. Its \"Kuradashi.jp\" marketplace sells surplus, near-expiry or overstocked food, beverages, health and beauty items, and daily necessities at discounted prices, framed around the Japanese \"mottainai\" (regret over waste) ethic. A portion of proceeds is donated to non-profit organisations spanning disaster relief"}, {"name": "L'Occitane", "slug": "l-occitane", "country": "Not publicly available", "categories": "consumer-education, material-recovery, refill, reusable-packaging, reverse-logistics, take-back", "priority": "★★★ Medium", "summary": "L'OCCITANE en Provence is a French-origin, Switzerland-headquartered cosmetics and personal-care group selling body, hair, skin and home fragrance products in roughly 90 countries. Founded in 1976, it began experimenting with refillable packaging in 1980 and has since built out an eco-refill product line, in-store refill fountains, and a bottle take-back/recycling programme. The Philippines is served as a retail market rather than as a distinct operating subsidiary; products are sold online at ph.loccitane.com and through local"}, {"name": "La BOB", "slug": "la-bob", "country": "Switzerland — Avenches (Broye region, straddling Vaud/Fribourg cantons)", "categories": "consumer-education, rental, sharing, waste-reduction", "priority": "★★★ Medium", "summary": "La BOB (Bibliothèque d'Objets de la Broye — \"Broye Object Library\") is a Swiss non-profit association operating a network of \"object library\" locations across the Broye region, in Avenches, Estavayer and Payerne, with a further location planned in Moudon. Modelled on a traditional book library but for physical objects, La BOB lets members borrow rather than buy over 700 items spanning cooking, celebrations/parties, gardening, DIY/repair, health and recreation categories. The organisation is run entirely by"}, {"name": "La Nature", "slug": "la-nature", "country": "Mexico — Mexico City", "categories": "consumer-education, deposit-return, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "La Nature is a Mexico City retailer, opened in 2016, dedicated to selling healthy, locally sourced farm products — primarily dairy — in returnable glass containers or in bulk, explicitly aiming to value Mexican small-scale producers while reducing the city's carbon and packaging footprint. Its signature products are pasture-raised dairy items: free-range eggs from Querétaro, cheeses from Zacatlán de las Manzanas, fresh milk and cream from Ajusco, milk and goat cheese from Chimalhuacán, butter, ghee,"}, {"name": "La Quemisterie", "slug": "la-quemisterie", "country": "Argentina — Buenos Aires (Las Cañitas neighbourhood)", "categories": "consumer-education, deposit-return, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "La Quemisterie is a self-described \"triple impact\" (social, environmental, economic) company founded in Buenos Aires in 2016 by three women — chemist Graciela Oblitas (previously with multinationals including Clorox and Colgate), book editor Daniela Nobili, and technology teacher Inés Abbiati. Based in the Las Cañitas neighbourhood, it sells biodegradable, cruelty-free cleaning, fabric-care and hand-care products through a bulk refill model, using an automated LED-lit dispensing system called \"Le Vrac®\" to fill customer containers. The company"}, {"name": "La Sfuseria", "slug": "la-sfuseria", "country": "Italy — Faenza (Emilia-Romagna)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "La Sfuseria (di Gusto Vivo) is a bulk-goods shop in Faenza, Italy, offering over 300 organic and package-free food items — cereals, pasta, legumes, nuts, seeds, flours and baked goods — alongside fresh/fermented foods, eco-friendly household cleaners, solid cosmetics and zero-waste accessories. Note: \"La Sfuseria\" is a common generic name used by several unrelated bulk shops across Italy (Milan, Modena, Arco di Trento); this profile covers only the business operating at lasfuseria.it in Faenza."}, {"name": "Laiday Refill Station", "slug": "laiday-refill-station", "country": "Vietnam — Ho Chi Minh City", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Lại Đây (\"Laiday\") Refill Station, founded in 2018 by Quyen Nguyen, is described as Vietnam's first bulk store dedicated to refillable household and personal-care products. Customers bring their own non-plastic containers to refill items such as detergents, shampoos and cleaning liquids stored in large dispensing jugs. The business has expanded beyond refills into a broader sustainable-lifestyle retailer, stocking over 400 eco-friendly and reusable products, with locations across Ho Chi Minh City in District 2, District"}, {"name": "Laika", "slug": "laika", "country": "Bulgaria — Sofia", "categories": "consumer-education", "priority": "★★ Low", "summary": "Laika.bg positions itself as Bulgaria's first shop for Bulgarian-made products of verified natural origin, combining an e-commerce platform with a physical store at Sopharma Business Towers in Sofia. It curates natural cosmetics, foods (including gluten-free items, chocolates, tahini, oils and spices), supplements, superfoods, beverages, handmade gifts and books, stating that products are personally researched and tested before being listed for sale."}, {"name": "Lamazuna", "slug": "lamazuna", "country": "France — Marches, Drôme (since 2018)", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Lamazuna was founded in 2010 in France by Laëtitia Van de Walle, then 25, after she replaced disposable make-up remover pads with washable microfibre alternatives. The company grew from that single reusable product into a full zero-waste beauty brand, launching the bamboo Oriculi reusable ear stick in 2013 and solid shampoo, toothpaste and deodorant from 2014. Since mid-2018 Lamazuna has been headquartered on a 6-hectare eco-site in Marches, in the Drôme — France's leading organic-farming"}, {"name": "Lana", "slug": "lana", "country": "Philippines — Las Piñas, Metro Manila", "categories": "consumer-education, refill, reusable-packaging", "priority": "★★★ Medium", "summary": "Lana is a Filipino-made natural skincare and zero-waste lifestyle brand offering skincare formulated and packaged with sustainability in mind, including recyclable/repurposable packaging. The brand operates one physical refill station, hosted at Let's Glow Aesthetics in Las Piñas, where customers can bring back empty Lana containers to be refilled rather than purchasing new packaging each time. Lana also sells complementary zero-waste lifestyle items such as yoga mats alongside its core skincare range."}, {"name": "LastObject", "slug": "lastobject", "country": "Denmark — Copenhagen", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "LastObject was established in August 2016 in Copenhagen, Denmark, by siblings Isabel and Nicolas Aagaard together with Kåre Frandsen, after research into ocean plastic pollution identified cotton swabs as a major contributor. The company developed LastSwab, a reusable cotton swab, launching it publicly in April 2019 and running a Kickstarter campaign the following month that raised over $700,000 from more than 19,000 backers. LastObject has since expanded its range to include LastTissue, LastRound and LastMask,"}, {"name": "Laververt", "slug": "laververt", "country": "Belgium — Namur", "categories": "refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "LaverVert is a Belgian manufacturer of natural, ecological household cleaning products, handcrafted in a workshop in Namur. Its core products are built around a signature black soap made from locally sourced rapeseed oil, extended into a range of multi-purpose cleaners for laundry, gardens, terraces, natural stone and general home use. The company holds certified artisan/craftsmanship status and promotes transparency in ingredients, alongside DIY recipes so customers can make cleaning products at home."}, {"name": "Le Drive Tout Nu", "slug": "le-drive-tout-nu", "country": "France — Toulouse area (Beauzelle / Haute-Garonne)", "categories": "consumer-education, deposit-return, reusable-packaging, reverse-logistics, waste-reduction", "priority": "★★★★ High", "summary": "Le Drive Tout Nu was founded in 2018 by Pierre Géraud-Liria and Salomé Géraud, who conceived the idea in mid-2017 and opened what they describe as the world's first zero-waste \"drive\" (a French click-and-collect grocery format) in Beauzelle, near Toulouse, in December 2018. Products — including fruit and vegetables, dairy, meat, cosmetics and cleaning items — are supplied in reusable glass jars or fabric bags rather than disposable packaging. The concept has since expanded to"}, {"name": "Le Vrac", "slug": "le-vrac", "country": "France — Besançon", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Le Vrac is a package-free grocery store (\"épicerie sans emballage\") located at 4 Rue de la Préfecture in Besançon, France. It sells organic-leaning bulk food items — grains, legumes, spices, nuts — alongside seasonally sourced fresh fruit and vegetables, packaged foods, beverages, and household/hygiene and cosmetics products, all designed to be purchased without single-use packaging. The store offers both in-person and online ordering with delivery options."}, {"name": "Lemon and Lavender", "slug": "lemon-and-lavender", "country": "United States — Madison, Alabama", "categories": "consumer-education, refill, reusable-packaging", "priority": "★★★ Medium", "summary": "Lemon & Lavender was founded in 2021 in downtown Madison, Alabama, by local residents Shannon Fisher and Brandy Booth, who set out to build a retail shop centred on sustainability. Billed as \"North Alabama's first refillery,\" the store lets customers bring in their own containers to refill everyday products such as shampoo, body wash, laundry detergent and dish soap, alongside a curated selection of eco-conscious home, gift and pet products sold at its Main Street"}, {"name": "Lena the Fashion Library", "slug": "lena-the-fashion-library", "country": "Netherlands — Amsterdam", "categories": "consumer-education, rental, sharing, waste-reduction", "priority": "★★★★ High", "summary": "LENA the Fashion Library was conceived in 2013 and launched its pilot store in Amsterdam in December 2014, founded by three sisters — Angela, Diana and Elisa Jansen — together with Suzanne Smulders. It was the first combined online and offline clothing library in the Netherlands, distinguishing itself from occasion-wear rental competitors by focusing on everyday clothing. Over more than a decade of operation, LENA has outlasted many clothing-rental peers, refining its model into a"}, {"name": "Let it Green", "slug": "let-it-green", "country": "Mexico — Mexico City area", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "Let it Green describes itself as \"la tienda zero waste\" — a Mexican zero-waste store acting as a sales platform for products that are 100% plastic-free and environmentally friendly. It curates and sells goods from small Mexican producers sharing an environmental and social-responsibility ethos, including natural, vegan, plastic-free personal-care items, cruelty-free cosmetics with natural pigments, and reusable household alternatives such as silicone storage bags and bamboo cutlery sets."}, {"name": "Let's Get Naked Refill", "slug": "lets-get-naked-refill", "country": "United Kingdom (Launceston, Cornwall)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "Let's Get Naked Refill is a small independent refill shop located in the White Hart Shopping Arcade in Launceston, Cornwall. Founded by Jade Harvey after being furloughed from a cafe job during the pandemic, the shop lets customers bring their own containers (or use provided paper bags) to buy pantry staples such as pasta, rice, lentils and pulses, alongside refillable shampoo, conditioner and other health and beauty products. It represents a very small-scale, community-level example"}, {"name": "Libattion AG", "slug": "libattion-ag", "country": "Switzerland (Zurich; new upcycling facility in Biberist)", "categories": "digital-tracking, industrial-reuse, material-recovery", "priority": "★★★★ High", "summary": "Libattion AG is a Zurich-based company founded in 2018 that designs and manufactures modular Battery Energy Storage Systems (BESS) for commercial, industrial and utility-scale applications. Its core proposition is upcycling: it sources battery modules and cells that are discarded from EV production lines or come from end-of-life vehicles — often due to minor cosmetic defects or overproduction rather than technical failure — and repurposes them into stationary storage systems (branded E-Rack, E-Cabinet and E-Container) ranging"}, {"name": "Life Essentials Refillery", "slug": "life-essentials-refillery", "country": "United States (Tampa, Florida)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "Life Essentials Refillery is an independent refill shop and organic bulk-goods store founded by Sheila Haque, an entrepreneur with an MBA and over three decades of business experience. It operates from a South Tampa storefront (4317 W El Prado Blvd) with a second location in Wesley Chapel, Florida, plus an online store. The business was inspired by Haque's observations of plastic waste in Tampa Bay and her personal search for safe skincare products for her"}, {"name": "LifeBag", "slug": "lifebag", "country": "Kazakhstan (Almaty)", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "LifeBag is a manufacturer based in Almaty, Kazakhstan, producing reusable eco-bags made from spunbond, a non-woven polypropylene material. Its products — offered in t-shirt style, die-cut handle, and loop handle formats — are marketed as durable, reusable alternatives to single-use polyethylene bags, positioned as compliant with EU Directive 2004/12/EC on packaging and packaging waste. The company's stated mission, \"Let's preserve nature together,\" reflects a focus on reducing plastic bag consumption in Central Asia. Public information"}, {"name": "LimeLoop", "slug": "limeloop", "country": "United States (headquarters location reported variously as California/Arizona in secondary sources; not confirmed on official site)", "categories": "digital-tracking, reusable-packaging, reverse-logistics, waste-reduction", "priority": "★★★★ High", "summary": "LimeLoop provides reusable shipping mailers for e-commerce brands, designed to replace single-use cardboard boxes and poly mailers. Its mailers are made from upcycled billboard vinyl, built to withstand 20+ shipping cycles, and are returned by customers simply by dropping them in any mailbox — no label printing or post-office trip required. The company has been featured in outlets including TechCrunch, Forbes, Good Morning America and Fast Company, and counts sustainable apparel brands such as Toad&Co"}, {"name": "Lipton (Lipton Teas and Infusions, Pakistan)", "slug": "lipton", "country": "Pakistan (local market operations); global parent HQ in the Netherlands/UK region under Lipton Teas and Infusions", "categories": "consumer-education, refill", "priority": "★ Low relevance", "summary": "Lipton is a globally known tea brand founded in 1890, sold in Pakistan for decades under Unilever Pakistan before Unilever divested its global tea business (including Lipton) to CVC Capital Partners in 2022, forming \"ekaterra,\" which rebranded to \"Lipton Teas and Infusions\" in 2024. The Pakistan market operation (lipton.com/pk) markets packaged tea products and references sustainability commitments such as recyclable packaging and QR-code-enabled smart packaging for consumer engagement. No public evidence was found to substantiate"}, {"name": "Little Plant Pantry", "slug": "little-plant-pantry", "country": "Netherlands (Amsterdam)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "Little Plant Pantry is described as the first plastic-free, plant-based zero-waste bulk grocery store in Amsterdam, located at Bosboom Toussaintstraat 45 in Amsterdam West. It sells 100% vegan food ingredients — dried beans, legumes, grains, nuts, seeds, coffee and teas — with minimal or no packaging, alongside personal care and cleaning products and fresh items such as vegan cheese, nut milks and baked goods. Customers bring their own containers and bags to reduce packaging waste,"}, {"name": "Lizee", "slug": "lizee", "country": "France (Paris)", "categories": "digital-tracking, packaging-as-a-service, rental, reverse-logistics, sharing, take-back", "priority": "★★★★ High", "summary": "Lizee is a Paris-based software company founded in 2019 that provides a Rental Management System (RMS) enabling brands and retailers to launch rental and resale business models within a few weeks rather than building the capability in-house. Its platform manages the complete lifecycle of a rental or resale item — in-store and online booking, shipping, returns, refurbishment, restocking and eventual resale — through a single system. Lizee has worked with major retail and apparel names"}, {"name": "LocknLock", "slug": "locknlock", "country": "South Korea (Seoul)", "categories": "consumer-education, industrial-reuse, material-recovery, take-back", "priority": "★★★ Medium", "summary": "Lock & Lock (trading as LocknLock) is a large, publicly listed South Korean household-products manufacturer founded in 1978, known globally for its patented four-side locking system for airtight, leak-proof plastic food containers. Headquartered in Seoul, it exports to 119 countries through 11 overseas sales units and 87 directly operated overseas stores, with reported 2021 revenue of approximately US$418 million. Since 2020 it has run \"Love for Planet,\" an ongoing take-back and upcycling campaign that collects"}, {"name": "Lola", "slug": "lola", "country": "Switzerland (Bern)", "categories": "consumer-education, refill, sharing, waste-reduction", "priority": "★★ Low", "summary": "LOLA is an unpackaged, 100% vegan grocery store network in Bern, Switzerland, founded in 2017 as the first store in Bern to offer over 100 items package-free. It operates two neighbourhood locations — Lorraineladen and Mattenhof — plus an online shop and its own beverage line. Customers bring bags, tins and bottles to fill with grains, rice, nuts, detergent, cosmetics, and other bulk goods. The Lorraine store also hosts a community fridge for sharing surplus"}, {"name": "Loop", "slug": "loop", "country": "United States — Trenton, New Jersey (via parent TerraCycle, Inc.); commercially scaled operating markets are France and Japan", "categories": "consumer-education, deposit-return, packaging-as-a-service, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "Loop is a reusable-packaging platform conceived by TerraCycle and launched publicly at the World Economic Forum's Davos meeting in January 2019, with pilots beginning in Paris and New York that May. It lets consumer-goods brands sell products in durable, deposit-bearing containers (glass, steel, or engineered plastics) that customers return for cleaning and refilling rather than disposal. Backed at launch by dozens of major CPG companies, Loop has since narrowed sharply in scope: as of late"}, {"name": "LoopedIn", "slug": "loopedin", "country": "Singapore", "categories": "digital-tracking, material-recovery, reusable-packaging, reverse-logistics, take-back", "priority": "★★★★ High", "summary": "Loopedin is a Singapore-based \"eco-technology\" packaging company that enables food & beverage retailers and corporate clients to replace single-use plastic takeaway containers with a fully reusable, food-grade, recyclable inventory system. Each container carries an RFID chip and QR code, allowing customers to scan, locate the nearest return station via the Loopedin app, and drop off used containers for collection, sorting, sanitising and redistribution. At end-of-life, containers are recycled back into food-grade polymers. The company positions"}, {"name": "Loopfront", "slug": "loopfront", "country": "Norway", "categories": "digital-tracking, industrial-reuse, material-recovery, waste-reduction", "priority": "★★★★★ Essential", "summary": "Loopfront is a Norwegian company founded in 2018 by architect Michael Anthony Curtis and four co-founders, born from frustration with the lack of effective digital tools for reusing building materials. It has built what it describes as Norway's largest digital platform for the reuse of building materials and interiors, using AI-assisted surveying tools to give buildings a digital material inventory within days, then managing the full process — mapping, documentation, internal/external marketplace listing, logistics coordination,"}, {"name": "Looping", "slug": "looping", "country": "Norway (Fornebuveien 50, 1366 Lysaker)", "categories": "industrial-reuse, packaging-as-a-service, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Looping AS is a Norwegian company founded in 2017 by Jens Brustad after he observed construction and housing modules being wrapped in large volumes of disposable plastic at building sites. The company designs and supplies durable, reusable protective covers — branded Modulcover™ — for contractor modules, housing modules, and steel containers used in the construction and module-rental industries. Looping frames its offering as \"reuse as a service,\" leasing covers to clients rather than selling single-use"}, {"name": "Loopipak", "slug": "loopipak", "country": "Belgium (Rue Chapelle Emmanuel 11, 1435 Hévillers)", "categories": "digital-tracking, industrial-reuse, packaging-as-a-service, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Loopipak is a Belgian brand of Graine de Malice SRL that designs, manufactures and rents or sells reusable, trackable packaging for industrial and e-commerce logistics — replacing single-use cardboard boxes, stretch film, and protective wrapping with durable crates, covers and custom-built containers. A distinguishing feature is that its products are made from upcycled advertising banners and other end-of-life materials, and manufactured/repaired in sheltered workshops that provide stable employment to people with disabilities or those on"}, {"name": "Ma Bouteille S'appelle Reviens", "slug": "ma-bouteille-sappelle-reviens", "country": "France (11 rue Gauthier Lucet, 26120 Chabeuil, Drôme)", "categories": "consumer-education, deposit-return, reusable-packaging, reverse-logistics, waste-reduction", "priority": "★★★★ High", "summary": "Ma Bouteille s'appelle Reviens is a French deposit-return (consigne) network for glass bottles and jars, operated by the company Locaverre, created in November 2017 with its bottle-washing facility inaugurated in Chabeuil (Drôme) in July 2019. Consumers return used glass containers to participating shops and producers; Locaverre collects, washes and redistributes the standardized bottles for reuse by regional wine, beer, fruit juice and other food producers. The initiative operates mainly around Valence, in the Drôme and"}, {"name": "Maji Milele", "slug": "maji-milele", "country": "Kenya (Nairobi — Parklands Road 25, P.O. Box 14786, 00800 Westlands); parent Water Forever International based in the Netherlands", "categories": "consumer-education, digital-tracking, refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Maji Milele is the Kenyan brand of Water Forever, a for-profit social enterprise founded in 2013 that installs and operates smart, prepaid water ATMs (communal water meters) across East Africa. The system lets communities and households pay via mobile money for water dispensed on demand, typically used to refill jerrycans, replacing costly or unreliable alternatives such as bottled/trucked water or unsafe informal sources. Water Forever's network extends into Uganda, South Sudan and Rwanda in addition"}, {"name": "Mapeei Colab", "slug": "mapeei-colab", "country": "Brazil (São Paulo — Rua Lisboa, 568, Pinheiros)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Mapeei Colab describes itself as Brazil's first \"zero waste\" retail space, opened in late 2018 in São Paulo (initially on Rua Augusta) as \"Mapeei — Uma Vida Sem Plástico\" by co-founders Lívia and designer Lori Vargas, before relaunching under an expanded curated-marketplace format, Mapeei Colab Sustentável, at a new Pinheiros address. The store/online platform curates and sells products from a large number of Brazilian sustainable brands, artisans and small businesses spanning home goods, cosmetics, wellness,"}, {"name": "Maria Granel", "slug": "maria-granel", "country": "Portugal (Lisbon — stores in Alvalade and Campo de Ourique)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Maria Granel is described as the first \"zero waste store\" in Portugal and among the pioneers of the bulk/package-free retail model in Europe. Founded by Eunice Maia and her husband, with the concept conceived in 2013 and the first store opened in 2015 in Lisbon, it sells organic and bulk products — grains, dried fruits, coffee, cleaning and personal-care items — dispensed by customers directly from bulk dispensers, evoking traditional neighbourhood groceries but with a"}, {"name": "Matterpieces", "slug": "matterpieces", "country": "Portugal (Porto)", "categories": "industrial-reuse, material-recovery, waste-reduction", "priority": "★★★ Medium", "summary": "Matterpieces is a Portuguese startup, founded in 2021 and headquartered in Porto, that converts construction and demolition (C&D) waste into decorative cladding and surface materials for architecture and interior design. Rather than a reusable-components or scaffolding provider, the company operates as a materials-upcycling business: debris sourced from demolition sites and waste-management partners is processed into two composite material collections (\"Matter\" and \"Nebula\"), sold as standard catalogue products or custom-developed from a client's own demolition waste."}, {"name": "Meadow", "slug": "meadow", "country": "Sweden (Stockholm), with a second office in London, UK", "categories": "material-recovery, packaging-as-a-service, refill, reusable-packaging", "priority": "★★★★ High", "summary": "Meadow is a Swedish packaging-technology startup, founded in 2020 and based in Stockholm (with a London office), that has reengineered the standard aluminium beverage can into a refillable format branded MEADOW KAPSUL™. Aluminium cans (available from 250ml to 568ml) are filled with products such as shampoo, soap or other liquid consumer goods and inserted as swappable cartridges into a reusable dispenser, combining the widely recyclable material properties of aluminium with a refill-based reuse system. Meadow"}, {"name": "Megloo", "slug": "megloo", "country": "Japan (Tokyo); pilot originated in Kamakura", "categories": "digital-tracking, reusable-packaging, reverse-logistics, sharing, take-back, waste-reduction", "priority": "★★★★ High", "summary": "Megloo is a reusable takeaway-container sharing service in Japan, operated by the company Kaman and launched as a pilot in November 2022, originating in Kamakura before expanding to Tokyo and other locations. Its name derives from the Japanese word for \"circulation\" (megaru/meguru). Customers order takeaway food at participating restaurants and food trucks, receive it in a durable reusable container tracked via the LINE messaging app, and return the container at the restaurant or a designated"}, {"name": "Meliora Cleaning Products", "slug": "meliora-cleaning", "country": "United States — Chicago, Illinois", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★★ High", "summary": "Meliora Cleaning Products is a Chicago-based, woman-owned B Corp founded in 2013 by Kate Jakubas (COO) and Mike Mayer (President), manufacturing eco-friendly cleaning products — laundry detergents, oxygen brighteners, home cleaning sprays/scrubs, and personal-care soaps — at its own West Side Chicago factory. The company is distinguished by its \"All Ingredients Listed, Right on the Label\" policy, disclosing 100% of ingredients, and successfully lobbied for California's SB-258, making California the first US state to require"}, {"name": "Melodea", "slug": "melodea", "country": "Israel (European operations/domain suggest EU presence as well)", "categories": "material-recovery", "priority": "★★ Low", "summary": "Melodea develops water-based barrier coating technology — including MelOx NGen (an ultra-high oxygen barrier) and VBseal (a high water-vapour barrier) — designed to make packaging 100% recyclable while maintaining performance, targeting food, pharmaceutical, and cosmetics industries. The coatings are PTS and CEPI certified for sustainability. The seed tracker's description of these coatings as enabling \"reuse\" is not strongly supported — the verified focus is recyclability and barrier performance, not a reuse-loop mechanism."}, {"name": "Meow Meow Tweet", "slug": "meow-meow-tweet", "country": "United States — Brooklyn, New York", "categories": "consumer-education, material-recovery", "priority": "★★ Low", "summary": "Meow Meow Tweet is a Brooklyn-based vegan, all-natural personal-care brand founded in 2009 by Jeff Kurosaki and Tara Pelletier, who met in art school. The brand's product line spans soap, natural insect repellent, deodorant, and a full facial-care regimen, using plant- and mineral-based formulas developed with Tara's background as a chef and herbalist. The company is a Certified B Corporation and is credited as the first company to popularize the zero-waste deodorant stick, packaged in"}, {"name": "Mercado Circular", "slug": "mercado-circular", "country": "Chile (Valparaíso); operations expanding to Mexico and other Latin American markets", "categories": "consumer-education, digital-tracking, refill, reverse-logistics", "priority": "★★★ Medium", "summary": "Mercado Circular is a Chilean circular-economy technology company founded in 2017 in Valparaíso. It designs and operates refill vending machines and accompanying software that let consumers purchase products such as cleaning and personal-care items into reusable containers instead of buying new single-use packaging each time. The company positions itself as a \"reuse solutions\" provider, working with retailers, municipalities, shopping centers, and consumer goods brands across Chile and, more recently, Mexico. Note: seed data listed Mexico"}, {"name": "Method", "slug": "method", "country": "United Kingdom (UK market operations); global parent HQ in San Francisco, California, USA", "categories": "consumer-education, material-recovery, refill, reusable-packaging", "priority": "★★★ Medium", "summary": "Method was founded in 2001 in San Francisco by Eric Ryan and Adam Lowry to make design-led, non-toxic home and personal care products, selling its first item in February 2001. The brand expanded into the UK market and was acquired by SC Johnson in 2017 alongside Belgian eco-brand Ecover. In the UK, Method sells cleaning, hand soap, and laundry products, with a growing range offered in refill pouch formats designed to cut plastic and water/energy"}, {"name": "Meu Copo Eco", "slug": "meu-copo-eco", "country": "Brazil", "categories": "rental, reusable-packaging, reverse-logistics, waste-reduction", "priority": "★★★ Medium", "summary": "Meu Copo Eco was created in Brazil in 2011 with the goal of replacing disposable cups across everyday settings — events, shows, festivals, schools, offices, and cafeterias — with a reusable, personalized \"Copo Eco\" cup. The company manufactures, customizes, sells, rents, and sanitizes its polypropylene cups, which are BPA-free, dishwasher/microwave/freezer safe, and treated with an antimicrobial additive. It markets itself as having eliminated billions of disposable cups from circulation since launch, primarily through the events"}, {"name": "Mi Barrio Sin Residuos", "slug": "mi-barrio-sin-residuos", "country": "Paraguay (Asunción)", "categories": "consumer-education, material-recovery, reverse-logistics, waste-reduction", "priority": "★★ Low", "summary": "Mi Barrio Sin Residuos (\"My Neighbourhood Without Waste\") is a household recycling pilot launched in Asunción, Paraguay on World Recycling Day 2021, under the UNDP-led Asunción Sustentable Project. It links residents in five Asunción neighbourhoods directly with the San Francisco Neighbourhood Recyclers Association, a cooperative of informal waste pickers, via a differentiated (source-separated) collection service. The initiative pairs technology (a simple registration platform) with in-person collection to build trust between households and recyclers, aiming to"}, {"name": "Migros", "slug": "migros", "country": "Turkey (Istanbul)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Migros Ticaret A.Ş. was established in Istanbul in 1954 through a joint initiative of the Swiss Migros Cooperative Federation and the Istanbul Municipality, modeled on the Swiss Migros retail concept. It has grown into one of Turkey's largest supermarket chains and has been publicly traded on Borsa Istanbul since 1991 (ticker MGROS). As part of its sustainability program, Migros partnered with Unilever's OMO detergent brand to pilot in-store refill units, letting customers refill empty liquid"}, {"name": "Milch Mehrweg Pool (MMP e.V.)", "slug": "milch-mehrweg-pool", "country": "Germany", "categories": "deposit-return, industrial-reuse, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "The Milch Mehrweg Pool traces back to a reusable glass-bottle pooling system established by the German dairy industry in the 1980s for milk bottles and yoghurt jars. The original pool was disbanded in 2008 but was revived in 2022 under the name \"Mach Mehrweg Pool\" (MMP e.V.), continuing the tradition with standardized reusable glass containers now open to a broader range of food products beyond dairy. The pool coordinates manufacturers, retailers, and logistics providers around"}, {"name": "Milly & Sissy", "slug": "milly-and-sissy", "country": "United Kingdom (Newark, Nottinghamshire — registered office)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "Milly & Sissy is a UK skincare brand founded by two friends with backgrounds in beauty-industry product management and healthcare, incorporated as Milly&Sissy Ltd on 16 August 2019. The company's core innovation is selling personal-care products — hand wash, body wash, and shampoo — as powders in compostable sachets, which customers mix with water at home in a reusable bottle rather than buying pre-mixed liquid in plastic packaging each time. This \"use and refill\" powder"}, {"name": "Mind the Trash", "slug": "mind-the-trash", "country": "Portugal — Lisbon", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Mind the Trash is described as Portugal's first online zero-waste store (\"1ª Loja online desperdício zero em Portugal\"), founded in 2017 in Lisbon by Catarina Matos and Christian Andersen, with the brand's social media presence dating back to 2016 in London. The company sells sustainable alternatives across home goods, kitchen items, cosmetics, cleaning supplies, stationery, baby products, and personal care, both to individual consumers and via wholesale resale to shops nationally and internationally."}, {"name": "MiniMakers", "slug": "minimakers", "country": "Singapore", "categories": "consumer-education, material-recovery, reusable-packaging", "priority": "★★★ Medium", "summary": "Minimakers is described as Singapore's largest manufacturer of beeswax wraps — a reusable, compostable alternative to plastic cling film and food storage bags. Beyond its product line, the company runs a distinctive social mission: since 2021, it has partnered with the Autism Resource Center to redesign its manufacturing process specifically to employ individuals on the autism spectrum, positioning itself as building \"a collective of makers, designers that supports differently abled artisans through shared employment.\""}, {"name": "Minimal Waste Grocery", "slug": "minimal-waste-grocery", "country": "Ireland", "categories": "refill, waste-reduction", "priority": "★★ Low", "summary": "Minimal Waste Grocery is an Irish zero-waste delivery service, founded autumn 2019, supplying plastic-free pantry staples and household goods sourced from small Irish producers, organic where possible."}, {"name": "Minimize", "slug": "minimize-zero-waste-store", "country": "Malaysia — Subang Jaya, Selangor", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "Minimize is a Subang Jaya, Malaysia-based retail store founded in 2021 by Jayne and Tan, specialising in eco-friendly and refillable products for waste reduction. The founders frame their approach around incremental, sustainable behaviour change rather than requiring customers to adopt zero-waste practices all at once, serving residents across Subang Jaya, the wider Klang Valley, and Malaysia more broadly."}, {"name": "Miniml", "slug": "miniml", "country": "United Kingdom — Yorkshire", "categories": "consumer-education, material-recovery, refill, reusable-packaging", "priority": "★★★★ High", "summary": "Miniml is a Yorkshire, UK refill brand founded by Emma, who started the company after experiencing sensitive skin and questioning why everyday cleaning and personal-care products often contain ingredients she wouldn't otherwise choose. Described as \"built in Yorkshire and grown from a garage start-up,\" the company manufactures its own natural (99%+), vegan, cruelty-free products in-house at its UK factory, sold in \"forever-bottles\" designed to be refilled repeatedly, made from 100% post-consumer recycled plastic. Miniml reports"}, {"name": "Minus Zero Waste Store", "slug": "minus-zero-waste-store", "country": "Malaysia (Johor Bahru)", "categories": "consumer-education, material-recovery, refill, reverse-logistics, waste-reduction", "priority": "★★ Low", "summary": "Minus Zero Waste Store is a female-founded, Johor Bahru-based online retailer selling zero-waste personal care, feminine hygiene, and kitchen products. Founded in September 2019 by Cassey Goh, the store built its model around eliminating single-use plastic packaging entirely, relying instead on upcycled and reused cardboard for shipping. It is recognised within Malaysia's zero-waste community and has been profiled as a case study by Zero Waste Malaysia."}, {"name": "Mio Bio (MioBio)", "slug": "mio-bio", "country": "Romania (Bucharest)", "categories": "consumer-education, waste-reduction", "priority": "★ Low relevance", "summary": "MioBio is a Bucharest-based retailer of organic and natural cosmetics, founded in 2009 by Ioana Paun and Alma Rusu. It operates both a physical boutique in central Bucharest and an e-commerce platform, curating over 50 organic personal-care brands from Romania and internationally. Note: the seed data's country attribution of \"Denmark\" is incorrect — the .ro domain and all sourced content confirm the company is Romanian, based and operating in Bucharest."}, {"name": "Mission Reuse", "slug": "mission-reuse", "country": "Netherlands (Rotterdam)", "categories": "consumer-education, packaging-as-a-service, reusable-packaging, reverse-logistics", "priority": "★★★ Medium", "summary": "Mission Reuse is a Dutch transition program, not a standalone commercial B2B packaging company as the seed data suggested — it is a collaborative non-profit initiative launched around 2020 by social enterprise Enviu together with Recycling Netwerk Benelux and Natuur & Milieu (under the Fair Resource Foundation umbrella). Based in Rotterdam, its mission is to make reusable products and packaging \"the norm\" in daily life across the Netherlands and Belgium, working through pilots, policy advocacy,"}, {"name": "Mission Zero (Refill Revolution)", "slug": "mission-zero-refill-revolution", "country": "New Zealand", "categories": "consumer-education, refill, reusable-packaging", "priority": "★★ Low", "summary": "Refill Revolution is a nationwide New Zealand campaign and toolkit, launched in February 2023, encouraging producers, retailers and consumers to adopt refill practices instead of single-use packaging. It sits under Mission Zero, a climate-action programme for businesses, and was initiated by Abbie Tebbutt (Chia Sisters) together with Caitlin Attenburrow and Kate Robertson (Pic's Peanut Butter). Rather than operating its own refill infrastructure, it functions as an advocacy and coordination initiative that supports and publicises existing"}, {"name": "MIWA", "slug": "miwa", "country": "Czechia — Prague (registered office: Plynární 1617/10, Praha 7; operational HQ: Truhlářská 1119/20, Praha 1)", "categories": "digital-tracking, packaging-as-a-service, refill, reusable-packaging, reverse-logistics, waste-reduction", "priority": "★★★★★ Essential", "summary": "MIWA Technologies, a.s. is a Prague-based company that builds a \"smart reuse\" ecosystem for selling dry food and household products without single-use packaging. Founded by CEO Petr Báča, the company supplies durable, chip-equipped B2B capsules and electronic in-store dispensers to retailers, alongside a consumer-facing app and reusable smart cups. It has run paid pilots and commercial installations with European grocery chains including REWE, Aldi (UK), Albert Heijn, and dm-drogerie markt, and has received significant blended"}, {"name": "Miya (Miya Cosmetics)", "slug": "miya", "country": "Poland", "categories": "consumer-education, waste-reduction", "priority": "★ Low relevance", "summary": "Miya Cosmetics is a Polish natural cosmetics brand founded around 2014-2015, producing skincare, haircare, lip care, and intimate hygiene products marketed around low environmental impact and recyclable packaging. In 2021 the company (operated under Kanani Europe) was acquired by investment firm TDJ together with beauty-industry veteran Leszek Klosinski, who became board chairman, as part of a strategy to scale cosmetics brands with export and consolidation potential. Since the acquisition, Miya has expanded its portfolio to"}, {"name": "Moon Berry Made (Moonberry Mercantile and Trading)", "slug": "moon-berry-made", "country": "United States (Tarpon Springs, Florida)", "categories": "consumer-education, refill, waste-reduction", "priority": "★ Low relevance", "summary": "The website moonberrymade.com now operates as \"Moonberry Mercantile and Trading,\" a physical natural-living general store based in Tarpon Springs, Florida, rather than the generic \"eco-friendly consumer products\" company described in the seed data. The shop sells raw dairy, locally-sourced meat, organic sourdough, apothecary items, and craft-kitchen goods, and includes a refillery offering for non-toxic household cleaning products. Public information about the business's founding date, founder, and detailed history is very limited."}, {"name": "moreloop", "slug": "moreloop", "country": "Thailand", "categories": "industrial-reuse, material-recovery, reverse-logistics", "priority": "★★★ Medium", "summary": "Moreloop is a Thai online marketplace, co-founded 2018, matching garment factories' surplus/deadstock fabric with buyers and upcycling scraps into new products — founder Thamonwan noticed leftover fabric piling up at her family's garment factory."}, {"name": "Mosaiq Group", "slug": "mosaiq-group", "country": "Italy — Milan", "categories": "reusable-packaging", "priority": "★★★ Medium", "summary": "Mosaiq Group was formed in 2024 uniting five Italian luxury-packaging companies (Bulgarelli Production 1970, Valtenna 1963, Brand Label 2009, D'Auria 1966, CoRi Sacchettificio 1985), reaching €70M annual turnover with 300 employees, serving luxury brands including EssilorLuxottica, Gucci, Valentino, Fendi, Prada, and Dior."}, {"name": "Mottainai Refill", "slug": "mottainai-refill", "country": "Colombia — Medellín", "categories": "refill, waste-reduction", "priority": "★★ Low", "summary": "Mottainai Refill is a Medellín, Colombia startup refilling household and personal-hygiene products, aiming to reduce single-use plastic via a home-refill delivery model, using Instagram (6,100+ followers) as its primary customer-engagement and scheduling platform."}, {"name": "MovoPack", "slug": "movopack", "country": "Italy — Milan", "categories": "digital-tracking, packaging-as-a-service, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "Movopack is a Milan-based B2B reusable packaging-as-a-service platform designing custom packaging for retail, e-commerce, B2B logistics, and large appliances, managing return logistics (pre-paid labels, QR-coded drop-off locators) and cleaning/redistribution. Reports serving 100+ brands including Legami, Decathlon, and R5."}, {"name": "Muji", "slug": "muji", "country": "Japan", "categories": "refill, waste-reduction", "priority": "★★★ Medium", "summary": "Muji originated in December 1980 as a product brand of supermarket chain The Seiyu, launching with 40 products across apparel, household goods, and food, and has since grown into the global Ryohin Keikaku retail company. Select flagship stores offer refill stations for liquid detergent and weight-based pantry staples."}, {"name": "Multi Pack", "slug": "multi-pack", "country": "Pakistan", "categories": "industrial-reuse, material-recovery", "priority": "★★★ Medium", "summary": "Multi Pack, established 2007, is described as Pakistan's leading manufacturer/exporter of industrial plastic products — crates, pallets, buckets, garbage bins, drums/jerry cans — serving food, agri, dairy, textile, and auto-parts manufacturers."}, {"name": "Muuse", "slug": "muuse", "country": "Singapore", "categories": "digital-tracking, packaging-as-a-service, reusable-packaging, reverse-logistics", "priority": "★★★★★ Essential", "summary": "Muuse is a Singapore-based reuse-as-a-service company founded in 2018 after its co-founders witnessed takeaway packaging waste while surfing in Bali. It provides QR-tagged reusable cups and containers to F&B businesses as an alternative to single-use packaging, tracking each item through its lifecycle."}, {"name": "MuvMi", "slug": "muvmi", "country": "Thailand (Bangkok)", "categories": "sharing", "priority": "★★ Low", "summary": "MuvMi was founded in 2016 by Krisada Kritayakirana, Pipat Tangsiripaisan and Supapong Kitiwattanasak, launching its ride-hailing app for electric tuk-tuks in 2018. It operates a fleet of 600+ electric tuk-tuks across roughly 12 Bangkok neighbourhoods, connecting riders to mass-transit hubs."}, {"name": "My Green Pod", "slug": "my-green-pod", "country": "United Kingdom", "categories": "consumer-education, refill", "priority": "★★★ Medium", "summary": "My Green Pod is an independent UK media and marketplace platform founded in 2013 by Katie Hill and Jarvis Smith to promote ethical, sustainable living. It curates and sells vetted eco-friendly brands, including refillable beauty products, through its online marketplace and editorial content."}, {"name": "My Naked Bar", "slug": "my-naked-bar", "country": "Singapore", "categories": "waste-reduction", "priority": "★★ Low", "summary": "My Naked Bar is a Singaporean indie brand producing handcrafted, cold-process vegan soap bars, marketed for sensitive skin (eczema/psoriasis-friendly) and sold in upcycled milk cartons to reduce packaging waste. It also runs private soap-making workshops."}, {"name": "MyEarth (L'earth)", "slug": "myearth", "country": "Singapore (with operations in Vietnam via Learth Vietnam Joint Stock Company)", "categories": "material-recovery, waste-reduction", "priority": "★★ Low", "summary": "MyEarth (trading as L'earth/Mylearth) is a Singapore-headquartered company producing bio-composite and green-technology packaging products, with award recognition at the WorldStar Packaging Awards (2015) and Asia Star Awards (2014). It also operates in Vietnam through a joint-stock subsidiary."}, {"name": "mymizu Philippines", "slug": "mymizu-ph", "country": "Philippines (usage); parent organisation based in Japan", "categories": "consumer-education, digital-tracking, refill", "priority": "★★★ Medium", "summary": "mymizu PH refers to Philippines use of the mymizu app (see mymizu.md for the parent organisation, founded in Japan in 2019). Search research found no confirmed dedicated \"Philippines chapter\" entity, legal structure, or launch date — mymizu's own materials mention confirmed local chapters/teams in Japan and Singapore, with expansion into further markets planned, but the Philippines was not specifically named in the sources reviewed."}, {"name": "mymizu", "slug": "mymizu", "country": "Japan (Tokyo)", "categories": "consumer-education, digital-tracking, refill", "priority": "★★★★★ Essential", "summary": "mymizu was co-founded by Robin Lewis and Mariko McTier, launching as Japan's first free water-refill app in September 2019 under nonprofit Social Innovation Japan. It maps public water fountains and partner cafes/shops/hotels where users can refill bottles for free, reducing single-use PET bottle consumption."}, {"name": "Myro", "slug": "myro", "country": "United States", "categories": "refill", "priority": "★★ Low", "summary": "Myro launched in fall 2018 as a direct-to-consumer refillable deodorant subscription brand, amassing a 16,000-person waitlist at launch. The company ceased operations in 2022, citing unsustainable costs and ongoing supply chain issues, and issued refunds to active subscribers."}, {"name": "Naber si", "slug": "naber-si", "country": "Czechia (Prague 7)", "categories": "consumer-education, refill", "priority": "★★ Low", "summary": "Naber si was a package-free zero-waste retail store in Prague 7, Czechia, offering roughly 400 food products and 250 drugstore/cosmetic items sold without packaging. The website now displays \"trvalé uzavřeno\" (permanently closed), indicating the business has ceased operations."}, {"name": "Nashonuma", "slug": "nashonuma", "country": "Pakistan (Lahore)", "categories": "consumer-education, waste-reduction", "priority": "★★ Low", "summary": "Nashonuma describes itself as Pakistan's first environment-friendly, eco-driven e-commerce store, delivering biodegradable, compostable and reusable products nationwide, including reusable stainless-steel and bamboo straws and sustainable food packaging out of Lahore."}, {"name": "Natura", "slug": "natura", "country": "Brazil (São Paulo)", "categories": "refill, waste-reduction", "priority": "★★★★★ Essential", "summary": "Natura was founded in 1969 by Antônio Luiz Seabra and is now part of Natura &Co, a publicly listed Brazilian global personal-care group. Natura was the first Brazilian cosmetics company to offer product refills, a program it has run for over 40 years and modernised using sugarcane-based renewable plastics since 2010."}, {"name": "Natural Living", "slug": "natural-living", "country": "Denmark (Roskilde)", "categories": "consumer-education, reusable-packaging", "priority": "★★★ Medium", "summary": "Natural Living is a Danish web shop selling aesthetic, sustainable everyday and wellness products, with an emphasis on reusable, plastic-free kitchen goods such as drink bottles, reusable coffee capsules, lunch boxes and household items. It ships using FSC-certified and recycled packaging materials."}, {"name": "Naturals by Watsons", "slug": "naturals-by-watsons", "country": "Hong Kong (A.S. Watson Group HQ); refill stations documented in Malaysia", "categories": "refill, reusable-packaging", "priority": "★★★★ High", "summary": "Naturals by Watsons is a personal-care product line under A.S. Watson Group's Watsons retail chain, featured in the group's \"Refill for a Better Tomorrow\" sustainability initiative. Confirmed reporting documents a Naturals by Watsons refill station launched in Sunway Pyramid, Malaysia, rather than Hong Kong specifically."}, {"name": "Natures Organics", "slug": "natures-organics", "country": "Australia (Ferntree Gully, Victoria)", "categories": "refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Natures Organics is an Australian-made, family-owned manufacturer of cleaning and personal-care products, run by the Dowel family. Its roots trace to Terry Dowel's father's company Trydel Research, a contract-filling bath-cube manufacturer; the business was renamed Natures Organics in 1991 when Justin Dowel joined."}, {"name": "Neat (Neat Essentials / neat.)", "slug": "neat", "country": "United Kingdom", "categories": "refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Neat (branded \"neat.\" and also referred to as \"Neat Essentials\") is a UK-made, plant-based refillable cleaning-products company. It replaces single-use bottles with reusable aluminium spray bottles and small concentrated refills, aiming to cut plastic and water waste from shipping."}, {"name": "Net Zero Co.", "slug": "net-zero-co", "country": "United States", "categories": "reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Net Zero Co. is a US brand selling reusable, non-toxic household products, founded after its creators were prompted by concern over plastic straw waste. In 2023, Tru Earth acquired Net Zero Co., combining it with Basic Goods Trading Co. to form the Eco-Collective online marketplace."}, {"name": "Netpak Ambalaj", "slug": "netpak-ambalaj", "country": "Turkey (Istanbul)", "categories": "reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Netpak Ambalaj, incorporated in 1998 and headquartered in Istanbul, is a leading Turkish manufacturer of nonwoven bags, woven bags, ultrasonic nonwoven bags and laminated eco-friendly bags. It holds a leading domestic market position and exports to roughly 40 countries across five continents."}, {"name": "New ERA (New European Reuse Alliance)", "slug": "new-era", "country": "Belgium (Brussels/Ixelles)", "categories": "consumer-education, reusable-packaging", "priority": "★★★★ High", "summary": "New ERA is the leading EU trade association representing businesses across the reuse value chain — manufacturing, logistics, washing, digital tracking and service provision. Founded in 2022 by nine pioneering members, it now represents over 80 businesses and associations promoting refillable and reusable packaging in the circular economy."}, {"name": "No Tox Life", "slug": "no-tox-life", "country": "United States (Austin, Texas)", "categories": "refill, waste-reduction", "priority": "★★★ Medium", "summary": "No Tox Life is a US-based (not UK as seed data suggested) vegan personal-care and home-cleaning brand manufacturing in a solar-powered North American facility. It focuses on plastic-free formats and has extended into refillable products, including a refillable deodorant with a low-plastic refill capsule."}, {"name": "Noms", "slug": "noms", "country": "Ireland (Dublin)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Noms is a Dublin (Phibsborough) organic and zero-waste grocery store certified by the Organic Trust. It stocks bulk dry goods, plant-based foods, and household/cleaning products, with roughly 99% of its range available refill-style via customer-supplied or in-store containers."}, {"name": "NOPA Move", "slug": "nopa-move", "country": "Vietnam (Ho Chi Minh City)", "categories": "consumer-education, reusable-packaging, sharing", "priority": "★★★ Medium", "summary": "NOPA Move designs and produces a modular, double-wall vacuum-insulated reusable bottle/tumbler in Vietnam for the Southeast Asian market, aimed at replacing single-use cups. It also runs a \"sustainable lifestyle platform\" rewarding users for bringing their bottle to partner cafés and wellness spaces across HCMC."}, {"name": "Nourishing Neighbours", "slug": "nourishing-neighbours", "country": "Australia (Hadfield, Melbourne, Victoria)", "categories": "waste-reduction", "priority": "★★ Low", "summary": "Nourishing Neighbours is a 100% volunteer-run charity founded in 2020 serving Moreland (Melbourne) and surrounding areas, providing culturally safe emergency food relief, toiletries and period products to people experiencing food insecurity, via referral-only access."}, {"name": "Nude Foods", "slug": "nude-foods", "country": "South Africa (Cape Town)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★★ High", "summary": "Nude Foods is a Cape Town plastic-free grocery chain founded by Paul Rubin in 2017, offering bulk/refill wholefoods, organic local produce, and zero-waste home and body-care products. It has expanded to multiple locations (Zonnebloem, Newlands) plus an in-store café and apothecary."}, {"name": "Nuhun Ambarı", "slug": "nuhunambari", "country": "Turkey", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "Nuhun Ambarı describes itself as Turkey's first organic products store, bringing together organic producers nationwide (under its Orgagen Ambarı brand). It emphasises cloth bags, reusing packaging/boxes, and minimising waste throughout its supply chain rather than operating as a dedicated \"zero-waste shop\" per seed data."}, {"name": "NULL Zero Waste Factory", "slug": "null-zero-waste-factory", "country": "Malaysia (Kuala Lumpur)", "categories": "consumer-education, refill, take-back", "priority": "★★★★ High", "summary": "NULL Zero Waste Factory operates refill dispensing stations for liquids (cleaning and personal-care products) across shopping malls in Malaysia's Klang Valley, launched in 2019. It encourages customers to bring their own containers, and reuse glass bottles where provided, avoiding new packaging."}, {"name": "Numafa Cleaning & Automation", "slug": "numafa", "country": "Netherlands (Heinenoord)", "categories": "industrial-reuse, reusable-packaging", "priority": "★★★★ High", "summary": "Numafa is a top-three global manufacturer of industrial cleaning and handling systems for reusable product carriers — crate washers, pallet washers, container washers and layer-pad washers — serving food and non-food industries worldwide from its Netherlands base."}, {"name": "Nuud", "slug": "nuud", "country": "Netherlands (Utrecht) — corrected from seed's \"Sweden\"", "categories": "refill, waste-reduction", "priority": "★★★ Medium", "summary": "Nuud is a Netherlands-founded (not Swedish, per seed data) natural deodorant brand created by Martijn van Seters in 2017. Its cream anti-odorant, packaged in a bioplastic sugarcane tube, uses microsilver and zinc oxide and is designed to last 3–7 days per application, sold globally with a UK-specific storefront."}, {"name": "O Cantinho do AL", "slug": "o-cantinho-do-al", "country": "Portugal", "categories": "refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "O Cantinho do AL supplies amenities, signage and complementary products to Portugal's \"Alojamento Local\" (short-term rental) and hotel sector, including branded product lines (Aroma de Portugal, Atlântico, Saudade, Luxury) with 5-litre refill formats for shampoo, shower gel, liquid soap and body lotion."}, {"name": "O Granel da Sofia", "slug": "o-granel-da-sofia", "country": "Portugal (Loures)", "categories": "refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "O Granel da Sofia is an organic and bulk grocery store in Loures, Portugal, offering food staples (cereals, spices, legumes, chocolates) plus bulk cleaning and cosmetic products. It prioritises national producers and actively promotes a bring-your-own-container (BYOC) refill system."}, {"name": "Oaklands Farm (Oaklands Milk)", "slug": "oaklands-farm", "country": "New Zealand (Nelson/Tasman)", "categories": "deposit-return, refill, reusable-packaging", "priority": "★★★★ High", "summary": "Oaklands Farm is a family-owned dairy farm near Nelson, New Zealand (owned by the Saxton/Raine family since 1842) that bottles fresh A2 milk in glass and sells it through home delivery, retail stockists, and self-service vending machines in Nelson, Tasman and Marlborough."}, {"name": "Oasis Packaging Industries", "slug": "oasis-packaging-industries", "country": "Pakistan (Lahore)", "categories": "reusable-packaging", "priority": "★★ Low", "summary": "Oasis Packaging Industries is a Lahore-based flexible packaging manufacturer founded in 2012, producing films, poly bags and custom pouches for industrial and consumer clients. Among its pouch formats it offers reusable, zip-lock-closure pouches with hanger holes and loop handles alongside conventional single-use packaging lines."}, {"name": "Ocean Lanka", "slug": "ocean-lanka", "country": "Sri Lanka (Biyagama Export Processing Zone, Malwana)", "categories": "industrial-reuse, reusable-packaging, reverse-logistics", "priority": "★★★ Medium", "summary": "Ocean Lanka, founded in 1996, is Sri Lanka's largest weft-knitted fabric manufacturer, supplying international apparel brands including Nike, GAP, Uniqlo and Marks & Spencer. It was the first Sri Lankan textile/apparel manufacturer to partner with bluesign® on sustainable production."}, {"name": "OceanSaver", "slug": "oceansaver", "country": "United Kingdom (Leeds)", "categories": "refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "OceanSaver is a UK eco-cleaning brand producing concentrated, plant-based, water-soluble cleaning pods (\"EcoDrops\") that dissolve into a reusable spray bottle with water, eliminating repeat plastic bottle purchases. Founded in Leeds, the company recently raised further growth funding (reported December 2025)."}, {"name": "Öko Créations", "slug": "oko-creations", "country": "Canada (Boisbriand, Québec)", "categories": "reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Öko Créations is a women-led, family-run Quebec business manufacturing reusable menstrual pads, period underwear, and hemp-fleece makeup-removal pads, all produced domestically at its Boisbriand workshop rather than imported."}, {"name": "Økofamilien", "slug": "okofamilien", "country": "Denmark", "categories": "reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Økofamilien is a small Danish family business running a webshop for organic, plastic-free and chemical-free household, personal-care and lifestyle products. It ships customer orders using RE-ZIP, a circulating reusable shipping-packaging system, rather than single-use boxes."}, {"name": "OMO", "slug": "omo", "country": "Turkey (brand); Unilever global HQ London/Rotterdam", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "OMO is Unilever's international laundry detergent brand, sold in Turkey under Unilever's \"Dirt is Good\" portfolio. It is a mass-market FMCG brand rather than a dedicated reuse company, with recent sustainability efforts focused on recycled-content packaging."}, {"name": "Ong Hut Co", "slug": "ong-hut-co", "country": "Vietnam (Ho Chi Minh City / Mekong Delta)", "categories": "consumer-education, waste-reduction", "priority": "★★ Low", "summary": "Ong Hut Co produces drinking straws from Lepironia articulata (grey sedge grass) harvested wild in Vietnam's Mekong Delta wetlands. The straws are biodegradable, chemical-free, and sold fresh or dried as a plastic-straw alternative."}, {"name": "OPA", "slug": "opa", "country": "Israel (Tel Aviv)", "categories": "digital-tracking, reusable-packaging, reverse-logistics", "priority": "★★ Low", "summary": "OPA was founded by former Wolt executives Ran Doron and Dar Hasson to tackle single-use takeout waste in Tel Aviv, where an estimated seven million disposable containers were discarded monthly. It offered reusable, recyclable bowls returnable via dedicated collection bins."}, {"name": "OPACK", "slug": "opack", "country": "Malaysia (Puchong)", "categories": "consumer-education, digital-tracking, packaging-as-a-service, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "OPACK is described as Malaysia's first operator of reusable cup and food container systems, providing a \"rentNreturn\" service to replace single-use plastic foodware for events, catering and canteens, paired with digital tracking and an ESG dashboard."}, {"name": "ORBIS Europe", "slug": "orbis-europe", "country": "Poland (also operations in Germany, e.g. ORBIS GmbH, Hürth)", "categories": "industrial-reuse, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "ORBIS Europe develops and manufactures reusable transport packaging — foldable large containers (FLCs), pallets and specialty load carriers — for industrial, food & beverage, and logistics customers, drawing on ORBIS Corporation's reusable-packaging heritage."}, {"name": "Organic Village", "slug": "organic-village", "country": "Thailand (Bangkok, Sukhumvit 32)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Organic Village is an organic grocery retailer in Bangkok, selling fruits, vegetables, meat, dairy and pantry staples sourced from Thai producers, with both a physical store and nationwide online delivery."}, {"name": "Otrium", "slug": "otrium", "country": "Netherlands (Amsterdam)", "categories": "repair, waste-reduction", "priority": "★★★ Medium", "summary": "Otrium is an online marketplace connecting shoppers with end-of-season and excess fashion stock from 400+ brands, founded in 2016 by Milan Daniels and Max Klijnstra after experiencing unsold-inventory problems firsthand. It now serves over 4 million registered members."}, {"name": "Ozarka", "slug": "ozarka", "country": "Netherlands (Amsterdam)", "categories": "packaging-as-a-service, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "Ozarka provides reusable, durable food and drink containers (silicone, borosilicate, polypropylene) as a pay-per-use replacement for single-use takeout packaging, delivering, collecting, washing and returning items for hospitality clients under the motto \"you do the food, we do the dishes.\""}, {"name": "Package Free Shop", "slug": "package-free-shop", "country": "United States (Brooklyn, New York)", "categories": "consumer-education, waste-reduction", "priority": "★★★ Medium", "summary": "Package Free Shop began as a 3-month popup in Williamsburg, Brooklyn in April 2017, founded by zero-waste advocate Lauren Singer following her viral \"waste fits in a mason jar\" story. It has grown into an online and physical retailer of package-free and reusable goods."}, {"name": "Packaging Cluster / Green Impackt", "slug": "packaging-cluster-green-impackt", "country": "Spain (Packaging Cluster, Catalonia) operating the Green Impackt initiative in Colombia", "categories": "consumer-education, waste-reduction", "priority": "★★★ Medium", "summary": "The Packaging Cluster is a Spanish packaging-industry association (working with 30+ entities across 19 countries) that leads Green Impackt, an EU-funded project connecting European sustainable-packaging solution providers with Colombian SMEs to accelerate their transition to circular plastics/packaging practices."}, {"name": "PackBack", "slug": "packback", "country": "Netherlands (Rotterdam)", "categories": "consumer-education, digital-tracking, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "PackBack is a Dutch reuse-technology company aiming to eliminate single-use food and beverage packaging waste. It supplies connected hardware and software — digital IDs, SmartBins, and a dashboard — to make returnable packaging simple and scalable for foodservice and retail operators."}, {"name": "Packoorang", "slug": "packoorang", "country": "Norway", "categories": "material-recovery, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "Packoorang manufactures reusable, waterproof shipping mailer bags made from recycled plastic bottles and recycled clothing, intended to replace single-use cardboard boxes and plastic mailers across e-commerce supply chains."}, {"name": "På(fyll)", "slug": "pafyll", "country": "Norway", "categories": "digital-tracking, refill, reverse-logistics", "priority": "★★★★★ Essential", "summary": "På(fyll) is a circular refill service for household products (detergents, soaps, sprays) developed by Orkla ASA with innovation partners Æra, Bakken & Bæck, and Form Us With Love. Customers order online, receive filled reusable containers, and reorder/return via QR code."}, {"name": "Pak Packages", "slug": "pak-packages", "country": "Pakistan (Lahore)", "categories": "Not publicly available", "priority": "★★ Low", "summary": "Pak Packages is a Lahore-based flexible packaging manufacturer producing multi-layered plastic films using extrusion technology. Available sources describe it as a conventional flexible-packaging producer rather than confirming a dedicated reusable/resealable pouch line."}, {"name": "Pakpet", "slug": "pakpet", "country": "Pakistan (Karachi)", "categories": "Not publicly available", "priority": "★★ Low", "summary": "Pakpet is a Karachi-based manufacturer of PET plastic bottles, supplying brands such as Dalda, Soya Supreme and SC Johnson. Available sources describe a conventional B2B bottle-manufacturing business (minimum order 10,000 units) rather than a documented reuse/refill system."}, {"name": "Paptic", "slug": "paptic", "country": "Finland (Espoo)", "categories": "material-recovery, waste-reduction", "priority": "★★ Low", "summary": "Paptic Ltd, founded in 2015 and based in Espoo, Finland, developed Paptic®, a renewable-wood-fibre material engineered to replace plastic film in flexible packaging while remaining recyclable alongside cardboard and paper streams. Industrial-scale production began in 2018."}, {"name": "Paraguay Sin Basura", "slug": "paraguay-sin-basura", "country": "Paraguay", "categories": "consumer-education, waste-reduction", "priority": "★★★ Medium", "summary": "Paraguay Sin Basura is an environmental foundation working to reduce consumer waste polluting Paraguay's waterways and natural spaces, sharing reduction/recycling knowledge and connecting citizens, companies and government with circular-economy initiatives."}, {"name": "PAX Whole Foods & Eco Goods", "slug": "pax-whole-foods-eco-goods", "country": "Ireland (Westport, Co. Mayo)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★★ High", "summary": "PAX Whole Foods & Eco Goods is a Westport-based retailer offering refills of nearly 400 organic foods alongside eco-friendly cleaning and personal-care products, described as one of Ireland's largest minimal-waste shops. It works with over 75 Irish businesses."}, {"name": "Peerby", "slug": "peerby", "country": "Netherlands — Amsterdam", "categories": "consumer-education, sharing, waste-reduction", "priority": "★★★★ High", "summary": "Peerby is an Amsterdam-based sharing platform connecting neighbors to borrow and lend household items such as tools, electronics, bikes, and camping gear. Founded in 2012 by Daan Weddepohl, it claims to be one of the first working goods-sharing platforms, now active in the Netherlands, Belgium, Germany, and the UK."}, {"name": "Pfaffhüsli", "slug": "pfaffhusli", "country": "Switzerland — Pfaffhausen (Zumikon, Zürich canton)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "Pfaffhüsli is a small unpackaged (\"Unverpackt\") shop and café in Pfaffhausen, Switzerland, offering package-free bulk goods. Customers bring their own containers, weigh them at the store, and fill them with the desired quantity of product, reducing single-use packaging waste at the point of sale."}, {"name": "Pick n Pay", "slug": "pick-n-pay", "country": "South Africa — Cape Town", "categories": "consumer-education, material-recovery, reverse-logistics, waste-reduction", "priority": "★★★ Medium", "summary": "Pick n Pay is one of South Africa's largest retail grocery chains, founded in 1967 and listed on the Johannesburg Stock Exchange (JSE: PIK) the following year. It operates roughly 2,300 corporate and franchised stores and has piloted zero-waste supermarket concepts and reverse vending machines for recyclables."}, {"name": "Pimpant", "slug": "pimpant", "country": "France — Normandy", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Pimpant is a French brand founded in 2020 by Karline and Baptiste, manufacturing refillable cleaning and personal-care products made in Normandy. Its signature format is a powder stick that customers dilute with water in a reusable bottle to make products such as laundry detergent, shower gel, dish soap, and toothpaste."}, {"name": "Pizza 4P's", "slug": "pizza-4ps", "country": "Vietnam — Ho Chi Minh City", "categories": "consumer-education, reusable-packaging, take-back, waste-reduction", "priority": "★★★ Medium", "summary": "Pizza 4P's is a farm-to-table pizza restaurant chain founded in 2011 in Ho Chi Minh City by Japanese entrepreneurs Yosuke Masuko and Sanae Takasugi. It has grown to roughly 32 locations across Vietnam, Cambodia, India, Indonesia, and Japan, and runs sustainability programmes including a jar return scheme and dedicated zero-waste restaurant sites."}, {"name": "Plaine Products", "slug": "plaine-products", "country": "United States — Terrace Park, Ohio", "categories": "consumer-education, refill, reusable-packaging, take-back", "priority": "★★★★ High", "summary": "Plaine Products is a US bath and body care brand founded in 2017 by sisters Lindsey and Alison Delaplaine to eliminate single-use plastic from bathrooms. It sells shampoo, conditioner, body wash, lotion, and facial products in refillable aluminum bottles, and is a Certified B Corporation and 1% for the Planet member."}, {"name": "Planet Organic", "slug": "planet-organic", "country": "United Kingdom — London", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Planet Organic opened its first store in 1995 in Westbourne Grove, London, becoming the UK's first certified organic supermarket. It grew into the largest chain of Soil Association-certified organic shops in the UK, with around eight to ten stores in and around London, and offers an \"Unpackaged\" range of packaging-free bulk refills."}, {"name": "Planet Renu", "slug": "planet-renu", "country": "United States", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "Planet Renu is an e-commerce retailer selling reusable organic cotton mesh produce and shopping bags intended to replace single-use plastic grocery bags. Products are marketed as washable, durable, and foldable, for use in grocery shopping, food storage, and general household organization."}, {"name": "Planet Reuse", "slug": "planet-reuse", "country": "Netherlands — The Hague", "categories": "consumer-education, digital-tracking, sharing", "priority": "★★★★★ Essential", "summary": "Planet Reuse, launched in September 2022, describes itself as the first European online platform and network for reusable packaging, connecting FMCG brands, retailers, reuse system operators, packaging suppliers, municipalities, NGOs, and academia. It is powered by the LoftOS Foundation and the Netherlands Institute for Sustainable Packaging (KIDV)."}, {"name": "Plantish Future", "slug": "plantish-future", "country": "Canada — Vancouver, British Columbia", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "Plantish Future is a Vancouver, Canada-based small business selling vegan, plant-based, plastic-free products for the home and bathroom, including dish brushes, solid dish soap, shampoo/conditioner bars, and bamboo hair brushes. It describes itself as a queer-owned company focused on everyday plastic-free swaps."}, {"name": "Plastic Free Life", "slug": "plastic-free-life", "country": "Bulgaria — Sofia", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "Plastic Free Life is a Bulgarian eco-goods retailer based in Sofia, selling plastic-free home and cosmetic products online and, since September 2022, through a physical store on Iskar Street. Its range includes reusable cotton tea bags, biodegradable sponges, and eco shaving sets, marketed as free of plastic and animal-tested ingredients."}, {"name": "Plastic Free Lisbon", "slug": "plastic-free-lisbon", "country": "Portugal — Lisbon", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "Plastic Free Lisbon is an online zero-waste store based in Lisbon, Portugal, selling sustainable, ecological, and waste-free household and personal-care products. Orders are dispatched within 48 hours of payment, largely using reused packaging materials to minimize additional waste."}, {"name": "Pneedles", "slug": "pneedles", "country": "Nigeria — Uyo", "categories": "industrial-reuse, material-recovery, waste-reduction", "priority": "★★★ Medium", "summary": "Pneedles is a Nigerian company founded by entrepreneur Joshua Attat that manufactures buttons and beads from repurposed plastic waste, positioned as one of the first plastic-button producers in Nigeria. The business evolved from a local Ankara footwear operation in Uyo into a dedicated sustainable-materials manufacturer, gaining attention including at Lagos Fashion Week."}, {"name": "PolyLayerTech", "slug": "polylayertech", "country": "Italy — Sacile (Pordenone), near Venice", "categories": "industrial-reuse, material-recovery, reusable-packaging", "priority": "★★★ Medium", "summary": "PolyLayerTech is an Italian company based near Venice specializing in extruded corrugated/alveolar polypropylene (PP) sheets used in reusable packaging for automotive, pharmaceutical, and food-sector applications. It also designs and manufactures machinery for PP sheet production and welding."}, {"name": "Precious Plastic Bangkok", "slug": "precious-plastic-bangkok", "country": "Thailand — Bangkok", "categories": "consumer-education, industrial-reuse, material-recovery, waste-reduction", "priority": "★★★★ High", "summary": "Precious Plastic Bangkok, founded in 2018, is a Thai chapter of the global open-source Precious Plastic recycling movement. It establishes community-based workspaces where local groups collect, clean, sort, and recycle plastic waste using low-cost, open-source machines, transferring recycling knowledge and technology to communities across Thailand."}, {"name": "Propack", "slug": "propack", "country": "Uruguay", "categories": "industrial-reuse, material-recovery, reusable-packaging", "priority": "★★★ Medium", "summary": "Propack, operating as MITOP SA, is a Uruguayan manufacturer converting post-consumer PET and polypropylene into food-grade recycled packaging, including trays and clamshell containers. It processes collected bottles and containers through a proprietary system to achieve food-contact quality, partnering with regional recycler Ecopet/Cristalpet."}, {"name": "Public Goods", "slug": "public-goods", "country": "United States — New York, NY", "categories": "consumer-education, refill, reusable-packaging", "priority": "★★★★ High", "summary": "Public Goods is a US e-commerce brand founded in 2017 by Morgan Hirsh and Michael Ferchak, selling sustainable personal-care, household, grocery, and supplement products under a minimalist, unbranded aesthetic. It operates on a low-cost annual membership model and emphasizes eco-friendly packaging such as sugarcane-based bottles."}, {"name": "Pure North", "slug": "pure-north", "country": "Iceland — South Iceland", "categories": "industrial-reuse, material-recovery, waste-reduction", "priority": "★★★★ High", "summary": "Pure North is Iceland's only plastic recycling plant, operating on geothermal steam and hydropower electricity in South Iceland. Established around 2015, it processes plastic waste — including most of Iceland's agricultural film plastic — into raw recycled material sold on to manufacturers, rather than directly producing finished reusable containers."}, {"name": "Qualy Design", "slug": "qualy", "country": "Thailand", "categories": "consumer-education, waste-reduction", "priority": "★★ Low", "summary": "Qualy is a Thai product-design brand launched in 2004 by the Suppametheekulwat family, whose original business was an OEM plastics manufacturer (Saint Louis Plas-Mold, est. 1977). Qualy designs household goods intended to reduce waste and encourage sorting/reuse behaviour, sold globally."}, {"name": "QYOS (by Algramo)", "slug": "qyos", "country": "Indonesia (Jakarta)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★★ High", "summary": "QYOS is a digital-based refill startup founded in 2020 within Enviu Indonesia's Zero Waste Living Lab (launched 2019). It places automatic refill-vending stations for household and personal-care products in residential and retail locations across Indonesia, and now carries \"by Algramo\" branding reflecting a partnership/integration with the Chilean reuse-tech company Algramo."}, {"name": "R Buy Smart Refill", "slug": "r-buy-smart-refill", "country": "India (Bengaluru)", "categories": "digital-tracking, refill, waste-reduction", "priority": "★★★ Medium", "summary": "R Buy Smart Refill is an Indian startup building a \"refill-as-a-service\" platform, deploying smart kiosks that refill home-care and laundry products into customers' own reusable containers. It is incubated at the Atal Incubation Centre, IIIT Hyderabad, and describes itself as building India's largest tech-enabled refill network."}, {"name": "RaaS (Reusable as a Service)", "slug": "raas", "country": "Israel (Herzliya, Tel Aviv District)", "categories": "consumer-education, reusable-packaging, reverse-logistics, sharing", "priority": "★★★★ High", "summary": "RaaS (\"Reusable as a Service\") is an Israeli company helping businesses, event venues and organisations replace single-use plastic tableware with reusable cups and utensils. It provides end-to-end logistics: supply, delivery, on-site return stations, collection, washing and re-circulation."}, {"name": "Rampe5 ZeroWaste Ladencafe", "slug": "rampe5-zerowaste-ladencafe", "country": "Switzerland (Zurich)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Rampe5 is a zero-waste \"Ladencafe\" (store-café) in Zurich, Switzerland, described as one of the city's original zero-waste outlets. Customers bring their own containers to fill with unpackaged organic food and household products; a small in-store café hosts workshops and community events. It operates under the Genossenschaft grassrooted cooperative, having taken over from a predecessor store, FOIFI."}, {"name": "RataPlan", "slug": "rataplan", "country": "Netherlands (Den Helder origin; stores across North/South Holland and Flevoland)", "categories": "consumer-education, material-recovery, reverse-logistics, waste-reduction", "priority": "★★★★ High", "summary": "RataPlan is a Dutch non-profit foundation, founded in 1982 (originally as Stichting Kringloopwinkel) in Den Helder, now operating over 40 thrift stores (\"kringloopwinkels\") across North Holland, South Holland and Flevoland. In 2024 it absorbed the Noppes thrift-store chain, expanding its footprint."}, {"name": "Re-Up Refills", "slug": "re-up-refills", "country": "United States (Rockridge, Oakland, California)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Re-Up Refills is a US non-profit operating a community refill shop in Rockridge, Oakland, California, providing bulk bath, body, food, kitchen and cleaning products in refillable containers. Its stated mission is to build a better grocery system with minimized waste, responsibly-sourced products, and informed consumers."}, {"name": "Re-Use Austria", "slug": "re-use-austria", "country": "Austria", "categories": "consumer-education, material-recovery, repair, reverse-logistics, waste-reduction", "priority": "★★★★★ Essential", "summary": "Re-Use Austria is a non-profit advocacy association founded in 2004 (originally as RepaNet, renamed in 2023) representing over 40 member organisations working in re-use, repair and resource conservation across Austria. It acts as a \"lobby for re-use,\" connecting repair networks, repair cafes and social-enterprise second-hand businesses."}, {"name": "RE-ZIP", "slug": "re-zip", "country": "Denmark (Aarhus)", "categories": "digital-tracking, packaging-as-a-service, reusable-packaging, reverse-logistics", "priority": "★★★★★ Essential", "summary": "RE-ZIP is a Danish startup, founded in 2018 by CEO Bo Bach Boddum and Thomas Fugl, that builds reusable packaging for e-commerce to replace single-use cardboard shipping boxes. It operates a SaaS platform (RE-ZIP Manager and consumer app) to track packaging circulation, returns and environmental savings."}, {"name": "Reath", "slug": "reath", "country": "United Kingdom (Edinburgh, Scotland)", "categories": "digital-tracking, packaging-as-a-service, reusable-packaging", "priority": "★★★★★ Essential", "summary": "Reath is an Edinburgh-based startup co-founded in 2019 by Claire Rampen and Emily Rogers, building digital track-and-trace software for reusable packaging systems. It authored the \"reuse.id\" Open Data Standard, an agreed vocabulary enabling different organisations in a reuse supply chain (manufacturer, retailer, cleaner, customer) to share packaging usage data."}, {"name": "Recicla y Reusa Venezuela", "slug": "recicla-y-reusa-venezuela", "country": "Venezuela", "categories": "consumer-education", "priority": "★ Low relevance", "summary": "No organisation operating specifically under the name \"Recicla y Reusa Venezuela\" could be confirmed through available search sources. Venezuela has multiple community-level recycling/reuse initiatives (e.g. REUSAMAS, \"Venezuela Recicla Paso a Paso\"), but none matched this exact name."}, {"name": "Reciclaje Moreno", "slug": "reciclaje-moreno", "country": "Venezuela", "categories": "material-recovery", "priority": "★ Low relevance", "summary": "No organisation matching the name \"Reciclaje Moreno\" could be confirmed on the AIM2Flourish platform or elsewhere. Searches of AIM2Flourish's Venezuela/Latin America recycling innovation profiles (e.g. \"Recycling from the Source,\" \"Metamorfica Lab\") did not surface an entity by this specific name."}, {"name": "Reciclarte", "slug": "reciclarte", "country": "Venezuela (per seed data; a distinct reciclarte.org site exists but its country of operation could not be confirmed)", "categories": "consumer-education", "priority": "★ Low relevance", "summary": "No Venezuelan artists' collective operating specifically under the name \"Reciclarte\" could be confirmed through available search sources. General reporting confirms recycled/upcycled art activity exists in Venezuela (e.g. individual Caracas artists working with recycled cardboard, collective recycled-art exhibitions), but no distinct \"Reciclarte\" organisation matching the seed description was verified."}, {"name": "reCIRCLE AG (Switzerland)", "slug": "recircle-ag-switzerland", "country": "Switzerland (Bern)", "categories": "deposit-return, packaging-as-a-service, reusable-packaging, reverse-logistics", "priority": "★★★★★ Essential", "summary": "reCIRCLE AG is the Swiss company that founded the reCIRCLE reusable-packaging deposit system in Bern in 2016, starting with 24 partner businesses. It has since grown to around 2,000 participating Swiss businesses (as of ~2024) and expanded the reCIRCLE brand into Germany (2020), and the Netherlands, Denmark, Estonia and Italy (2021)."}, {"name": "reCIRCLE Denmark", "slug": "recircle-denmark", "country": "Denmark", "categories": "deposit-return, packaging-as-a-service, reusable-packaging, reverse-logistics", "priority": "★★★★★ Essential", "summary": "reCIRCLE Denmark is the Danish national operation of the reCIRCLE reusable takeaway-packaging system, a \"packaging-as-a-service\" deposit scheme for restaurants and cafes. The parent reCIRCLE brand was founded in Bern, Switzerland in 2016 by Jeannette Morath and expanded into Denmark, along with the Netherlands, Estonia and Italy, in June 2021."}, {"name": "reCIRCLE Ireland (by VOICE)", "slug": "recircle-ireland", "country": "Ireland (piloted at University College Cork)", "categories": "consumer-education, deposit-return, reusable-packaging", "priority": "★★★ Medium", "summary": "reCIRCLE Ireland is Ireland's first reusable takeaway food-container deposit scheme, brought to University College Cork (UCC) by the environmental non-profit VOICE Ireland, in partnership with catering company KSG and academics from UCC's Cleaner Production Promotion Unit. It licenses the reCIRCLE reusable-container system (originated by reCIRCLE AG, Switzerland) for a campus setting."}, {"name": "Reco", "slug": "reco", "country": "United Kingdom", "categories": "consumer-education, waste-reduction", "priority": "★★ Low", "summary": "Reco is a UK online retailer selling concentrated, low-waste alternatives to conventional single-use plastic personal-care and cleaning products, including laundry detergent sheets and toothpaste tablets, sold in recyclable cardboard packaging."}, {"name": "Recolecc", "slug": "recolecc", "country": "Peru", "categories": "consumer-education, material-recovery, reverse-logistics, take-back", "priority": "★★★ Medium", "summary": "Recolecc is a Peruvian collective management system for electrical and electronic equipment waste (RAEE), representing manufacturers in meeting Extended Producer Responsibility (EPR) recycling obligations through nationwide collection campaigns and drop-off points."}, {"name": "Recovo", "slug": "recovo", "country": "Spain (Barcelona)", "categories": "digital-tracking, material-recovery, reverse-logistics, waste-reduction", "priority": "★★★★ High", "summary": "Recovo is a Barcelona-based circular-fashion technology company operating a B2B marketplace where fashion brands and manufacturers buy and sell surplus fabric, deadstock, and production leftovers, alongside a white-label recommerce (resale) platform and upcycling services. Founded in 2021 by Mónica Rodríguez Corral, Marta Iglesias, and Gonzalo Sáenz Escudero."}, {"name": "RECUP & REBOWL (Germany)", "slug": "recup-rebowl-germany", "country": "Germany (founded in Rosenheim/Munich area)", "categories": "deposit-return, reusable-packaging, reverse-logistics", "priority": "★★★★★ Essential", "summary": "RECUP & REBOWL is a German deposit-based reuse system for takeaway coffee cups (RECUP) and food bowls (REBOWL), founded in September 2016 by Fabian Eckert and Florian Pachaly, piloted in Rosenheim near Munich before expanding nationwide."}, {"name": "Recup (UK)", "slug": "recup-uk", "country": "United Kingdom (London office; Essex manufacturing/washing facility)", "categories": "deposit-return, rental, reusable-packaging", "priority": "★★★ Medium", "summary": "Recup UK is a British company supplying reusable polypropylene cups (pint, half-pint, wine) for events, stadiums, and venues, offering purchase, rental, deposit-scheme, or levy-based models to reduce single-use cup waste. Self-described as operating since 2016 with 25+ years of team experience in plastics and recycling."}, {"name": "Refill Deutschland", "slug": "refill-deutschland", "country": "Germany", "categories": "consumer-education, digital-tracking, refill", "priority": "★★★★ High", "summary": "Refill Deutschland is a German non-profit initiative, part of the international \"Refill\" movement originating in the UK, that maps and promotes free tap-water refill points nationwide via the \"Karte von morgen\" (Map of Tomorrow) to reduce single-use plastic bottle consumption."}, {"name": "Refill H2O – IPVC", "slug": "refill-h2o-ipvc", "country": "Portugal (Instituto Politécnico de Viana do Castelo)", "categories": "consumer-education, digital-tracking, refill", "priority": "★★★ Medium", "summary": "Refill H2O is a research-led pilot project at the Instituto Politécnico de Viana do Castelo (IPVC) that built a \"Smartbottle Ecosystem\": reusable bottles with digital tags communicating with IoT-enabled refill stations, to eliminate single-use plastic bottles across the institute's campuses. Coordinated by researcher António Curado."}, {"name": "Refill.ie", "slug": "refill-ie", "country": "Ireland", "categories": "consumer-education, digital-tracking, refill", "priority": "★★★★ High", "summary": "Refill.ie is an Irish non-profit social enterprise, founded in 2017, that maps free drinking-water refill locations on its \"Tap Map\" app, aiming for refill access within 400m of anywhere in Ireland, alongside waste-free event services and mobile hydration station rentals."}, {"name": "Refill Lab", "slug": "refill-lab", "country": "Argentina", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Refill Lab is Argentina's first refillable cosmetics and home-care company, founded in January 2021 by two sisters-in-law with combined experience in the fragrance and cosmetics industry, offering hair care, creams, sanitiser, and home-fragrance products via a refill model."}, {"name": "Refill Mill", "slug": "refill-mill", "country": "United Kingdom (Ongar, England)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Refill Mill is a UK refill shop (physical store in Ongar, England, plus online delivery/pickup) selling package-free organic pantry foods, eco-friendly cleaning products, and natural beauty essentials, founded by a research scientist to help customers reduce single-use plastic."}, {"name": "Refill 'n' Refresh", "slug": "refill-n-refresh", "country": "United States (Prescott, Arizona)", "categories": "refill, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "Refill 'n' Refresh is a home, bath, and beauty destination in Prescott, Arizona, specialising in handcrafted soaps, lotions, and bath products with natural ingredients, operating as part of the US refillery movement that lets customers refill their own containers."}, {"name": "Refill.Swiss", "slug": "refill-swiss", "country": "Switzerland", "categories": "consumer-education, digital-tracking, refill", "priority": "★★★ Medium", "summary": "Refill.Swiss is a campaign run by Good For My Planet Association, a Swiss non-profit, bringing the UK-originated \"Refill\" model to Switzerland by mapping free water-refill locations via a shared app, with plans to expand into coffee and low-waste shopping."}, {"name": "Refillable Store (Mumbai)", "slug": "refillabels-mumbai", "country": "India (Mumbai)", "categories": "refill, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "Refillable is a Mumbai-founded startup providing home-care product refills (detergents, cleaners, sanitisers) via retrofitted delivery vehicles fitted with IoT-enabled refill stations, letting customers reuse the same containers repeatedly in a closed loop; it has expanded to Pune, Chennai, and Lucknow."}, {"name": "Refillables Hoi An", "slug": "refillables-hoi-an", "country": "Vietnam (Cẩm Thanh Commune, Hội An)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Refillables Hoi An is the first refillable concept store in Central Vietnam, located in Hội An, offering pay-by-weight refills of cleaning and personal-care liquids plus dried foods and spices for customers who bring their own containers (BYOC)."}, {"name": "Refilled", "slug": "refilled", "country": "Australia (Sydney)", "categories": "digital-tracking, refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Refilled is a Sydney-based startup that installs \"The Refiller,\" a smart drink dispenser pouring over 100 varieties of flavoured still or sparkling drinks on demand into reusable bottles or glasses, targeting offices, co-working spaces, gyms, and cafeterias to eliminate single-use plastic bottle waste."}, {"name": "Refiller Mobile", "slug": "refiller-mobile", "country": "Malaysia (Klang Valley)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Refiller Mobile is Malaysia's first mobile zero-waste store, a refill van founded by former media producer Oh Sok Peng that travels to Klang Valley neighbourhoods so residents can refill household cleaning products, dried food, and personal-care items in their own containers."}, {"name": "RefillMyBottle", "slug": "refillmybottle", "country": "Indonesia (Bali)", "categories": "consumer-education, digital-tracking, refill", "priority": "★★★★ High", "summary": "RefillMyBottle is a community-driven global map/app launched in Indonesia in 2015, helping travellers and locals find nearby free or low-cost water refill stations to reduce single-use plastic bottle consumption; it has since expanded to Vietnam, Thailand, Malaysia, and other countries via local ambassadors."}, {"name": "RefillNZ", "slug": "refillnz", "country": "New Zealand (Wellington)", "categories": "consumer-education, digital-tracking, refill", "priority": "★★★★ High", "summary": "RefillNZ is a grassroots, volunteer-led non-profit campaign founded in Wellington in October 2018 by Jill Ford, inspired by her work with City to Sea (founders of the UK Refill movement), that maps free tap-water refill sites nationwide via stickers and an app to cut single-use plastic bottle consumption."}, {"name": "Refillz", "slug": "refillz", "country": "Ireland (Naas, Co. Kildare; second location Portarlington)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Refillz is an independent zero-waste retailer operating physical refill stores in Naas and Portarlington, Ireland, plus an online shop. Customers bring or buy reusable containers to fill with pantry staples, cleaning products, and personal care items, avoiding single-use plastic packaging entirely."}, {"name": "RefilMe", "slug": "refilme", "country": "Brazil (national coverage)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "RefilMe supplies \"sustainable hydration stations\" (filtered/chilled water dispensers) and mobile hydration trucks for corporate, cultural, and sporting events across Brazil, replacing single-use plastic water bottles while offering brands an out-of-home advertising surface."}, {"name": "Refind", "slug": "refind", "country": "Sri Lanka", "categories": "consumer-education, reverse-logistics, waste-reduction", "priority": "★★★ Medium", "summary": "Refind is described as Sri Lanka's first and exclusive online thrifting marketplace, connecting buyers and sellers of second-hand clothing, furniture, home decor, beauty items, and more. It aggregates multiple independent vendor stores under one platform with nationwide delivery."}, {"name": "Regn", "slug": "regn", "country": "United Kingdom (Yeadon, Leeds, West Yorkshire)", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "Regn is a UK e-commerce wholesaler supplying retailers with sustainable, largely plastic-free products such as reusable sanitary items, bamboo toothbrushes, natural skincare, and household cleaning goods, positioning itself as a \"go-to wholesale partner for eco products.\""}, {"name": "REkrabička & REkelímek", "slug": "rekrabicka-rekelimek", "country": "Czechia", "categories": "deposit-return, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "REkrabička (\"food box\") and REkelímek (\"cup\") form a reusable food-and-drink container deposit system used by restaurants, bistros, and cafes across the Czech Republic as an alternative to single-use takeaway packaging. Containers are manufactured domestically and designed for roughly 400 reuses."}, {"name": "RePack", "slug": "repack", "country": "Finland (Helsinki)", "categories": "packaging-as-a-service, reusable-packaging, reverse-logistics", "priority": "★★★★★ Essential", "summary": "RePack, founded in Helsinki in 2011 by Jonne Hellgren, Juha Mäkelä, and Petri Piirainen, provides reusable, foldable delivery packaging for e-commerce and re-commerce brands. Inspired by Finland's bottle deposit system, it launched its return service in 2013 and won Finland's Fennia Prize design award in 2014."}, {"name": "RePlated", "slug": "replated", "country": "Australia (Bondi Junction, NSW)", "categories": "digital-tracking, reusable-packaging, take-back, waste-reduction", "priority": "★★★★ High", "summary": "rePlated is a Sydney-based company providing reusable \"Mealboxes\" made from ocean-bound plastic as a swap-and-wash alternative to single-use takeaway food packaging. It began with a pilot in late 2019 and now serves restaurants, workplaces, events, and individual consumers."}, {"name": "Replenish Refillery & Zero Waste Store (Canada)", "slug": "replenish-refillery-canada", "country": "Canada (Summerland, British Columbia)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Replenish Refillery & Zero Waste Store is a Canadian eco-friendly retailer at 9921 Main Street, Summerland, BC, offering bulk refillable cleaning, bath, and body products in-store, alongside biodegradable and non-toxic packaged goods shipped online for a zero-waste lifestyle."}, {"name": "Replenish Refillery (US)", "slug": "replenish-refillery-us", "country": "United States (Dover, New Hampshire)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Replenish Refillery is a zero-waste boutique in Dover, New Hampshire, describing itself as \"a shop, a teacher, a community builder, and a support system.\" It sells low-waste, non-toxic household and personal-care goods and offers refill-by-weight services alongside community education events."}, {"name": "Replenish Supermarket", "slug": "replenish-supermarket", "country": "Canada (Newmarket, Ontario)", "categories": "consumer-education, refill, reusable-packaging", "priority": "★★★ Medium", "summary": "Replenish is a curated general store at 208 Main St S, Newmarket, Ontario, selling sustainable, refillable, and consciously made goods across skincare, bath and body, home, kitchen, and lifestyle categories, with a strong focus on Canadian and Ontario-made products."}, {"name": "The Restart Project", "slug": "restart-project", "country": "United Kingdom (London)", "categories": "consumer-education, digital-tracking, repair, waste-reduction", "priority": "★★★★★ Essential", "summary": "The Restart Project is a London-based charity founded in 2013 that empowers people to repair and use electronics longer, reducing e-waste. It runs community \"Restart Parties\" where volunteers help the public fix broken devices, and supports a wider UK network of repair initiatives."}, {"name": "ReThink BioClean", "slug": "rethink-bioclean", "country": "Canada (Regina, Saskatchewan)", "categories": "refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "ReThink BioClean is a Regina, Saskatchewan-based company providing zero-waste commercial cleaning and janitorial supplies via a mobile refill service. It operates across Western Canada, delivering eco-friendly cleaning products directly to businesses without single-use containers."}, {"name": "ReTuna Återbruksgalleria", "slug": "retuna-aterbruksgalleria", "country": "Sweden (Eskilstuna)", "categories": "consumer-education, material-recovery, repair, waste-reduction", "priority": "★★★★★ Essential", "summary": "ReTuna Återbruksgalleria is a municipally-owned shopping mall in Eskilstuna, Sweden, billed as the world's first recycling mall. Public donations of discarded items are sorted and redistributed to independent shops within the mall, which repair, upcycle, and resell them, alongside a café and educational programming."}, {"name": "RETURNiT", "slug": "returnit", "country": "South Korea (Gangnam-gu, Seoul)", "categories": "reusable-packaging, reverse-logistics, waste-reduction", "priority": "★★★★ High", "summary": "RETURNiT is a Seoul-based platform operated by itgreen Co., Ltd. that lets customers order food through major Korean delivery apps (e.g., Coupang Eats, Naver Order) delivered in reusable stainless-steel containers instead of single-use packaging, with containers collected, sanitized, and recirculated."}, {"name": "Returnity", "slug": "returnity", "country": "United States (Brooklyn, New York)", "categories": "reusable-packaging, reverse-logistics, take-back", "priority": "★★★★ High", "summary": "Returnity, founded in 2016 and based in Brooklyn, New York (formerly Reusable Solutions Group), develops \"The Last Box,\" a durable, collapsible reusable tote for B2B shipping that integrates into existing carrier networks such as FedEx without requiring software or workflow changes."}, {"name": "Returnr", "slug": "returnr", "country": "Australia", "categories": "deposit-return, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Returnr is an Australian company (\"Powering reuse since 2018\") that manufactures and distributes reusable containers — insulated stainless-steel cups, bowls, trays, and storage solutions — designed to replace single-use disposable packaging for takeaway food and drink."}, {"name": "Reusables.com", "slug": "reusables-com", "country": "Canada (Vancouver, BC)", "categories": "deposit-return, digital-tracking, packaging-as-a-service, reusable-packaging", "priority": "★★★★ High", "summary": "Reusables™ is a Vancouver-based B2B platform providing enterprise-wide reusable container programs for campus dining and other high-volume foodservice environments, using patented \"Tap to Reuse™\" technology to let users borrow containers by tapping a credit card or student ID."}, {"name": "Reuse Network", "slug": "reuse-network", "country": "United Kingdom", "categories": "consumer-education, material-recovery, reverse-logistics, waste-reduction", "priority": "★★★★★ Essential", "summary": "Reuse Network is a UK registered charity (No. 1090824) that supports a national network of local reuse charities, helping them give donated items \"a new lease of life\" while alleviating poverty, reducing waste, and tackling climate change through coordinated local action and national support."}, {"name": "Reuso.io", "slug": "reuso-io", "country": "United States — Chicago, Illinois", "categories": "consumer-education, digital-tracking, reusable-packaging, reverse-logistics", "priority": "★★★ Medium", "summary": "REUSO provides a checkout/return system for reusable polypropylene food containers used by restaurants, museums, and venues in the Chicago area. Customers scan a QR code, receive a text-message PIN, and check out a container; a $1 service fee covers washing and technology costs, with containers reusable over 1,000 times."}, {"name": "Reuzi", "slug": "reuzi", "country": "Ireland — Dublin area (click-and-collect at Foxrock, Co. Dublin)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Reuzi is an Irish e-commerce and education business selling sustainable, plastic-free goods across kitchen, bathroom, health/beauty, children's and office categories, alongside a bulk refill bar (\"reuzi Pantry\"). Founded by Pat Kane in 2018, it also runs corporate workshops, school programs, and eco-events promoting reduced single-use consumption."}, {"name": "REWE Group", "slug": "rewe-group", "country": "Germany — Cologne", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "REWE Group is a major German diversified retail and tourism cooperative headquartered in Cologne, founded in 1927 as an auditing association of purchasing cooperatives. It operates supermarket chains (REWE, PENNY) across Germany and parts of Europe, and select stores have piloted in-store refill stations for bulk dry goods, cleaning products, and other items as part of broader waste-reduction efforts."}, {"name": "Rezero Foundation", "slug": "rezero-foundation", "country": "Spain — Barcelona, Catalonia (secondary base in Manacor, Mallorca)", "categories": "consumer-education, deposit-return, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Rezero is a Catalan non-profit foundation founded in 2005 to advance waste prevention and a \"zero waste society\" in Catalonia. It conducts research and pilot projects through RezeroLab, provides waste-prevention consulting to companies and public bodies, and builds community engagement around responsible consumption, including projects touching on reusable-container systems."}, {"name": "rhinopaq", "slug": "rhinopaq", "country": "Germany — Essen (Ruhr region)", "categories": "digital-tracking, packaging-as-a-service, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "rhinopaq develops and operates reusable shipping and transport packaging for B2B logistics, offering polypropylene boxes (partly recycled material) as an alternative to single-use cardboard. Founded in 2021 in Essen, Germany, it serves manufacturers, rental services, and logistics operators with a closed-loop collect-clean-redistribute system."}, {"name": "Rimani Venezia", "slug": "rimani-venezia", "country": "Italy — Venice (Castello district, Barbaria de le tole)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Rimani is a packaging-free bulk shop in Venice's Castello district, founded in 2020 by Lisa and Orsetta, selling bulk pasta, biscuits, teas and other dry goods alongside refillable detergents and cut soaps, plus local artisanal products. Its name plays on \"ri-mani\" (\"recycled\" + \"hands\"), reflecting a philosophy of reuse and handmade craft."}, {"name": "RingKarp", "slug": "ringkarp", "country": "Estonia", "categories": "deposit-return, digital-tracking, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "RingKarp is an Estonian family business that built a nationwide reusable food-container and drink-cup deposit system, letting customers order food in a returnable container, pay a small deposit, and return it at network locations or via the reCIRCLE European reuse network. Founded in 2021, its containers are designed for at least 200 uses."}, {"name": "Ringo Eco", "slug": "ringo-eco", "country": "Estonia — Tallinn", "categories": "deposit-return, digital-tracking, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "Ringo Eco operates an open reusable-packaging platform in Estonia, letting retailers, restaurants and food producers join with reusable containers while Ringo Eco centrally manages deposit handling, collection, and industrial washing. Founded in 2020 in Tallinn, it has built what is reported to be Northern Europe's largest food-packaging cleaning centre."}, {"name": "Rituals", "slug": "rituals", "country": "Netherlands — Amsterdam", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Rituals is a Dutch luxury personal-care, cosmetics, and home-fragrance retailer founded in 2000 by Raymond Cloosterman, opening its first Amsterdam store the same year. It has grown into a global retail chain exceeding €1 billion in annual turnover, and introduced an in-store product-refill programme in 2017 as part of its sustainability strategy."}, {"name": "Robuust", "slug": "robuust", "country": "Belgium — Antwerp", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Robuust is described as Belgium's first packaging-free shop, founded in August 2014 by Savina Istas in Antwerp. It sells organic, local, seasonal produce and bulk dry goods, dairy, and beverages without packaging, letting customers buy exact quantities using their own containers."}, {"name": "Roots Collective", "slug": "roots-collective", "country": "Philippines — Taguig City (flagship store, Uptown Bonifacio Mall)", "categories": "consumer-education, waste-reduction", "priority": "★★★ Medium", "summary": "Roots Collective is a Philippine curated marketplace, established in 2016, connecting conscious consumers with Filipino social enterprises and sustainable brands. It represents over 120 brands and nearly 4,000 products spanning food, personal care, fashion, home goods, books, and zero-waste items, through both a flagship Taguig City store and an e-commerce platform."}, {"name": "RREUSE", "slug": "rreuse", "country": "Belgium — Brussels", "categories": "consumer-education, material-recovery, repair", "priority": "★★★★★ Essential", "summary": "RREUSE is Europe's largest network of social enterprises active in reuse, repair, and recycling, established in 2001. It supports member organisations engaged in refurbishing, repairing, and recycling materials (notably furniture, textiles, WEEE, and mattresses) across Europe, and advocates for supportive EU circular-economy policy."}, {"name": "Ruohonjuuri", "slug": "ruohonjuuri", "country": "Finland — Helsinki", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Ruohonjuuri is a Finnish retail chain specialising in organic food, natural cosmetics, and health products, tracing its origins to 1982 when its founders began importing recycled paper into Finland. It now operates 16 physical stores, online shops in Finland and Sweden (Happy Food Store), and offers certified natural cosmetics with refill options."}, {"name": "Rustic Strength", "slug": "rustic-strength", "country": "United States — the Ozarks region", "categories": "refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Rustic Strength manufactures concentrated, plant-based cleaning and wellness products free of phthalates, parabens, phosphates, SLS, and SLES, made at a family-run factory in the Ozarks. It supplies these products in bulk to a network of refill stations and retail partners across the United States, operating a \"Close The Loop Program\" for container recycling and sanitisation."}, {"name": "Sabon Depot", "slug": "sabon-depot", "country": "Philippines — Bunlo, Bocaue, Bulacan", "categories": "refill, waste-reduction", "priority": "★★ Low", "summary": "Sabon Depot JDG is a Philippine soap and cleaning-product retailer based in Bulacan, operating a \"Green Formula\" product line sold through a franchise and dealership network. Customers can access refillable soap and cleaning products at multiple franchised outlets across the greater Manila area and Baguio."}, {"name": "Saffron & Serai", "slug": "saffron-and-serai", "country": "Malaysia — Kuala Lumpur", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Saffron & Serai is a Kuala Lumpur-based enterprise producing handcrafted, plastic-free products, most notably reusable beeswax food wraps marketed as an alternative to cling film, alongside coconut bowls, batik bags, and other sustainable home goods."}, {"name": "Salubata", "slug": "salubata", "country": "Nigeria (founded); company later registered in France, with current operations also based in the United States", "categories": "industrial-reuse, material-recovery, repair, waste-reduction", "priority": "★★★★ High", "summary": "Salubata is a Nigerian-founded footwear company that designs and manufactures modular sneakers with interchangeable, patented components, made from recycled ocean plastic (PET). Founded by environmental scientist Fela Buyi Akinse alongside Yewande Akinse, each pair reportedly repurposes around 25 plastic bottles while using over 70% less manufacturing energy than conventional footwear."}, {"name": "Sanergy (The Sanergy Collaborative / Fresh Life)", "slug": "sanergy", "country": "Kenya (Nairobi)", "categories": "industrial-reuse, material-recovery, waste-reduction", "priority": "★★★★ High", "summary": "Sanergy operates \"Fresh Life\" urine-diverting dry toilets across informal settlements in Nairobi, franchised to local entrepreneurs. Waste is collected regularly and processed at a treatment facility into organic fertiliser and insect-based animal feed, closing a sanitation-to-agriculture loop for smallholder farmers across Kenya."}, {"name": "Sanima (formerly X-Runner)", "slug": "sanima", "country": "Peru (Lima)", "categories": "industrial-reuse, material-recovery, waste-reduction", "priority": "★★★★ High", "summary": "Sanima (rebranded from X-Runner) provides urine-diverting dry toilets and weekly waste collection to low-income households in Lima informal settlements lacking sewer access. Collected waste is composted off-site using thermophilic and microbial treatment, producing soil-safe fertiliser meeting international pathogen-safety standards."}, {"name": "Sankoty Sustainables", "slug": "sankoty-sustainables", "country": "United States (Peoria, Illinois)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "Sankoty Sustainables sells handmade and manufactured low-waste household and personal-care goods around Peoria, Illinois, with clean-ingredient, minimal-packaging products. The company also operates a zero-waste refill station inside the Take Two Resale Boutique in nearby Pekin, Illinois."}, {"name": "Sans Market", "slug": "sans-market", "country": "United States (St. Petersburg, Florida)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Sans Market is a low-waste refillery and grocery store in downtown St. Petersburg, founded by Eniko Olah in 2018 to combat single-use plastic in the community. Customers refill bottles and containers with bulk household and personal-care products rather than buying new packaged goods."}, {"name": "São João da Madeira Municipality", "slug": "sao-joao-da-madeira", "country": "Portugal", "categories": "consumer-education, refill, repair, waste-reduction", "priority": "★★★★ High", "summary": "São João da Madeira (pop. ~22,000, near Porto) is among the first Portuguese municipalities to pursue Zero Waste City certification under Mission Zero Academy / Zero Waste Europe. The town centre offers swap, refill, and repair services and workshops as part of a 2030 zero-waste roadmap."}, {"name": "Saponetti", "slug": "saponetti", "country": "Canada (Toronto, Ontario)", "categories": "refill, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "Saponetti launched in 2016 from a garage as Toronto's first online refill delivery service, founded by Nikki Self and Christian von Seydlitz. By 2018 it added a Bloordale storefront, offering Canadian-made soaps and cleaning products delivered/sold in reusable jars and jugs."}, {"name": "saveBOARD", "slug": "saveboard", "country": "New Zealand (Te Rapa, Hamilton) / Australia", "categories": "industrial-reuse, material-recovery, waste-reduction", "priority": "★★★★ High", "summary": "saveBOARD manufactures CodeMark-certified wall and ceiling boards from up to 100% recycled packaging waste — beverage cartons, soft plastics and composite packaging — shredded and heat-pressed. Founder Paul Charteris acquired the underlying IP from the US and opened the Te Rapa factory in November 2021."}, {"name": "Savonnerie des Diligences", "slug": "savonnerie-des-diligences", "country": "Canada (Saint-Raymond, Quebec)", "categories": "waste-reduction", "priority": "★★ Low", "summary": "Founded in 2005 by Marie-Eve Lejour and Sébastien Boismenu, this Quebec brand handmakes natural soaps and body-care products with mostly organic ingredients. Its \"zéro déchet\" (zero waste) line includes body butter, solid dish soap, face soap and serums sold without plastic packaging."}, {"name": "Schoeller Allibert (IPL Schoeller)", "slug": "schoeller-allibert", "country": "Netherlands (Hoofddorp)", "categories": "industrial-reuse, reusable-packaging, reverse-logistics", "priority": "★★★★★ Essential", "summary": "Schoeller Allibert formed in 2012–2013 through the merger of LINPAC Allibert and Schoeller Arca Systems, tracing its reusable-crate lineage back to 1960. It is the world's largest manufacturer of reusable plastic containers, crates and pallets for materials handling, merging into \"IPL Schoeller\" in 2025."}, {"name": "Scoop Wholefoods", "slug": "scoop-wholefoods", "country": "Singapore (Australia-founded)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★★ High", "summary": "Founded in 2013 by Jeremy & Bettina Kirk in Australia, Scoop Wholefoods sells bulk organic and natural wholefoods, sourcing most grains, nuts, teas and oils direct from Australian farmers. Its Singapore operation, a joint venture with retailer Gill Capital, is billed as Asia's largest organic wholefoods store."}, {"name": "Searious Business – MOSSUP", "slug": "searious-business-mossup", "country": "Morocco (project); Netherlands (parent company)", "categories": "consumer-education, deposit-return, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "MOSSUP (Moroccan Supermarkets Tackling Single Use Plastic) is a pilot run by Dutch company Searious Business with retailers Marjane and Carrefour in Morocco. It combines a PET bottle-to-bottle collection/reward scheme with a reusable deli-container deposit system, funded by the Netherlands' SBIR programme."}, {"name": "Seekers Spirits", "slug": "seekers-spirits", "country": "Cambodia (Phnom Penh)", "categories": "consumer-education, material-recovery, refill, reusable-packaging", "priority": "★★★ Medium", "summary": "Seekers Spirits is a Phnom Penh craft distillery that lets customers bring empty spirit bottles to designated \"refill hubs\" (including its own distillery and partner pop-ups) to refill with its core spirits, reducing new glass/packaging demand while also running a community glass-recycling initiative."}, {"name": "SESI (Food & Household Refill LLP)", "slug": "sesi", "country": "United Kingdom (Oxfordshire)", "categories": "deposit-return, refill, reusable-packaging, reverse-logistics", "priority": "★★★★★ Essential", "summary": "Founded in 2006 in Oxfordshire, SESI supplies sustainable, vegan, cruelty-free detergents and toiletries to independent shops, farmers markets, cooperatives and charities across the UK in returnable 5L/20L drums, pioneering a closed-loop bulk refill model nearly two decades ago."}, {"name": "Seventh Generation", "slug": "seventh-generation", "country": "Not publicly available", "categories": "consumer-education, material-recovery, refill, take-back, waste-reduction", "priority": "★★ Low", "summary": "Seventh Generation, Inc. is a Burlington, Vermont-based manufacturer of plant-derived cleaning, laundry, paper and personal-care products, founded in 1988 by Alan Newman and Jeffrey Hollender. The company built its identity around the \"seventh generation\" principle drawn from Haudenosaunee (Iroquois) philosophy — weighing decisions against their impact on descendants seven generations forward. It became a Certified B Corporation in 2007. In September 2016, Unilever acquired the company in a deal reported at roughly $700 million; Seventh"}, {"name": "SF Express", "slug": "sf-express", "country": "China (Shenzhen, Guangdong)", "categories": "industrial-reuse, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "SF Express is China's largest courier and logistics company, piloting reusable packaging in over 20 cities for scenarios including fresh cold-chain delivery and government document transport, as part of a broader \"Zero Waste Cities\" and full-lifecycle packaging sustainability strategy."}, {"name": "Shareclub", "slug": "shareclub", "country": "Ireland (Dublin)", "categories": "digital-tracking, packaging-as-a-service, reusable-packaging, reverse-logistics, waste-reduction", "priority": "★★★★ High", "summary": "Founded in 2022 by Sarah Fliessbach, Shareclub provides businesses with reusable hot/cold drink cups and bowls for workplace canteens, cafés, corporate events and festivals, tracked via a mobile app (QR code borrow/return) or RFID tags for higher-frequency settings."}, {"name": "Shuangti", "slug": "shuangti", "country": "China (Guangdong)", "categories": "packaging-as-a-service, reusable-packaging, reverse-logistics, take-back", "priority": "★★★ Medium", "summary": "Shuangti is a platform company providing reusable takeaway food container (RTFC) services to restaurants and consumers, launching China's first campus pilot in June 2020 at a Guangdong university, letting diners rent containers and return them to recycling cabinets for cleaning and reuse."}, {"name": "Siklus", "slug": "siklus", "country": "Not publicly available", "categories": "consumer-education, refill, reusable-packaging, reverse-logistics, waste-reduction", "priority": "★★★★★ Essential", "summary": "Siklus is a Jakarta-based startup founded in 2019 by Jane von Rabenau that provides an on-demand refill service for household staples — shampoo, liquid soap, cooking oil, detergent and dishwashing liquid — as an alternative to single-use plastic sachets, which dominate the FMCG market across Southeast Asia. Customers order via app, Instagram or WhatsApp and receive refills delivered by motorbike into their own reusable containers, or buy from roadside refill stalls stocked by Siklus. The"}, {"name": "Simple Switch", "slug": "simple-switch", "country": "United States (Denver, Colorado)", "categories": "consumer-education, waste-reduction", "priority": "★★ Low", "summary": "Founded in 2018 by Rachel Kois in Denver, Simple Switch is an online marketplace for ethical and sustainable shopping, vetting every supplier on manufacturing, labor practices, materials and packaging before listing home essentials, gifts and other everyday products."}, {"name": "Simula (Simula PH)", "slug": "simula", "country": "Philippines (Glorietta 2, Makati City)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Simula (\"beginning\" in Filipino) is a Metro Manila sustainable lifestyle store selling zero-waste and local products. It hosts a physical \"Refillery\" for household cleaners and personal care items, and carries over 70 partner local and micro/small enterprise brands."}, {"name": "Sinba", "slug": "sinba", "country": "Peru", "categories": "industrial-reuse, material-recovery, reverse-logistics, waste-reduction", "priority": "★★★★ High", "summary": "Sinba is a Peruvian social enterprise and Certified B Corp that collects food waste from restaurants and businesses and converts it, via a biotechnological process, into animal feed (\"Punba\") and fertiliser, while also recovering recyclable materials in partnership with informal recyclers."}, {"name": "Sixth + Zero", "slug": "sixth-and-zero", "country": "United States (Evansville, Indiana)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "Sixth + Zero is a small-town zero-waste market and refillery that grew out of the original Sixth Street Soapery. It hand-makes soaps and skincare, and stocks bulk pantry staples and household goods for customers to refill using their own containers."}, {"name": "Skubu", "slug": "skubu", "country": "South Africa (Diepsloot, Johannesburg)", "categories": "digital-tracking, refill, waste-reduction", "priority": "★★★★★ Essential", "summary": "Skubu is South Africa's first fully automated refill store, launched in Diepsloot by tech startup Sonke in partnership with the CSIR and the Department of Science, Technology and Innovation under the Circular Economy Demonstration Fund. Customers refill staples like maize meal, rice, cooking oil and detergent using IoT-enabled dispensing machines."}, {"name": "Slo Store", "slug": "slo-store", "country": "Philippines (Parañaque City)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "Slo Store is a Filipino zero-waste retailer with a physical refill station, selling face, body and hair care, menstrual products, pet and wellness items, and storage products under the philosophy of slow, mindful, intentional living to reduce environmental impact."}, {"name": "SmartFilter", "slug": "smartfilter", "country": "Mexico", "categories": "refill, waste-reduction", "priority": "★★★ Medium", "summary": "SmartFilter is the official Mexican distributor of Elkay drinking fountains and bottle-filling stations (including the ezH2O line), selling water filtration and hydration equipment to businesses, hotels, resorts, schools and public spaces to reduce reliance on bottled water."}, {"name": "smol", "slug": "smol", "country": "United Kingdom", "categories": "consumer-education, packaging-as-a-service, waste-reduction", "priority": "★★★★ High", "summary": "smol is a UK direct-to-consumer subscription brand founded in 2018 by ex-Unilever employees Paula Quazi and Nick Green, delivering concentrated laundry capsules, dishwasher tablets and cleaning products in plastic-free, letterbox-friendly packaging."}, {"name": "SOCSE", "slug": "socse", "country": "Not publicly available", "categories": "Not publicly available", "priority": "Not publicly available", "summary": "Not publicly available"}, {"name": "SodaStream", "slug": "sodastream", "country": "Not publicly available", "categories": "consumer-education, deposit-return, material-recovery, refill, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "SodaStream makes home carbonation machines and reusable CO2 cylinders that let consumers make sparkling water and flavoured drinks at home instead of buying single-use bottled/canned beverages. The brand's roots trace to 1903, when Guy Hugh Gilbey of London gin distillers W & A Gilbey Ltd developed an early home carbonation apparatus; the business passed through Reckitt & Colman, a 1974 management buyout, and Cadbury Schweppes (1985) before being acquired in 1998 by Soda-Club, an Israeli"}, {"name": "Soeder", "slug": "soeder", "country": "Switzerland (Zurich)", "categories": "refill, reusable-packaging, reverse-logistics", "priority": "★★★★★ Essential", "summary": "Founded in 2013 by Hanna and Johan, Soeder produces natural soaps and personal-care products in its own Zurich soap factory. It operates a \"true closed-loop\" refill model with over 130 refill stations across Switzerland, including flagship stores in Basel and Zurich-Stadelhofen railway stations."}, {"name": "Sol Goods", "slug": "sol-goods", "country": "New Zealand", "categories": "reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Founded in 2019 by Steph Wood after a surf trip inspired the search for a naturally protective sunscreen, Sol Goods makes reef-safe, tested mineral sunscreens packaged in reusable/recyclable aluminium tubes and glass, and is developing a bulk dispensing solution for refill stores."}, {"name": "Solid (Solid Oral Care)", "slug": "solid-oral-care", "country": "New Zealand (Titahi Bay, Porirua)", "categories": "reusable-packaging, reverse-logistics, take-back", "priority": "★★★★ High", "summary": "Founded by dental professional Laura Nixon, Solid makes plastic-free toothpaste, tablets and powders packaged in glass jars designed to be sterilised and reused up to 30 times. The company runs a jar-return program and encourages in-store retailer refills."}, {"name": "Solidarity Market Bonpland (Mercado Bonpland)", "slug": "solidarity-market-bonpland", "country": "Argentina (Buenos Aires)", "categories": "consumer-education, refill", "priority": "★★★ Medium", "summary": "Mercado Bonpland was founded in 2003 from a joint project between neighbourhood assemblies, cooperatives, NGOs and small producers in the wake of Argentina's economic crisis. Held Tuesdays, Fridays and Saturdays in Palermo Hollywood, it sells dried fruits, nuts, organic produce, cleaning products and artisanal goods."}, {"name": "Somos Tierra", "slug": "somos-tierra", "country": "Mexico (Estado de México)", "categories": "waste-reduction", "priority": "★★ Low", "summary": "Somos Tierra began around 2015 and first sold at market in August 2016, making solid cosmetics (solid shampoo, personal care) before \"zero waste\" was a known trend in Mexico. The founder grows many of the plants used in products at Rancho el Cardo Santos, Estado de México."}, {"name": "Sonora Reffilery (Sonora Refillery)", "slug": "sonora-reffilery", "country": "United States (Oceanside, California)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Sonora Refillery is a zero-waste shop in Oceanside, California offering plastic-free bath, body and home products from small businesses, including customisable-scent oils and bulk spices. Customers bring their own containers or purchase glass bottles in-store to refill."}, {"name": "Sourceful", "slug": "sourceful", "country": "United Kingdom (Manchester)", "categories": "consumer-education, digital-tracking", "priority": "★★★ Medium", "summary": "Founded in 2020 by Wing Chan, Shiran Zheng and Mary Wang, Sourceful helps brands build more sustainable supply chains, starting with branded packaging, via a platform offering custom packaging design, supply-chain management tools and real-time carbon-footprint data."}, {"name": "Spin by Valorlux", "slug": "spin-by-valorlux", "country": "Luxembourg", "categories": "digital-tracking, packaging-as-a-service, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "Launched 17 April 2023 by Valorlux, Spin is a free app-based system letting consumers borrow and return reusable 0.3L take-away cups at \"SpinPoints\" in Luxembourg City's hospitality sector — a pilot ahead of Luxembourg's 1 January 2025 single-use packaging ban."}, {"name": "Splosh", "slug": "splosh", "country": "Not publicly available", "categories": "consumer-education, material-recovery, refill, reusable-packaging, take-back, waste-reduction", "priority": "★★★★ High", "summary": "Splosh Limited is a UK private limited company, incorporated 23 January 2009 (Companies House no. 06800040), that sells refillable household cleaning and personal-care products directly to consumers by post. Founder Angus Grahame has described the idea originating from observing plastic-bottle waste in a supermarket car park in Hay-on-Wye; company factory operations are based in Newtown, Wales. Customers buy a durable bottle once, then order concentrated refill pouches by post, mixing with water at home; used"}, {"name": "Spruce", "slug": "spruce", "country": "United Kingdom (London), also sold in the US", "categories": "consumer-education, refill, reusable-packaging", "priority": "★★★★ High", "summary": "Founded in 2019 by Mahira in London, Spruce makes natural, non-toxic, zero-waste cleaning and laundry products. Customers buy a reusable spray bottle once and refill endlessly with plastic-free refills, and the brand is sold in both UK and US markets."}, {"name": "Station Zero", "slug": "station-zero", "country": "Bulgaria (Sofia)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Station Zero is described as Bulgaria's first zero-waste refill shop, created by founders Ani and Stoicho and based on Yuriy Venelin street in Sofia. It offers bulk cleaning and personal-care product refills to reduce single-use packaging in the local market."}, {"name": "Studio Fletta (Flétta)", "slug": "studio-fletta", "country": "Iceland", "categories": "consumer-education, industrial-reuse, material-recovery", "priority": "★★★★ High", "summary": "Founded in 2018 by product designers Birta Rós Brynjólfsdóttir and Hrefna Sigurðardóttir after research beginning in 2014 into where local industrial waste ends up, Flétta transforms discarded materials — including retired Icelandair uniforms and airbags — into unique, high-value design products."}, {"name": "Suds Refillery", "slug": "suds-refillery", "country": "United States (Shawnee, Kansas)", "categories": "consumer-education, refill, reusable-packaging", "priority": "★★★ Medium", "summary": "Founded by mother-daughter duo Kerry and Barbette, Suds Refillery started as a pop-up in May 2022 and opened a Shawnee, Kansas storefront that September. It refills soaps, detergents, lotions and cleaning products, encouraging repeated container reuse to reduce single-use plastic."}, {"name": "Sun Moon Rain", "slug": "sun-moon-rain", "country": "United States (Santa Monica, California)", "categories": "consumer-education, refill, reusable-packaging", "priority": "★★★ Medium", "summary": "Founded by Shabnam Melwani, Sun Moon Rain opened its first Santa Monica, California store in April 2023, offering a refill bar with 72 plastic-free home, kitchen, laundry, skin and body-care products, serving both in-store and online customers."}, {"name": "Sunbird Straws (seed name: \"Sunrise Straws\")", "slug": "sunbird-straws", "country": "India (Bengaluru)", "categories": "material-recovery, waste-reduction", "priority": "★★★ Medium", "summary": "Founded in 2020 by Christ University professor Saji Varghese and Chirag M G, Sunbird Straws makes biodegradable, chemical-free straws from fallen coconut leaves, previously burned as agricultural waste. Production is run at women-operated centres in Karnataka, Kerala and Tamil Nadu."}, {"name": "Sunsilk (Unilever Refill Initiative, Pakistan)", "slug": "sunsilk-pakistan-refill", "country": "Pakistan (brand global via Unilever)", "categories": "consumer-education, refill", "priority": "★★★ Medium", "summary": "Sunsilk is a Unilever hair-care brand; as part of Unilever's global \"Reuse. Refill. Rethink.\" programme, refill stations offering Sunsilk shampoo have been deployed at select retail locations (confirmed at a Carrefour in Karachi, Pakistan), alongside similar Unilever refill kiosks in other markets like the Philippines."}, {"name": "SuperDrecksKëscht (SDK)", "slug": "superdreckskescht", "country": "Luxembourg", "categories": "consumer-education, material-recovery, repair, waste-reduction", "priority": "★★★★★ Essential", "summary": "SuperDrecksKëscht (SDK) is a four-decade-old Luxembourg state initiative for hazardous-waste management, evolved into a key circular-economy player. Supported by the Ministry of Environment, Chamber of Commerce and Chamber of Trades, it advises over 6,000 companies (60%+ of the active workforce) on sustainable material management."}, {"name": "Suppli", "slug": "suppli", "country": "Canada (Toronto)", "categories": "digital-tracking, packaging-as-a-service, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "Suppli is a circular supply-chain platform connecting restaurants, food-delivery apps, caterers and consumers around reusable food containers. Its software manages container accounting and return reminders, and Uber Eats piloted it (alongside Reusables.com) in Toronto and Vancouver for zero-waste takeout."}, {"name": "Sustain LA", "slug": "sustain-la", "country": "United States (Los Angeles, California)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Founded in 2009 by Leslie VanKeuren Campbell, Sustain LA is a certified woman-owned social enterprise providing zero-waste event services and a refill station offering household cleaners, body-care products and bulk goods to Los Angeles-area customers."}, {"name": "Sustenir", "slug": "sustenir", "country": "Singapore (with UAE operations)", "categories": "Not publicly available", "priority": "★ Low relevance", "summary": "Sustenir is a Singapore-founded (2013) agri-tech company growing nutrient-rich leafy greens and superfoods in climate-controlled vertical farms, with R&D/production facilities also established in the UAE. It reduces food miles via urban indoor farming, not through a packaging reuse or refill system."}, {"name": "Swapfiets", "slug": "swapfiets", "country": "Netherlands", "categories": "rental, repair, reverse-logistics, sharing", "priority": "★★★★★ Essential", "summary": "Founded in 2014 by student friends in Delft, Swapfiets pioneered \"bicycle-as-a-service\": subscribers get a maintained bike with 48-hour repair/swap guarantee for a monthly fee, eliminating bike ownership. It has grown to 280,000+ subscribers across 8+ European countries and is majority-owned by Pon Holdings (Pon.bike)."}, {"name": "Swapp!", "slug": "swapp", "country": "Poland", "categories": "digital-tracking, refill, reusable-packaging", "priority": "★★★★ High", "summary": "Swapp! is a closed-loop retail concept combining refilling-station vending machines, a mobile app, reusable containers and e-commerce, deployed at Carrefour, Auchan and Superpharm locations in Warsaw, Wrocław and Kraków, selling FMCG products like cosmetics and cleaning liquids."}, {"name": "Taluelu", "slug": "taluelu", "country": "Estonia", "categories": "waste-reduction", "priority": "★★ Low", "summary": "Taluelu is an Estonian farm-based producer of handmade zero-waste household and personal-care items, referenced within Estonia's low-waste-living resource networks alongside organisations like Zero Waste Estonia SA."}, {"name": "Tạp Hóa Lá Xanh", "slug": "tap-hoa-la-xanh", "country": "Vietnam (Ho Chi Minh City)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★★ High", "summary": "Founded in 2018 by Phạm Ngọc Trâm Anh, a former flight attendant turned eco-entrepreneur, Tạp Hóa Lá Xanh is one of the three most prominent zero-waste refill shops in Saigon, selling dried food and condiments (rice, cereal, tea, pasta) without packaging."}, {"name": "Tarım Kredi Sıfır Market", "slug": "tarim-kredi-sifir-market", "country": "Turkey (Ankara)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★★ High", "summary": "Launched by the Agricultural Credit Cooperatives of Turkey (Tarım Kredi) in July 2024, the first \"Sıfır Market\" (Zero Market) opened in Beytepe, Ankara, letting customers buy raw milk, legumes, dried fruits/nuts, liquid soap, detergent and sunflower oil using their own reusable containers."}, {"name": "Tarra Verpakkingsvrij", "slug": "tarra-verpakkingsvrij", "country": "Belgium (Sint-Gillis-bij-Dendermonde)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★★ High", "summary": "Founded in 2017 by former plastic-arts teacher Nora Lorré, inspired by Bea Johnson's packaging-free movement, Tarra is a packaging-free store in Dendermonde selling dry foods (nuts, pasta, rice, flour, herbs, teas, oils) and zero-waste care products via BYOC refill."}, {"name": "Teko (Refill Not Landfill, Philippines)", "slug": "teko", "country": "Philippines", "categories": "consumer-education, refill, reusable-packaging", "priority": "★★★★ High", "summary": "Teko.ph leads the Philippine chapter of \"Refill Not Landfill\" (RNL), a Southeast Asia-wide campaign to eliminate single-use plastic water bottles. It distributes free (customer covers ₱95 shipping) double-wall insulated stainless-steel bottles and partners with local businesses to supply free refill water."}, {"name": "Teo Straw", "slug": "teo-straw", "country": "Vietnam", "categories": "material-recovery, waste-reduction", "priority": "★ Low relevance", "summary": "Teo Straw is listed as a small Vietnamese seller of compostable grass straws made from wild sedge, similar to the well-documented \"Ống Hút Cỏ\" (Ong Hut Co) grass-straw industry from the Mekong Delta. No independent press coverage specific to \"Teo Straw\" by that name was found."}, {"name": "Terra Refill", "slug": "terra-refill", "country": "Mexico (San Pedro Garza García, Nuevo León)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★★ High", "summary": "Founded in December 2018 by Rocío Patrón and Jeannet Maggi, Terra Refill is a zero-waste bulk store offering 600+ products — flours, seeds, legumes, condiments, nuts, cleaning and personal-care items — encouraging customers to reuse their own containers, and has expanded to Guadalajara and Chihuahua."}, {"name": "TerraCycle (Loop)", "slug": "terracycle", "country": "United States (Trenton, New Jersey)", "categories": "material-recovery, reusable-packaging, reverse-logistics, take-back", "priority": "★★★★★ Essential", "summary": "Founded in 2001 by Tom Szaky, TerraCycle turns hard-to-recycle pre- and post-consumer waste into raw materials. In 2019 it launched Loop, a global circular shopping platform delivering products in durable containers collected, cleaned and reused (sometimes 100+ times), partnering with P&G, Coca-Cola, Carrefour, Tesco, Nestlé and others."}, {"name": "Tetra Pak Paraguay", "slug": "tetra-pak-paraguay", "country": "Paraguay (local division of Swedish/Swiss multinational)", "categories": "industrial-reuse, material-recovery", "priority": "★★ Low", "summary": "Tetra Pak Paraguay is the local operation of the global beverage-carton manufacturer, running a carton-recycling facility processing an estimated 1,500 tons per year, positioned by the company as promoting a broader packaging reuse/recycling value chain in Paraguay."}, {"name": "Thanks to Love Zero-Waste Shop (덕분애)", "slug": "thanks-to-love-zero-waste-shop", "country": "South Korea (Seoul)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Thanks to (덕분애) is a Seoul-based zero-waste platform run by KG Traders Inc. under representative Lee Yun-kyung, offering a vegan-friendly zero-waste shop and café with bulk refills of soaps, shampoos, detergents, oils, vinegars, grains and snacks."}, {"name": "The Body Shop", "slug": "the-body-shop", "country": "Not publicly available", "categories": "consumer-education, material-recovery, refill, reusable-packaging, take-back", "priority": "★★★★★ Essential", "summary": "The Body Shop was founded in 1976 by Anita Roddick, who opened the first shop in Brighton, England, built around ethically sourced, cruelty-free beauty products and environmental/social campaigning. Ownership passed from L'Oréal (2006–2017, £652.3m) to Natura &Co (2017–2023, £880m) to Aurelius Group (autumn 2023, £207m). Aurelius placed the UK business into administration in February 2024 owing an estimated £276m to creditors, leading to roughly 85 UK store closures and around 500 retail plus 270 head-office"}, {"name": "The Bulk House", "slug": "the-bulk-house", "country": "China — originally Beijing (Gulou Dongdajie / Drum Tower area); now operates online", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "The Bulk House is described in multiple independent sources (China Development Brief, Xinhua, Yicai Global) as mainland China's first social enterprise dedicated to a zero-waste lifestyle. Founded in 2018 by Chinese-British couple Carrie Yu and Joseph Harvey, it opened a physical shop in Beijing's Drum Tower (Gulou) area where customers could bring their own containers to refill shampoo, conditioner, soap, and other personal-care and household products, and buy reusable alternatives such as steel straws, cotton"}, {"name": "The Castile Soap Shop", "slug": "the-castile-soap-shop", "country": "Singapore", "categories": "consumer-education, refill, reusable-packaging", "priority": "★★★ Medium", "summary": "The Castile Soap Shop is a Singapore-based e-commerce and wholesale retailer specialising in castile soaps (predominantly the US Vermont Soap brand) and related natural personal-care and household cleaning products, marketed as USDA Certified Organic, vegan, cruelty-free, and free from petroleum, phthalates, and formaldehyde. Beyond retail sales of packaged products, the company operates a refill program allowing customers to bring their own bottles to refill soap and cleaning products, plus a \"Mobile Refills\" house-call service described"}, {"name": "The Clean Kilo", "slug": "the-clean-kilo", "country": "United Kingdom (Birmingham)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★★ High", "summary": "The Clean Kilo opened 16 June 2018 in Birmingham after an Indiegogo crowdfunding campaign raising ~£20,000, billing itself as the UK's largest zero-waste supermarket, selling food, drink, toiletries and cleaning products by weight for customers to refill."}, {"name": "The Collective (DSM)", "slug": "the-collective-dsm", "country": "United States (Des Moines, Iowa)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Owned by Jamie, a Des Moines native, The Collective is a sustainable-living shop and bulk refillery in Highland Park, Des Moines, offering vegan and ethically-made low-waste goods, including natural body-care products from brands like Plaine Products."}, {"name": "The Ditty Bag", "slug": "the-ditty-bag", "country": "United States (Mystic, Connecticut)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Founded by Jason Hine, The Ditty Bag Zero-Waste Market and Café opened in 2021 in Mystic, Connecticut, helping customers reduce plastic use through bulk dry goods, refill stations for cleaning products, and package-free grocery items."}, {"name": "The Eco Alchemist", "slug": "the-eco-alchemist", "country": "Canada (Squamish, British Columbia)", "categories": "consumer-education, refill, reusable-packaging", "priority": "★★★ Medium", "summary": "Launched in May 2021 by Cosmetic Chemist and Holistic Nutritionist Terri Kirkham, The Eco Alchemist makes vegan hair and skin care manufactured on-site in Squamish, BC, with a boutique offering in-person refills alongside bulk sizes for wholesale partners."}, {"name": "The Eco Flamingo (Eco & The Flamingo)", "slug": "the-eco-flamingo", "country": "United States (Chicago, Illinois)", "categories": "consumer-education, refill, repair, waste-reduction", "priority": "★★★★ High", "summary": "Co-founded in 2020 by Bethany Barbouti and Jackie MacCartie, Eco & The Flamingo is Chicago's first zero-waste general store, offering eco-friendly products, refills and a market café, with a second location added in Evanston in 2022."}, {"name": "The Eco Refill Station", "slug": "the-eco-refill-station", "country": "Australia (Mandurah region, Western Australia)", "categories": "refill, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "Eco Refill Station serves the Mandurah region of Western Australia (Shoalwater, Safety Bay, Mundijong and surrounds), offering natural household cleaning and body-care refills with a BYOC model; the business was previously run by a founder named Kate and has since changed to new ownership continuing the same model."}, {"name": "The Filling Station Eco Store", "slug": "the-filling-station-eco-store", "country": "Ireland (Galway)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★★ High", "summary": "Established July 2019 by John Tedders — whose family transitioned from conventional to organic farming — The Filling Station Eco Store in Galway supports organic producers with hundreds of refillable food, cleaning and personal-care dispensers, using only recyclable materials."}, {"name": "The Good Fill", "slug": "the-good-fill", "country": "United States (Nashville, Tennessee)", "categories": "refill, reusable-packaging, reverse-logistics, take-back", "priority": "★★★★ High", "summary": "Founded in 2022 in Nashville, The Good Fill offers bulk refills of all-natural home and personal-care products both online and in-store, using a reusable aluminium case system plus mail-in refill pouches with prepaid return envelopes."}, {"name": "The Green Bee", "slug": "the-green-bee", "country": "United States (Goshen, Indiana)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Founded by sisters Brandy Nichols and Ashley Anglemyer, The Green Bee opened around January 2023 as northern Indiana's first zero-waste store, offering refillable household products alongside locally-made, repurposed and recycled crafts, gifts and home decor."}, {"name": "The Green Collective", "slug": "the-green-collective", "country": "Singapore", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Launched in April 2018 by Danielle Champagne, Mayur Singh and Agatha Lee, The Green Collective began as a platform bringing together sustainable brands and has grown into Singapore's largest eco-friendly collective and first B-Corp-certified platform for eco-friendly goods in Asia."}, {"name": "The Green Jar", "slug": "the-green-jar", "country": "Canada (Toronto, Ontario)", "categories": "deposit-return, refill, reusable-packaging", "priority": "★★★★ High", "summary": "Opened in December 2019 by twin sisters Tannis and Mara Bundi, The Green Jar is a Toronto eco-friendly refillery offering package-free personal-care and home goods in bulk, developing a bottle-deposit system during the city's first COVID lockdown to support online delivery."}, {"name": "The Green Market (Bali)", "slug": "the-green-market-bali", "country": "Indonesia (Bali — Kerobokan, Seseh)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★★ High", "summary": "Billed as the first zero-waste bulk food store in Bali, The Green Market sells organic and non-organic groceries via a self-weigh refill system, with locations in Kerobokan and Seseh, plus WhatsApp ordering and delivery/pickup."}, {"name": "The Green Tap", "slug": "the-green-tap", "country": "South Africa (Table View / Sunningdale, Cape Town)", "categories": "refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "The Green Tap is a Cape Town zero-waste refill store that has refilled \"thousands of bottles\" over roughly five years of operation, offering wholesale refills of cleaning and personal-care products, plus white-label options for businesses wanting branded natural refillable products."}, {"name": "The Greet", "slug": "the-greet", "country": "South Korea", "categories": "digital-tracking, packaging-as-a-service, reusable-packaging, reverse-logistics", "priority": "★★★★★ Essential", "summary": "The Greet operates Korea's most extensive reusable-container sanitisation network under its \"Drimm\" brand — 38 standardised, QR-tracked container types for packaging, delivery, festivals, catering and funeral services — using a proprietary 7-stage sanitisation process developed with partners from Germany, Japan and the US."}, {"name": "The Mayan Collective", "slug": "the-mayan-collective", "country": "US (San Luis Obispo, California)", "categories": "consumer-education, refill, reusable-packaging", "priority": "★★ Low", "summary": "A San Luis Obispo, California candle-bar retailer selling 100% soy-wax candles in reusable glass jars, with a dedicated Refill Station in Arroyo Grande where customers refill candle vessels and bottles of soap, detergent, dish soap, shampoo and conditioner. Donates 20% of proceeds to causes in Guatemala."}, {"name": "The Nature Masons", "slug": "the-nature-masons", "country": "India (Goa)", "categories": "refill, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "Goa-based personal-care brand making gender-neutral, organic, cruelty-free deodorant balms and shampoo bars sold in reusable tins, with standalone refill bars available so customers reuse the same tin. The company reports having tested and abandoned aluminium packaging due to quality and humidity-related oxidation problems in its Goa warehouse."}, {"name": "The Olive Branch", "slug": "the-olive-branch", "country": "Ireland (Clonakilty, Co. Cork)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "A health food shop in Clonakilty, Co. Cork, founded in 2004 by Olive Finn and Andy Beattie. Its zero-waste refill offering — bulk groceries and household/personal-care refills — is run through a related \"little sister\" store/brand called Twig Refill Station."}, {"name": "The Purest Solutions", "slug": "the-purest-solutions", "country": "Turkey (Istanbul)", "categories": "refill, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "A Turkish clean-beauty/skincare brand founded in 2020, offering paraben/alcohol/dye-free skincare (serums, cleansers, toners, moisturisers, sunscreens) sold in over 30 countries, with \"Refill Eco Packs\" introduced as a sustainability-focused packaging option."}, {"name": "The Refill Coalition", "slug": "the-refill-coalition", "country": "UK", "categories": "industrial-reuse, refill, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "A cross-sector UK industry coalition, run by reuse consultancy GoUnpackaged, developing an open-source industry standard for reusable bulk vessels. Partnered with Aldi, Ocado and logistics firm CHEP, and funded by Innovate UK, it launched its first real-world in-store/online trial in October 2023."}, {"name": "The Refill Company", "slug": "the-refill-company", "country": "Canada (Thunder Bay, Ontario)", "categories": "consumer-education, material-recovery, refill, reusable-packaging, take-back", "priority": "★★ Low", "summary": "An independent refillery in Thunder Bay, Ontario, offering bulk personal-care and household refills sourced from Canadian and local suppliers. Customers bring their own containers, which are weighed before and after filling so they pay only for the product used."}, {"name": "The Refill Shoppe", "slug": "the-refill-shoppe", "country": "Not publicly available", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "The Refill Shoppe was founded by Michelle Stevens in Ventura, California, as one of the earliest dedicated refill retailers in the US zero-waste movement. The business sells bath, body, home-cleaning and personal-care liquids in bulk from a physical storefront (relocated within Ventura since opening) and via e-commerce, allowing customers to refill their own containers or purchase one of the store's reusable bottles. It has held Certified B Corporation status since 2015 and describes itself as"}, {"name": "The Refillable Van", "slug": "the-refillable-van", "country": "UK (Kent — Canterbury, Dover, Deal, Sandwich, Ashford, Ramsgate area)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "A mobile, van-based zero-waste refill business serving south-east Kent, UK. Customers bring their own containers to be weighed, filled and re-weighed at farmers' markets, village pop-up refill stations, or via home-delivery/home-shop bookings."}, {"name": "The Refillery Storehouse", "slug": "the-refillery-storehouse", "country": "United States (Poughkeepsie, New York)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "A woman-owned, package-free bulk grocery store in Poughkeepsie, New York, offering 250+ non-perishable food items plus household essentials, personal care products, local dairy and a self-serve craft-beer tap system, all sold by weight into reusable containers."}, {"name": "The Refillery", "slug": "the-refillery", "country": "UK (Newington, Edinburgh, Scotland)", "categories": "consumer-education, refill, reusable-packaging, reverse-logistics", "priority": "★★ Low", "summary": "A plastic-free, ethical refill shop based in Newington, Edinburgh, selling dry goods, eco-cleaning products, soaps and local grains/pulses/teas by weight, with UK-wide delivery and click-and-collect refill options."}, {"name": "The Social Space", "slug": "the-social-space", "country": "Singapore", "categories": "consumer-education, refill, reusable-packaging", "priority": "★★ Low", "summary": "A Singapore social enterprise combining a café, retail store, nail salon and \"Refillery\" refill station, founded by Daniel Yeow and Cheryl Ou to promote low-waste living alongside inclusive employment practices."}, {"name": "The Source Bulk Foods", "slug": "the-source-bulk-foods", "country": "Australia (Mullumbimby, NSW origin); operates in Australia, New Zealand and UK", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Australia's largest specialised bulk-food retailer, evolved from a Mullumbimby health-food store (Eden's Landing, acquired by founders Paul and Emma in 2007) into The Source Bulk Foods brand. Now a franchise network of 40-50+ stores across Australia, with additional locations in New Zealand and the UK, selling 400+ package-free wholefood and pantry items."}, {"name": "The Sustainability Project", "slug": "the-sustainability-project", "country": "Singapore", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "A Singapore-based zero-waste advocacy and retail business that grew from a blog into an online and showroom-based shop in 2018, selling low/zero-waste lifestyle products and operating an in-store refill station."}, {"name": "The Swapshop", "slug": "the-swapshop", "country": "Netherlands (Rotterdam, with additional Amsterdam locations)", "categories": "consumer-education, repair, reverse-logistics, sharing", "priority": "★★★ Medium", "summary": "A Dutch clothing-swap retail concept founded in 2019 as a Rotterdam pop-up by Laura Suijkerbuijk and Monique Drent, now operating four stores across Rotterdam and Amsterdam where customers exchange used fashion items for store credit (\"swaps\")."}, {"name": "The Tare Market", "slug": "the-tare-market", "country": "US (Minneapolis, Minnesota)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Minneapolis-based zero-waste retailer billed as Minnesota's first such store, operating two locations offering 135+ bulk food items and 700+ package-free household/personal-care \"swaps,\" with local delivery and curbside pickup."}, {"name": "The Unwaste Shop", "slug": "the-unwaste-shop", "country": "US (Chicago, Illinois)", "categories": "consumer-education, material-recovery, refill, reusable-packaging, take-back", "priority": "★★★ Medium", "summary": "A Chicago (West Loop) zero-waste store and online shop offering plastic-free, package-free products, including a dedicated in-store refill station and a range of refillable/plastic-free oral-care items such as bamboo dental floss in reusable containers."}, {"name": "The Wallet Shop", "slug": "the-wallet-shop", "country": "Singapore (also serving Malaysia)", "categories": "consumer-education, reusable-packaging", "priority": "★ Low relevance", "summary": "A Singapore/Malaysia-focused online retailer primarily known for bags, wallets and accessories, which also stocks a dedicated reusable-cup category — including KeepCup, Oasis, and Sttoke brand reusable coffee cups and insulated travel tumblers."}, {"name": "The Wally Shop", "slug": "the-wally-shop", "country": "US (Brooklyn, New York)", "categories": "consumer-education, refill, reusable-packaging, reverse-logistics, waste-reduction", "priority": "★★★★ High", "summary": "A Brooklyn-based zero-waste grocery delivery service founded in 2017 by Tamara Lim, sourcing local and organic goods from farmers markets and bulk suppliers and delivering them in reusable packaging that couriers later collect for reuse."}, {"name": "The Waste Free Co.", "slug": "the-waste-free-co", "country": "Sweden (Uppsala)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Founded by Estefania Coral (originally from Colombia, moved to Sweden 2017), The Waste Free Co installs refill stations for food, snacks and household goods in supermarkets, hotels and offices across Sweden, letting customers buy only the quantity they need in reusable packaging."}, {"name": "TheCircularLab", "slug": "thecircularlab", "country": "Spain (Logroño, La Rioja)", "categories": "consumer-education, material-recovery, reusable-packaging", "priority": "★★★★ High", "summary": "TheCircularLab is Ecoembes' open innovation centre for the circular economy, opened in 2017 in Logroño, Spain — described as the first such centre in Europe dedicated to packaging circularity. It researches, tests and develops eco-design, reuse and recycling solutions with universities, tech centres, companies and entrepreneurs."}, {"name": "Tierra Verde", "slug": "tierra-verde", "country": "Bulgaria", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Tierra Verde Bulgaria offers natural, toxin-free household products — cleaning, laundry, dishwashing and baby-care lines — sold in reusable packaging designed to be refilled repeatedly from bulk stores or larger containers rather than discarded."}, {"name": "Tingi Station", "slug": "tingi-station", "country": "Philippines (Baguio City)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★★ High", "summary": "Tingi Station is a zero-waste store in Baguio City, Philippines, offering pantry staples, household goods, loose-leaf teas, roasted nuts and pet products refillable by weight — allowing customers to buy exactly the quantity needed (the \"tingi\" tradition) using their own containers, cutting single-use sachet waste."}, {"name": "Tip Toe Eco Marketplace", "slug": "tip-toe-eco-marketplace", "country": "United States (Kennebunk, Maine)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "TipToe Eco Marketplace is a community-hub storefront in Kennebunk, Maine, hosting over 40 local Maine makers and consignors selling plastic-free gifts, art, home and body-care products, alongside a full home-and-body refill bar and a \"ReLove\" section for previously-owned goods."}, {"name": "TIPA", "slug": "tipa", "country": "Israel (Hod HaSharon)", "categories": "waste-reduction", "priority": "★★ Low", "summary": "Founded in 2010 by Daphna Nissenbaum and Tal Neuman, TIPA develops compostable, flexible films and laminates for food and apparel packaging that mimic conventional plastic's durability and barrier properties but decompose within roughly 180 days. The company has raised over $130M across funding rounds."}, {"name": "TNT Bags", "slug": "tnt-bags", "country": "Peru", "categories": "consumer-education, waste-reduction", "priority": "★★ Low", "summary": "TNT Bags manufactures reusable shopping bags made from non-woven (TNT/spunbond polypropylene) fabric in Peru, positioning them as a durable, water-resistant, multi-use alternative to single-use plastic bags for retail and promotional use."}, {"name": "TOMRA (Reusable Takeaway Packaging / REUSEABLE Aarhus)", "slug": "tomra-reuse", "country": "Norway (Asker) — Aarhus, Denmark pilot", "categories": "deposit-return, digital-tracking, reusable-packaging, reverse-logistics", "priority": "★★★★★ Essential", "summary": "TOMRA, the Norwegian reverse-vending machine pioneer founded in 1972, launched \"REUSEABLE\" — the world's first open, city-wide system for reusable takeaway packaging — in Aarhus, Denmark in January 2024, using its Rotake collection infrastructure, deposit incentives and a central sanitization facility."}, {"name": "Tosca", "slug": "tosca", "country": "United Kingdom (regional); global HQ Atlanta, USA", "categories": "industrial-reuse, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "Tosca has led the reusable transport packaging and pooling industry for over 60 years, supplying durable plastic pallets, crates, beverage trays, dollies and e-commerce totes to supply chains across North America, Europe (including the UK) and Australia/New Zealand."}, {"name": "Totoya", "slug": "totoya", "country": "Japan (Kyoto)", "categories": "consumer-education, digital-tracking, refill, waste-reduction", "priority": "★★★★★ Essential", "summary": "Launched July 3, 2021 in Kyoto, Totoya is billed as Japan's first zero-waste supermarket, selling fresh produce, cleaning supplies, noodles and nuts entirely package-free through a bring-your-own-container (BYOC) bulk-refill system, with jars and stainless-steel lunch boxes available on a deposit basis."}, {"name": "Touch the Toes", "slug": "touch-the-toes", "country": "Singapore", "categories": "consumer-education", "priority": "★★ Low", "summary": "Founded in 2011 by Eliza, Kelly and Wuen, Touch The Toes was Singapore's (and reportedly Asia's) first sustainably-produced yoga gear retailer, selling eco-friendly mats, props and apparel made from organic cotton, recycled and upcycled materials, and bamboo blends; it added a community studio/workshop space in 2017."}, {"name": "TRAMUCO (via COOPI initiative)", "slug": "tramuco-coopi", "country": "Venezuela (Caracas)", "categories": "consumer-education, material-recovery, waste-reduction", "priority": "★★★ Medium", "summary": "TRAMUCO is a women-led cooperative established in 2023 that runs a participatory solid-waste management system across several Caracas parishes (Antímano, La Vega, Sucre, Altagracia, San Agustín, Coche, Valle), developed through a COOPI–International Cooperation project with local partner Tinta Violeta and EU funding."}, {"name": "Trash Hero Czech Republic", "slug": "trash-hero-czech-republic", "country": "Czech Republic", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Trash Hero Czech Republic is the national chapter of the global Trash Hero movement, running local clean-up events and a free water-refill network across cities including Prague, Jablonec nad Nisou, Plzeň, Hradec Králové, Jihlava and Nymbursko, letting people refill their own Trash Hero bottles for free at participating businesses."}, {"name": "Trashit", "slug": "trashit", "country": "Pakistan (Karachi)", "categories": "consumer-education, material-recovery, waste-reduction", "priority": "★★★ Medium", "summary": "Founded in 2018, TrashIt is a Pakistan-based youth-led social enterprise that collects organic waste via its \"Trash on Wheelz\" service and converts it into organic compost, operating facilities in Karachi, Hyderabad, Bahawalpur and Gharo, alongside an online eco-store selling reusable and zero-waste lifestyle products."}, {"name": "Truly Free Home", "slug": "truly-free-home", "country": "United States (Williamsburg, Michigan)", "categories": "consumer-education, packaging-as-a-service, refill, waste-reduction", "priority": "★★★★ High", "summary": "Founded in 2015 by Stephen Enzell (originally as MyGreenFills) after his son had a reaction to conventional laundry detergent, Truly Free Home makes non-toxic laundry and cleaning products sold via an online subscription: customers get reusable jugs/bottles once, then receive concentrated refill shipments to top them up."}, {"name": "TULU", "slug": "tulu", "country": "Israel (Tel Aviv)", "categories": "digital-tracking, rental, sharing, waste-reduction", "priority": "★★★★★ Essential", "summary": "Founded in 2018 by architect Yishai Lehavi and environmental entrepreneur Yael Shemer at MIT's DesignX incubator, TULU installs smart locker units in residential/commercial buildings, letting residents rent items like vacuum cleaners, tools and gaming consoles via a mobile app instead of owning them individually."}, {"name": "Turtle Green (Turtle Green Refillery)", "slug": "turtle-green", "country": "Canada (Bolton, Ontario / Caledon, GTA)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Turtle Green Refillery is a mobile refill business serving Caledon and the surrounding Greater Toronto Area, delivering earth-friendly home and personal-care products — including DIY bodycare ingredients and household cleaning refills — in minimal or customer-reused packaging, with routine neighbourhood stops and farmers'-market attendance."}, {"name": "UBQ Materials", "slug": "ubq-materials", "country": "Israel (Tel Aviv, with manufacturing at Kibbutz Tze'elim, Negev)", "categories": "industrial-reuse, material-recovery, waste-reduction", "priority": "★★★ Medium", "summary": "UBQ Materials is an Israeli cleantech company that converts unsorted household waste — organics, mixed plastics, paper, cardboard — into UBQ, a bio-based thermoplastic composite sold as pellets. The material substitutes for virgin plastic, wood, or concrete in manufacturing."}, {"name": "Unboxed Market", "slug": "unboxed-market", "country": "Canada (Toronto, Ontario)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Unboxed Market is a Toronto grocery store offering package-free fresh produce, bulk dry goods, butcher, cheese and deli counters, plus refill stations for home and personal care products. It aims to be a full one-stop shop for low-waste grocery shopping, in-store and online."}, {"name": "Uni (Uni Refill System / Uni Bodycare)", "slug": "uni-refill", "country": "United States (direct at weareuni.com); also sold in UK via Space NK and other authorized retailers", "categories": "consumer-education, refill, reusable-packaging", "priority": "★★★ Medium", "summary": "Uni is a single bodycare/haircare brand offering 100% recyclable, refillable packaging with reef-safe, upcycled ingredients (including olive-oil-industry byproducts). It sells directly via weareuni.com and through authorized retailers — Space NK (UK), Ulta Beauty, MECCA, Credo Beauty, Amazon, and Goop (US/international)."}, {"name": "Unibag", "slug": "unibag", "country": "Chile (Santiago) — expanded to Peru and Mexico", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Unibag manufactures reusable non-woven (TNT) bags and compostable plant-fiber bags for retail, e-commerce, and produce use. Founded in Chile as the country's first reusable-bag factory, it has since expanded to Peru and Mexico, supplying major retail chains."}, {"name": "Unilever Colombia (FAB / Dirt is Good) — Refill & Sustainable Packaging", "slug": "unilever-colombia-fab-dirt-is-good", "country": "Colombia", "categories": "material-recovery, refill, waste-reduction", "priority": "★★★ Medium", "summary": "FAB is one of Colombia's most established laundry detergent brands, historically owned by Unilever. Unilever introduced sustainable-packaging measures for FAB, including bottles made partly from recycled plastic, and separately piloted mobile refill stations for detergents (via an Algramo partnership) in Latin American markets. In January 2026, Unilever sold its Colombia/Ecuador home-care portfolio, including FAB, to Peruvian conglomerate Alicorp."}, {"name": "Unilever — Global Refill & Reuse Initiative (incl. Philippines)", "slug": "unilever-global-refill", "country": "Global (HQ: London/Rotterdam); Philippines pilot based in Manila", "categories": "consumer-education, refill, reverse-logistics, take-back, waste-reduction", "priority": "★★★★ High", "summary": "Since 2018, Unilever has run more than 50 refill and reuse pilots worldwide as part of its packaging sustainability strategy. In the Philippines, this included the \"All Things Hair Refillery,\" launched in March 2019 across three Manila shopping malls, allowing consumers to refill haircare products and drop off used sachets/bottles."}, {"name": "Unilever (Sedal brand) — Mexico Refill Stations", "slug": "unilever-sedal-mexico", "country": "Mexico", "categories": "refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Unilever's Sedal brand set up shampoo refill stations in ten Walmart stores across Mexico in late 2019, letting shoppers fill reusable aluminum bottles instead of buying plastic bottles — the first reuse-refill trial for a Unilever Beauty & Personal Care brand in Mexico."}, {"name": "Unit Goods", "slug": "unit-goods", "country": "Finland (unverified)", "categories": "refill", "priority": "★ Low relevance", "summary": "Seed data describes Unit Goods as a Finnish refillable food store. Targeted web searches in this research pass returned no results confirming this business's existence, website, or operational details."}, {"name": "Unpackaged Eco", "slug": "unpackaged-eco", "country": "Australia (Melbourne, Victoria)", "categories": "refill, reverse-logistics, waste-reduction", "priority": "★★★ Medium", "summary": "Unpackaged Eco makes cleaning and soap products in Melbourne and distributes them through zero-waste online deliveries to serviced postcodes plus refill station installations at partner retailers, including Ritchies SUPA IGA locations."}, {"name": "Unpackt", "slug": "unpackt", "country": "Singapore", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★★ High", "summary": "Unpackt is Singapore's first zero-waste bulk store, co-founded by Florence Tay and Jeff Lam. Customers bring their own containers, weigh them, and fill up with self-serve grains, pastas, oils, teas, and other bulk goods, avoiding single-use packaging entirely."}, {"name": "The Unscented Company", "slug": "unscented-company", "country": "Canada (Quebec)", "categories": "consumer-education, refill, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Founded by Anie Rouleau, The Unscented Company makes all-natural, fragrance-free household cleaning and body care products designed for refilling at home or in-store, reducing single-use plastic packaging. It gained wider attention in 2017-2018 after being featured on Gwyneth Paltrow's Goop platform."}, {"name": "Original Unverpackt", "slug": "unverpackt", "country": "Germany (Berlin, Kreuzberg)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★★★ Essential", "summary": "Founded by Sara Wolf and Milena Glimbovski, Original Unverpackt opened in February 2014 as Germany's first unpackaged supermarket. Customers bring their own containers and dispense food, cleaning, and beauty products from gravity bins with no single-use packaging."}, {"name": "UrCup", "slug": "urcup", "country": "Poland (Warsaw)", "categories": "deposit-return, reusable-packaging, reverse-logistics, waste-reduction", "priority": "★★★★ High", "summary": "UrCup provides a deposit-based reusable cup system for events, festivals, and catering in Poland. Customers pay a small deposit to \"borrow\" a durable, dishwasher-safe cup, return it at any partner outlet, and UrCup handles washing, storage, and redistribution."}, {"name": "Uzaje", "slug": "uzaje", "country": "France (Neuilly-sur-Marne / Avignon)", "categories": "industrial-reuse, reusable-packaging, reverse-logistics", "priority": "★★ Low", "summary": "Uzaje operated high-efficiency industrial washing centers in France, collecting, cleaning, and redelivering reusable food packaging for caterers, restaurants, and retailers. Since founding in 2019, it built out multiple sites before entering liquidation and ceasing all operations in May 2026."}, {"name": "Vegan Dükkan", "slug": "vegan-dukkan", "country": "Turkey (Istanbul, Cihangir)", "categories": "consumer-education, waste-reduction", "priority": "★★ Low", "summary": "Vegan Dükkan describes itself as Turkey's first all-vegan product market, operating in Istanbul's Cihangir neighborhood. It began in 2004 as an ecological and health-food store and transitioned to a fully vegan model in 2012, selling organic, vegetarian/vegan, and cruelty-free products."}, {"name": "Venezolana de Reciclaje, C.A. (Venrecicla)", "slug": "venezolana-de-reciclaje", "country": "Venezuela (Barquisimeto, Lara State)", "categories": "industrial-reuse, material-recovery, reverse-logistics", "priority": "★★★ Medium", "summary": "Venrecicla is a Venezuelan recycling company based in Barquisimeto that recovers solid waste and processes it into secondary raw materials for domestic and export markets. It operates an office in Barquisimeto's Industrial Zone III and a processing plant in Cabudare's La Montañita Industrial Zone, positioning itself around \"efficiency, reliability, and responsibility in recycling.\""}, {"name": "Venezuela Refill Initiative", "slug": "venezuela-refill-initiative", "country": "Venezuela", "categories": "refill", "priority": "★★ Low", "summary": "The seed data describes an NGO operating refill stations for water and detergents in Venezuela. However, the listed domain (venezuelarefill.org) does not resolve (DNS lookup failure), and a targeted web search found no evidence of an organisation by this name operating in Venezuela. No independent confirmation of this organisation's existence could be obtained."}, {"name": "Verde Market", "slug": "verde-market", "country": "United States (Miami, Florida)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Verde Market is a zero-waste grocery and bulk-foods store founded in Miami in May 2018 by co-owners Martha Balaguer and Pam Barrera, who saw a gap in the local market for package-free shopping. It now operates two Miami-area locations (Midtown and South Miami) stocking over 300 bulk food and plastic-free personal/home-care products."}, {"name": "VerdeMar", "slug": "verdemar", "country": "Brazil (Belo Horizonte, Minas Gerais)", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "Verdemar is a regional supermarket chain operating multiple stores in Belo Horizonte, Minas Gerais, positioned as a higher-end grocery retailer with an emphasis on variety, fresh/organic produce, and prepared foods. It is consistently noted by customers as not supplying single-use plastic shopping bags, instead packing purchases with staff assistance into customer-brought or store-sold reusable bags."}, {"name": "Vietnam Zero Waste Alliance", "slug": "vietnam-zero-waste-alliance", "country": "Vietnam", "categories": "consumer-education, material-recovery, waste-reduction", "priority": "★★★ Medium", "summary": "The Vietnam Zero Waste Alliance is a coalition of Vietnamese civil-society organisations and individuals — including GreenHub, Mekong Community Development, Vietnam Sustainable Green, iDE Global, Green Việt, Enda Vietnam, and Culao Champa — supported internationally by Pacific Environment, the Global Alliance for Incinerator Alternatives, and Break Free From Plastic. It promotes \"conservation of all resources by means of responsible production, consumption, reuse, and recovery... without burning.\""}, {"name": "Village General Store & Refillery", "slug": "village-general-store", "country": "United States (Roseville, California)", "categories": "refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "Village General Store & Refillery is a Roseville, California retail store framed as \"a return to the community general store in a modern and sustainable way,\" located at 500 Vernon St. It sells everyday pantry staples, home-cleaning products, DIY ingredients, lifestyle/home goods, vintage items, and personal-care products, with refill stations for cleaning and personal-care items."}, {"name": "V's HOME - Veggie Restaurant & Cafe", "slug": "vs-home-veggie-restaurant-cafe", "country": "Vietnam (Hanoi)", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "V's HOME was a vegetarian/vegan restaurant and cafe in Hanoi's Hoan Kiem district, known among reviewers for zero-waste practices such as bamboo straws and eco-friendly retail items. Independent review sources indicate the restaurant has since closed."}, {"name": "Vytal", "slug": "vytal", "country": "Not publicly available", "categories": "deposit-return, digital-tracking, reusable-packaging, reverse-logistics, waste-reduction", "priority": "★★★★ High", "summary": "Vytal (VYTAL Global GmbH) is a Cologne-based company that operates a digital, deposit-free reusable packaging system for takeaway and delivery food and drink. Founded in 2019 by Sven Witthöft and Tim Breker (joined shortly after by Fabian Barthel in 2020), the company provides durable, microwave-safe containers to restaurants, canteens, delivery platforms, caterers and event operators; consumers borrow and return containers for free via a smartphone app and QR-code scanning, with partner businesses paying per use"}, {"name": "Wasteless", "slug": "wasteless", "country": "Not publicly available (US contact number referenced; likely Israel/US dual presence per industry sources)", "categories": "digital-tracking, waste-reduction", "priority": "★ Low relevance", "summary": "Wasteless is a retail-technology company providing AI-driven dynamic pricing (\"AI Markdowns\") and shelf-life management tools (DateCheck+, Rotation Calendar, Grind Logs, Waste Tracking, Insights) to help grocery retailers reduce food waste by automatically adjusting prices as products approach expiry, deployed across 640+ stores including Makro (Poland) and Spanish retailers."}, {"name": "Wasteupso: The Zero Waste Shop", "slug": "wasteupso-zero-waste-shop", "country": "South Korea (Seocho-gu, Seoul)", "categories": "consumer-education, refill, reusable-packaging, take-back", "priority": "★★★ Medium", "summary": "Wasteupso is a community-based zero-waste grocery and goods shop in Seoul, founded in summer 2018 by American expatriate Kychele Boone. It sells food, home goods, and zero-waste products with minimal packaging, located at 4F, 189 Bangbae-ro, Seocho-gu, near Naebang Station."}, {"name": "WaterKiosk Africa", "slug": "waterkiosk-africa", "country": "Kenya", "categories": "consumer-education, refill", "priority": "★★★★ High", "summary": "WaterKiosk Africa installs, operates, and maintains solar-powered water desalination systems for off-grid communities across Africa, providing drinking, irrigation, sanitation, and fish-farm water. It works closely with Boreal Light GmbH, a German manufacturer of the underlying solar desalination technology, and emphasises women as kiosk operators."}, {"name": "Waterpod by I-Drop", "slug": "waterpod-by-i-drop", "country": "South Africa", "categories": "digital-tracking, refill", "priority": "★★★ Medium", "summary": "Waterpod is a self-service, in-store drinking-water refill system developed by I-Drop Water, installed inside grocery stores with no upfront capital cost to the retailer. The company describes itself as \"born in Africa,\" using multi-stage filtration and UV sterilisation to deliver affordable drinking water as a lower-cost, lower-plastic alternative to bottled water."}, {"name": "We Fill Good", "slug": "we-fill-good", "country": "United States (Kittery, Maine)", "categories": "material-recovery, refill, reusable-packaging, waste-reduction", "priority": "★★★ Medium", "summary": "We Fill Good is a local circular-economy retail store based in Kittery, Maine (Seacoast region), operating both a physical storefront and an online shop selling refillable and reusable low-waste household products. It offers free local delivery within 15 miles (on orders $45+) and nationwide shipping ($70+, excluding liquids)."}, {"name": "Well Spent Grain", "slug": "well-spent-grain", "country": "Ireland (Walkinstown, Dublin)", "categories": "industrial-reuse, waste-reduction", "priority": "★★★ Medium", "summary": "Well Spent Grain Ltd, trading as \"Born Again Snacks,\" is a Dublin-based food company that transforms brewery spent grain — a byproduct typically discarded after beer production — into nutritious snack bars. Founded in 2022, it is based in Walkinstown, Dublin, and has been supported by Irish innovation programmes including Teagasc, Climate Launchpad, Food Academy, and New Frontiers."}, {"name": "Wheedle", "slug": "wheedle", "country": "India (Bengaluru)", "categories": "sharing, waste-reduction", "priority": "★★★ Medium", "summary": "Wheedle is an online marketplace, operated by ReEarth Tech Private Limited, for buying and selling pre-loved (secondhand) baby and kids' products in India. Founded in 2021 by Snehal Chaitanya and Harshada Joshi and based in Bengaluru, it raised a seed funding round in October 2023 led by Startup India."}, {"name": "Wild", "slug": "wild", "country": "Not publicly available", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★★ High", "summary": "Wild is a UK personal-care brand built around refillable, plastic-reduced products, starting with a natural deodorant sold as a reusable metal case plus compostable/bamboo-pulp refill sticks. It was co-founded by childhood friends Charlie Bowes-Lyon and Freddy Ward, with the operating company (Wild Cosmetics Limited) incorporated in December 2018 and the brand launching commercially in the UK in 2019/2020. Wild grew rapidly through direct-to-consumer subscription and expansion into major UK retailers, reporting revenue of £46.9 million"}, {"name": "Wildcraft", "slug": "wildcraft", "country": "Canada (Toronto, Ontario)", "categories": "consumer-education, refill, reusable-packaging", "priority": "★★★ Medium", "summary": "Wildcraft is a Toronto-based, women-owned natural skincare brand making 100%-natural, handmade, small-batch face, body, and hair-care products. It offers refill options for select products (e.g., toners) and ships every order using only repurposed packaging materials, positioning itself as a low-waste, cruelty-free (Leaping Bunny certified) skincare company."}, {"name": "Wobz", "slug": "wobz", "country": "France (Lyon)", "categories": "deposit-return, digital-tracking, packaging-as-a-service, reusable-packaging", "priority": "★★★★ High", "summary": "Wobz is a French reusable-packaging company based in the Lyon area, providing intelligent reusable containers (cups and food packaging) managed through its proprietary \"MagicLoop®\" digital deposit system, along with washing and container-management services. It targets events, municipalities, universities, and office/tertiary-sector clients seeking to replace single-use packaging."}, {"name": "Woodly", "slug": "woodly", "country": "Finland (Helsinki); UK commercial office also referenced for London/UK growth", "categories": "material-recovery, waste-reduction", "priority": "★★★ Medium", "summary": "Woodly Oy is a Finnish materials-technology company, headquartered in Helsinki, that has developed Woodly®, a patented bioplastic made from FSC-certified wood cellulose. Development began in 2011 in cooperation with VTT, Finland's state research institute, and the company has since built out UK-facing commercial leadership to support European growth (announced July 2026)."}, {"name": "Woola", "slug": "woola", "country": "Estonia", "categories": "material-recovery, reusable-packaging, waste-reduction", "priority": "★★★★ High", "summary": "Woola manufactures protective shipping packaging — envelopes, bottle sleeves and cushioning inserts — from waste sheep wool that would otherwise be discarded (an estimated 200,000 tonnes go unused in Europe annually). Founded by Anna-Liisa Palatu with Jevgeni Širai and Katrin Kabun, the company positions its \"Bubble Wool\" product as a reusable, water-repellent, compostable replacement for fossil-fuel-based bubble wrap."}, {"name": "Woosh Water", "slug": "woosh-water", "country": "Israel (Tel Aviv); later also operating from Miami Beach, Florida, USA", "categories": "digital-tracking, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Woosh Water designs internet-connected, self-service \"smart\" water stations that purify (via ozone) and dispense drinking water, including a bottle-cleansing function for reusable bottles. Piloted on Tel Aviv streets from 2013, the concept expanded to US sites including a Dayton, Ohio college campus (2016) and Miami Beach (from around 2019)."}, {"name": "Wura", "slug": "wura", "country": "Nigeria", "categories": "consumer-education, digital-tracking, sharing, waste-reduction", "priority": "★★★ Medium", "summary": "Wura is a community item-sharing app founded by Nigerian entrepreneur Damilola Kadiri, letting users post household items, food, clothing, tools and electronics they no longer need for others nearby to request for free. The app computes an estimated environmental impact/carbon-footprint saving for each exchange and is available on Android and iOS in multiple languages."}, {"name": "Biocírculo (seed-listed as \"XICLO / Biocírculo\")", "slug": "xiclo-biocirculo", "country": "Colombia (Bogotá)", "categories": "industrial-reuse, material-recovery, waste-reduction", "priority": "★★★ Medium", "summary": "Biocírculo is a Bogotá-based mechanical recycling company that processes post-consumer PET, HDPE, PP and PS plastic waste into pelletised recycled raw material for packaging and plastic-product manufacturers, partially or wholly displacing virgin plastic. It is B Corp-certified (since 2022) and supplies recycled resin used in packaging, including by refill/reuse-oriented brands."}, {"name": "Xiclo", "slug": "xiclo", "country": "Colombia (Bogotá)", "categories": "digital-tracking, packaging-as-a-service, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "Founded in 2021 by Ana María Villegas and her brother, Xiclo emerged from Villegas's circular-economy studies at UC Berkeley and pandemic-era observations of food-delivery packaging waste. Its app connects restaurants and diners around returnable containers reusable 1,000+ times, with Xiclo handling collection, washing and sterilisation."}, {"name": "XXL Refill", "slug": "xxl-refill", "country": "Portugal", "categories": "refill, repair, take-back, waste-reduction", "priority": "★★ Low", "summary": "XXL Refill is a Portuguese retail franchise specialising in refilling and recycling ink and toner printer cartridges on-site, alongside selling compatible toners and offering basic computer assistance. The network operates outlets in shopping centres and standalone stores across multiple Portuguese cities/regions, including Covilhã, Leiria, Figueira da Foz, Maia, Aveiro and Vila Nova de Gaia."}, {"name": "Yes Future", "slug": "yes-future", "country": "Spain (Barcelona)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★★ High", "summary": "Yes Future opened in 2017 in Barcelona's Sant Antoni neighbourhood as Spain's first plastic-free, zero-waste supermarket, later adding a second store in Poblenou (2019). Co-founded by Olga Rodríguez, the store sells food, drinks, cleaning and hygiene products in bulk via dispensers and refillable containers, with customers bringing their own containers to be weighed, filled and charged by quantity."}, {"name": "Yope", "slug": "yope", "country": "Poland (Warsaw)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Yope is a Polish natural personal-care and home-cleaning brand founded in 2013 by Karolina and Paweł Kosowicz, exporting to over 40 markets with an annual turnover of roughly €20 million. Since 2021/2022 it has partnered with Polish refill-technology startup Swapp to offer coffee-machine-style refill stations for hand soap, shampoo, shower gel and dish soap in retail locations, letting customers refill reusable Yope/Swapp bottles at a discount versus buying new packaged product."}, {"name": "Your Sustainable Store", "slug": "your-sustainable-store", "country": "Singapore", "categories": "consumer-education, refill, rental, take-back, waste-reduction", "priority": "★★ Low", "summary": "Your Sustainable Store is an online-only retailer founded in 2018 by Dawn Chen after she struggled to find affordable, accessible sustainable products in Singapore. It sells a curated range of reusable items — bamboo coffee cups, beeswax food wraps, silicone storage bags, bamboo toothbrushes and similar goods — aimed at making low-waste living convenient and budget-friendly."}, {"name": "YourGreenKit", "slug": "yourgreenkit", "country": "Luxembourg (Steinsel)", "categories": "packaging-as-a-service, reusable-packaging, reverse-logistics, waste-reduction", "priority": "★★★ Medium", "summary": "YourGreenKit is a Luxembourg reuse initiative offering \"packaging-as-a-service\": subscribers pay for unlimited annual use of YourGreenBox (reusable food takeaway/delivery containers) and YourGreenCup (reusable hot-drink cups), returning them to collection points or partner restaurants/cafés after use for cleaning and reuse. It is supported by national innovation agency LuxInnovation and listed as a World Economic Forum project."}, {"name": "Z.W. Mercantile", "slug": "z-w-mercantile", "country": "United States — Ames, Iowa", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "Z.W. Mercantile is a small eco-friendly general store based in Ames, Iowa, selling bulk and package-free cleaning, personal care, and pantry goods. It operates as one of the businesses housed within The Shops at Clark & Main, serving local and regional customers through in-store shopping and curbside pickup."}, {"name": "Zacros Corporation", "slug": "zacros", "country": "Japan — Tokyo", "categories": "material-recovery, refill, waste-reduction", "priority": "★★★★ High", "summary": "ZACROS is a long-established Japanese flexible packaging manufacturer founded in 1914 as Fujimori Kogyo Co., Ltd., renamed ZACROS Corporation in October 2024. It is a pioneer of self-standing refill pouches (introduced in 2000 under the FLOWPACK brand) for personal care and household products, and continues to develop monomaterial refill packaging."}, {"name": "Zemito", "slug": "zemito", "country": "Slovakia", "categories": "consumer-education, refill, waste-reduction", "priority": "★★ Low", "summary": "Zemito is an online zero-waste store based in Slovakia selling ecological products aimed at reducing household waste. Its catalogue spans natural cosmetics, refillable coffee capsules, reusable bottles, and home composting equipment, positioning itself as a curated resource for customers adopting a zero-waste lifestyle."}, {"name": "Zero Impack", "slug": "zero-impack", "country": "Italy — Milan", "categories": "digital-tracking, packaging-as-a-service, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "Zero Impack is a Milan-based startup founded in 2021 that provides reusable container systems for the takeaway and food-delivery industry, aiming to displace single-use packaging waste. It combines reusable stainless-steel containers with a digital tracking app and reverse-logistics (collection, washing, redistribution) service."}, {"name": "Zero Market", "slug": "zero-market", "country": "Mexico — Mexico City", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Zero Market México is a 100% Mexican-owned bulk store business dedicated to promoting responsible, sustainable consumption of natural and ecological products. Aligned with the global Zero Waste movement, it operates physical stores in Mexico City plus bazaar/distributor presence, selling bulk foods and plastic-free personal care alternatives."}, {"name": "Zero PC", "slug": "zero-pc", "country": "Japan — Yokohama", "categories": "consumer-education, material-recovery, repair, waste-reduction", "priority": "★★★★ High", "summary": "ZERO PC is a Yokohama-based social enterprise project run by People Port Inc. that refurbishes used laptops into \"ethical PCs\" while training and employing refugees living in Japan as upcycling technicians. It combines environmental goals (reducing e-waste and CO2) with a social mission of refugee livelihood support."}, {"name": "Zero Store", "slug": "zero-store", "country": "United Kingdom — Leamington Spa, Warwickshire", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Zero Store is a UK zero-waste retailer founded by \"Charlie,\" who began the project in autumn 2018 and opened a shop in Leamington Spa in November 2019, followed by a second store in Stratford-upon-Avon in June 2022. It sells package-free dried goods, eco-cleaning refills, and plastic-free toiletries and household goods both in-store and online."}, {"name": "Zero Waste Austria", "slug": "zero-waste-austria", "country": "Austria — Vienna", "categories": "consumer-education, waste-reduction", "priority": "★★★ Medium", "summary": "Zero Waste Austria is a Vienna-based non-profit association founded to amplify the zero-waste movement across Austria by strengthening networks and raising public awareness. It is a member of Zero Waste Europe and works nationally through talks, school workshops, and collaborations with waste management organisations and green start-ups."}, {"name": "Zero Waste Delivery", "slug": "zero-waste-delivery", "country": "United Kingdom — Guildford", "categories": "refill, reverse-logistics, waste-reduction", "priority": "★★★ Medium", "summary": "Zero Waste Delivery is a Guildford-based refill company that delivers household products directly to customers' doors using zero-emission electric vans, avoiding single-use plastic packaging. It serves London and the South East with van delivery and offers UK-wide courier delivery as an alternative."}, {"name": "Zero Waste Earth Store", "slug": "zero-waste-earth-store", "country": "Malaysia (Shah Alam, Selangor — Eco Ardence)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Zero Waste Earth Store (ZWES) is a bulk-goods refill store based in Shah Alam, Malaysia, operating under a \"Zero Waste To Landfill\" mission. Customers bring their own containers to purchase groceries, cleaning products and personal-care items in bulk, reducing single-use packaging waste at the point of purchase."}, {"name": "Zero Waste Harare", "slug": "zero-waste-harare", "country": "Zimbabwe (Willowvale Road, Harare)", "categories": "material-recovery, reverse-logistics, waste-reduction", "priority": "★★★ Medium", "summary": "Zero Waste Harare is a group of women, led by Barbara Tiki, who since 2021 have operated a plastic-waste buying and sorting station beside Willowvale Road in Harare. Community members bring plastic waste to the station, where it is graded and sold on to recycling companies, generating income for the women involved, many of whom are widows, divorced or single mothers."}, {"name": "Zero Waste Kenya", "slug": "zero-waste-kenya", "country": "Kenya", "categories": "consumer-education, material-recovery, waste-reduction", "priority": "★★★ Medium", "summary": "Zero Waste Kenya is a national non-profit initiative promoting integrated sustainable waste management across Kenya. It runs educational campaigns on waste segregation, reduction and recycling, engages communities and volunteers, and supports reporting mechanisms for illegal dumping, aiming to empower Kenyans to take responsibility for the waste they generate."}, {"name": "Zero Waste Malaysia", "slug": "zero-waste-malaysia", "country": "Malaysia", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★★ High", "summary": "Zero Waste Malaysia is a non-profit NGO, co-founded in 2016 and formally registered in 2018, that works to make zero-waste living accessible across Malaysia. It builds educational content and free public resources, including a crowdsourced map of zero-waste and refill locations, and engages individuals, community groups and corporates on waste reduction."}, {"name": "Zero Waste on Wheels", "slug": "zero-waste-on-wheels", "country": "United Kingdom (Maidstone, Kent)", "categories": "refill, reverse-logistics, waste-reduction", "priority": "★★★ Medium", "summary": "Zero Waste on Wheels is a Maidstone-based mobile refill service that visits customers by van to refill their own containers with household and personal-care essentials, avoiding single-use packaging. It launched to help people access plastic-free refills during COVID-19 self-isolation and has continued as a local delivery-refill business across Maidstone and surrounding Kent areas."}, {"name": "Zero Waste Reserve", "slug": "zero-waste-reserve", "country": "United States (Bettendorf, Iowa)", "categories": "consumer-education, waste-reduction", "priority": "★★ Low", "summary": "Zero Waste Reserve is a physical and online retailer, opened in August 2022 by Kelsey Pisel, selling natural, non-toxic and sustainable products for the body, home and planet. Located at The Plex in Bettendorf, Iowa, it sells reusable household items alongside other zero-waste consumer goods, shipping within the continental United States."}, {"name": "Zero Waste Sofia", "slug": "zero-waste-sofia", "country": "Bulgaria (Sofia)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Zero Waste Sofia is a Bulgarian sustainable-living initiative founded by corporate-communications professional Simona Stiliyanova(-Pavlova), aimed at reducing single-use plastic and bottled-water consumption. Its flagship project, the \"Fountains of Bulgaria\" map, catalogues around 1,000 public water fountains and refill-friendly venues nationwide."}, {"name": "Zero Waste Store NL", "slug": "zero-waste-store-nl", "country": "Netherlands", "categories": "refill, waste-reduction", "priority": "★★ Low", "summary": "Zero Waste Store NL is a Dutch webshop presence selling package-free, refillable home and body-care products, positioned within the Netherlands' broader zero-waste retail scene. It maintains active Instagram and Facebook profiles, but its primary website could not be reached during this research pass."}, {"name": "Zeroo", "slug": "zeroo", "country": "Portugal (operations linked to Porto and Lisbon retail partners)", "categories": "digital-tracking, packaging-as-a-service, refill, reusable-packaging", "priority": "★★★★ High", "summary": "Zeroo is a Portuguese smart-packaging venture, launched in 2023 as a co-creation between The Loop Co. and Loja do Zero, that develops automated bulk-dispensing systems and RFID-enabled reusable cups for retailers. Its technology targets bulk, refill and takeaway retail operations, replacing manual weighing with automated, traceable dispensing."}, {"name": "Zerooo", "slug": "zerooo", "country": "Germany (Hamburg)", "categories": "consumer-education, deposit-return, reusable-packaging, reverse-logistics", "priority": "★★★★ High", "summary": "Zerooo is a Hamburg-based start-up operating a deposit-return system for PET and glass containers used by cosmetics and drugstore brands. Containers are returned via deposit machines or checkout points and reused in closed loops, with some glass containers circulating up to 30 times."}, {"name": "Zeropolitan", "slug": "zeropolitan", "country": "Australia (Melbourne)", "categories": "consumer-education, reusable-packaging, waste-reduction", "priority": "★★ Low", "summary": "Zeropolitan is an Australian e-commerce store selling reusable and plastic-free personal care and household items — bamboo toothbrushes, cork deodorants, soy wax candles, and related zero-waste goods — aimed at helping customers reduce single-use plastic consumption."}, {"name": "Zero Posro", "slug": "zeroposro", "country": "India (Panaji/Porvorim, Goa)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Zero Posro is a Goa-based social enterprise selling seasonal, locally sourced produce and pantry staples loose from dispensers, requiring customers to bring their own containers or reusable bags. It aims to reduce plastic waste in the food retail sector."}, {"name": "ZeroWaste Switzerland", "slug": "zerowaste-switzerland", "country": "Switzerland", "categories": "consumer-education, repair, sharing, waste-reduction", "priority": "★★★ Medium", "summary": "ZeroWaste Switzerland is a non-profit association founded in 2015 to guide long-term waste reduction across the Swiss population. It raises awareness of waste-related issues, promotes behaviour change, and coordinates volunteer \"Ambassador\" networks across Swiss regions."}, {"name": "Zoja Market", "slug": "zoja", "country": "Argentina (Buenos Aires)", "categories": "refill, waste-reduction", "priority": "★★ Low", "summary": "Zoja Market is a boutique organic grocery store in the Palermo area of Buenos Aires, selling dried goods, pantry staples, and organic products, with a retail presence promoted primarily through Instagram and an online storefront."}, {"name": "Zoya", "slug": "zoya", "country": "Bulgaria (Sofia)", "categories": "consumer-education, refill, waste-reduction", "priority": "★★★ Medium", "summary": "Zoya was founded in 2008 as Sofia's first organic and natural products shop and has grown into Bulgaria's largest natural/organic retailer, with seven physical stores, an e-commerce arm, and wholesale distribution to 250+ shops across Bulgaria."}, {"name": "ZTO Express", "slug": "zto", "country": "China (Shanghai/Shanghai Qingpu)", "categories": "material-recovery, reusable-packaging, reverse-logistics, waste-reduction", "priority": "★★★★ High", "summary": "ZTO Express is one of China's largest express-delivery and logistics companies, operating a nationwide parcel sorting and delivery network. Alongside its core courier business, ZTO has deployed reusable packaging (bags, turnover baskets, cartons) at scale within its sorting centres to cut single-use packaging waste."}];
